var e=JSON.parse(`[{"id":13000,"term":"abnormal","meaning":"비정상적인; 이상한","partOfSpeech":"adj.","example":"The doctor said the test results looked abnormal.","exampleTranslation":"의사가 검사 결과가 비정상적으로 보인다고 했어요.","level":23,"category":"빈도 학습"},{"id":13001,"term":"aboard","meaning":"탑승하여; (배·비행기·기차에) 타서","partOfSpeech":"adv.","example":"All passengers must be aboard before the ship departs.","exampleTranslation":"배가 출발하기 전에 모든 승객은 탑승해 있어야 합니다.","level":23,"category":"빈도 학습"},{"id":13002,"term":"abrupt","meaning":"갑작스러운; 퉁명스러운","partOfSpeech":"adj.","example":"The meeting ended with an abrupt announcement from the manager.","exampleTranslation":"회의는 관리자의 갑작스러운 발표로 끝났습니다.","level":23,"category":"빈도 학습"},{"id":13003,"term":"absent","meaning":"결석한; 자리를 비운","partOfSpeech":"adj.","example":"Three students were absent from class because of illness.","exampleTranslation":"세 명의 학생이 아파서 수업에 결석했습니다.","level":23,"category":"빈도 학습"},{"id":13004,"term":"absurd","meaning":"불합리한; 터무니없는","partOfSpeech":"adj.","example":"It seems absurd to wait two hours for a ten-minute meeting.","exampleTranslation":"10분짜리 회의를 위해 두 시간을 기다리는 건 터무니없어 보입니다.","level":23,"category":"빈도 학습"},{"id":13005,"term":"abundant","meaning":"풍부한; 넘치는","partOfSpeech":"adj.","example":"This region has abundant natural resources that support many industries.","exampleTranslation":"이 지역은 많은 산업을 지탱하는 풍부한 천연자원을 보유하고 있습니다.","level":23,"category":"빈도 학습"},{"id":13006,"term":"acid","meaning":"산(酸); 신맛의","partOfSpeech":"n.","example":"The scientist carefully handled the acid in a protective glove.","exampleTranslation":"과학자는 보호 장갑을 끼고 산을 조심스럽게 다뤘습니다.","level":23,"category":"빈도 학습"},{"id":13007,"term":"accountant","meaning":"회계사; 회계 담당자","partOfSpeech":"n.","example":"The company hired an accountant to manage its financial records.","exampleTranslation":"그 회사는 재무 기록을 관리하기 위해 회계사를 고용했습니다.","level":23,"category":"빈도 학습"},{"id":13008,"term":"accustom","meaning":"익숙하게 하다; 적응시키다","partOfSpeech":"v.","example":"Living abroad will accustom you to different cultural habits.","exampleTranslation":"해외에서 생활하면 다양한 문화적 습관에 익숙해질 것입니다.","level":23,"category":"빈도 학습"},{"id":13009,"term":"acquaint","meaning":"알게 하다; 소개하다","partOfSpeech":"v.","example":"Let me acquaint you with the new office procedures before you start.","exampleTranslation":"시작하기 전에 새 사무실 절차를 알려드리겠습니다.","level":23,"category":"빈도 학습"},{"id":13010,"term":"activate","meaning":"활성화하다; 작동시키다","partOfSpeech":"v.","example":"Press this button to activate the alarm system.","exampleTranslation":"이 버튼을 눌러 경보 시스템을 활성화하세요.","level":23,"category":"빈도 학습"},{"id":13011,"term":"acute","meaning":"심각한; 예리한","partOfSpeech":"adj.","example":"She felt an acute pain in her chest and called an ambulance.","exampleTranslation":"그녀는 가슴에 심한 통증을 느끼고 구급차를 불렀습니다.","level":23,"category":"빈도 학습"},{"id":13012,"term":"adhere","meaning":"고수하다; 달라붙다","partOfSpeech":"v.","example":"All employees must adhere to the company's code of conduct.","exampleTranslation":"모든 직원은 회사의 행동 강령을 준수해야 합니다.","level":23,"category":"빈도 학습"},{"id":13013,"term":"adjacent","meaning":"인접한; 바로 옆의","partOfSpeech":"adj.","example":"Our office is adjacent to the main train station.","exampleTranslation":"우리 사무실은 중앙 기차역 바로 옆에 있습니다.","level":23,"category":"빈도 학습"},{"id":13014,"term":"administer","meaning":"관리하다; 집행하다","partOfSpeech":"v.","example":"The principal will administer the scholarship program this year.","exampleTranslation":"교장 선생님이 올해 장학금 프로그램을 운영할 것입니다.","level":23,"category":"빈도 학습"},{"id":13015,"term":"adverse","meaning":"불리한; 역효과의","partOfSpeech":"adj.","example":"The project was delayed due to adverse weather conditions.","exampleTranslation":"악천후로 인해 프로젝트가 지연되었습니다.","level":23,"category":"빈도 학습"},{"id":13016,"term":"aesthetic","meaning":"미적인; 심미적인","partOfSpeech":"adj.","example":"The designer made several aesthetic improvements to the logo.","exampleTranslation":"디자이너는 로고에 몇 가지 미적 개선을 했습니다.","level":23,"category":"빈도 학습"},{"id":13017,"term":"affiliate","meaning":"제휴하다; 가맹점","partOfSpeech":"v.","example":"The local clinic decided to affiliate with a major hospital network.","exampleTranslation":"지역 클리닉은 대형 병원 네트워크에 가맹하기로 결정했습니다.","level":23,"category":"빈도 학습"},{"id":13018,"term":"aggression","meaning":"공격성; 침략","partOfSpeech":"n.","example":"The teacher warned students that any form of aggression would not be tolerated.","exampleTranslation":"선생님은 어떤 형태의 공격적 행동도 용납되지 않을 것이라고 경고했습니다.","level":23,"category":"빈도 학습"},{"id":13019,"term":"agony","meaning":"극심한 고통; 고민","partOfSpeech":"n.","example":"He was in agony after twisting his knee during the game.","exampleTranslation":"그는 경기 중 무릎을 삐끗한 후 극심한 고통을 겪었습니다.","level":23,"category":"빈도 학습"},{"id":13020,"term":"align","meaning":"일치시키다; 정렬하다","partOfSpeech":"v.","example":"We need to align our goals with the company's overall strategy.","exampleTranslation":"우리는 목표를 회사의 전반적인 전략과 일치시켜야 합니다.","level":23,"category":"빈도 학습"},{"id":13021,"term":"alike","meaning":"비슷한; 똑같이","partOfSpeech":"adj.","example":"The twins looked so alike that even their teacher got confused.","exampleTranslation":"그 쌍둥이는 너무 닮아서 선생님도 헷갈릴 정도였습니다.","level":23,"category":"빈도 학습"},{"id":13022,"term":"alley","meaning":"골목; 좁은 길","partOfSpeech":"n.","example":"There is a small café hidden at the end of that alley.","exampleTranslation":"그 골목 끝에 작은 카페가 숨겨져 있습니다.","level":23,"category":"빈도 학습"},{"id":13023,"term":"alpha","meaning":"알파; 첫 번째","partOfSpeech":"n.","example":"The software is still in alpha and not ready for the public.","exampleTranslation":"그 소프트웨어는 아직 알파 단계라 일반에 공개될 준비가 되지 않았습니다.","level":23,"category":"빈도 학습"},{"id":13024,"term":"alternate","meaning":"번갈아 하다; 교대의","partOfSpeech":"v.","example":"The guards alternate shifts every eight hours throughout the day.","exampleTranslation":"경비원들은 하루 종일 8시간마다 교대로 근무합니다.","level":23,"category":"빈도 학습"},{"id":13025,"term":"aluminum","meaning":"알루미늄","partOfSpeech":"n.","example":"The frame of this bicycle is made of lightweight aluminum.","exampleTranslation":"이 자전거의 프레임은 가벼운 알루미늄으로 만들어졌습니다.","level":23,"category":"빈도 학습"},{"id":13026,"term":"amateur","meaning":"아마추어; 비전문가","partOfSpeech":"n.","example":"He is still an amateur photographer but his photos look professional.","exampleTranslation":"그는 아직 아마추어 사진작가지만 사진이 전문가처럼 보입니다.","level":23,"category":"빈도 학습"},{"id":13027,"term":"ambassador","meaning":"대사; 사절","partOfSpeech":"n.","example":"The ambassador met with foreign leaders to discuss trade agreements.","exampleTranslation":"대사는 무역 협정을 논의하기 위해 외국 지도자들을 만났습니다.","level":23,"category":"빈도 학습"},{"id":13028,"term":"ambiguous","meaning":"모호한; 불분명한","partOfSpeech":"adj.","example":"The contract language was ambiguous and led to a dispute.","exampleTranslation":"계약서의 표현이 모호해 분쟁으로 이어졌습니다.","level":23,"category":"빈도 학습"},{"id":13029,"term":"ambition","meaning":"야망; 포부","partOfSpeech":"n.","example":"Her ambition is to become the CEO of a global company.","exampleTranslation":"그녀의 야망은 글로벌 기업의 CEO가 되는 것입니다.","level":23,"category":"빈도 학습"},{"id":13030,"term":"ambitious","meaning":"야심찬; 의욕적인","partOfSpeech":"adj.","example":"The team set an ambitious target to double sales within a year.","exampleTranslation":"팀은 1년 안에 매출을 두 배로 늘리겠다는 야심찬 목표를 세웠습니다.","level":24,"category":"빈도 학습"},{"id":13031,"term":"ambulance","meaning":"구급차","partOfSpeech":"n.","example":"Someone called an ambulance after the man collapsed on the street.","exampleTranslation":"남자가 길에서 쓰러지자 누군가가 구급차를 불렀습니다.","level":24,"category":"빈도 학습"},{"id":13032,"term":"amid","meaning":"~한가운데에; ~속에서","partOfSpeech":"prep.","example":"She stayed calm amid all the chaos around her.","exampleTranslation":"그녀는 주변의 모든 혼란 속에서도 침착함을 유지했습니다.","level":24,"category":"빈도 학습"},{"id":13033,"term":"ancestor","meaning":"조상; 선조","partOfSpeech":"n.","example":"She traced her ancestor back to a small village in Ireland.","exampleTranslation":"그녀는 자신의 조상을 아일랜드의 작은 마을까지 거슬러 올라갔습니다.","level":24,"category":"빈도 학습"},{"id":13034,"term":"anchor","meaning":"닻; 고정시키다","partOfSpeech":"n.","example":"The crew dropped the anchor so the boat would not drift away.","exampleTranslation":"선원들은 배가 떠내려가지 않도록 닻을 내렸습니다.","level":24,"category":"빈도 학습"},{"id":13035,"term":"animate","meaning":"생기를 불어넣다; 활기차게 하다","partOfSpeech":"v.","example":"The director used bright colors to animate the opening scene.","exampleTranslation":"감독은 밝은 색상을 사용해 오프닝 장면에 생기를 불어넣었습니다.","level":24,"category":"빈도 학습"},{"id":13036,"term":"ankle","meaning":"발목","partOfSpeech":"n.","example":"She twisted her ankle while jogging on an uneven path.","exampleTranslation":"그녀는 울퉁불퉁한 길에서 조깅하다가 발목을 삐었습니다.","level":24,"category":"빈도 학습"},{"id":13037,"term":"anniversary","meaning":"기념일; 주년","partOfSpeech":"n.","example":"They celebrated their wedding anniversary at a fancy restaurant.","exampleTranslation":"그들은 결혼 기념일을 고급 레스토랑에서 기념했습니다.","level":24,"category":"빈도 학습"},{"id":13038,"term":"anonymous","meaning":"익명의; 이름을 밝히지 않은","partOfSpeech":"adj.","example":"An anonymous donor gave a large sum to the local school.","exampleTranslation":"익명의 기부자가 지역 학교에 거액을 기부했습니다.","level":24,"category":"빈도 학습"},{"id":13039,"term":"anthropology","meaning":"인류학","partOfSpeech":"n.","example":"She studied anthropology to better understand different human cultures.","exampleTranslation":"그녀는 다양한 인간 문화를 더 잘 이해하기 위해 인류학을 공부했습니다.","level":24,"category":"빈도 학습"},{"id":13040,"term":"antique","meaning":"골동품; 오래된","partOfSpeech":"n.","example":"He found a beautiful antique at the weekend flea market.","exampleTranslation":"그는 주말 벼룩시장에서 아름다운 골동품을 발견했습니다.","level":24,"category":"빈도 학습"},{"id":13041,"term":"appall","meaning":"경악하게 하다; 충격을 주다","partOfSpeech":"v.","example":"The graphic images in the documentary will appall most viewers.","exampleTranslation":"그 다큐멘터리의 충격적인 장면은 대부분의 시청자를 경악하게 할 것입니다.","level":24,"category":"빈도 학습"},{"id":13042,"term":"applicable","meaning":"적용 가능한; 해당하는","partOfSpeech":"adj.","example":"These safety rules are applicable to all employees in the building.","exampleTranslation":"이 안전 규정은 건물 내 모든 직원에게 적용됩니다.","level":24,"category":"빈도 학습"},{"id":13043,"term":"appraise","meaning":"평가하다; 감정하다","partOfSpeech":"v.","example":"An expert was hired to appraise the value of the old painting.","exampleTranslation":"전문가가 오래된 그림의 가치를 감정하기 위해 고용되었습니다.","level":24,"category":"빈도 학습"},{"id":13044,"term":"arch","meaning":"아치; 아치형 구조물","partOfSpeech":"n.","example":"Visitors walked through the grand arch at the entrance of the palace.","exampleTranslation":"방문객들은 궁전 입구의 웅장한 아치를 통해 걸어 들어갔습니다.","level":24,"category":"빈도 학습"},{"id":13045,"term":"archive","meaning":"기록 보관소; 보관하다","partOfSpeech":"n.","example":"The library has a large archive of historical documents and photographs.","exampleTranslation":"그 도서관에는 역사적 문서와 사진의 대규모 기록 보관소가 있습니다.","level":24,"category":"빈도 학습"},{"id":13046,"term":"arena","meaning":"경기장; 무대","partOfSpeech":"n.","example":"The concert was held in a large arena that seated ten thousand people.","exampleTranslation":"콘서트는 만 명을 수용할 수 있는 대형 경기장에서 열렸습니다.","level":24,"category":"빈도 학습"},{"id":13047,"term":"armor","meaning":"갑옷; 방어물","partOfSpeech":"n.","example":"The knight wore a full suit of armor to protect himself in battle.","exampleTranslation":"기사는 전투에서 자신을 보호하기 위해 완전한 갑옷을 입었습니다.","level":24,"category":"빈도 학습"},{"id":13048,"term":"arouse","meaning":"일깨우다; 자극하다","partOfSpeech":"v.","example":"The teacher used creative activities to arouse curiosity in students.","exampleTranslation":"선생님은 학생들의 호기심을 자극하기 위해 창의적인 활동을 활용했습니다.","level":24,"category":"빈도 학습"},{"id":13049,"term":"array","meaning":"배열; 다양한","partOfSpeech":"n.","example":"The store offered a wide array of products to choose from.","exampleTranslation":"그 가게는 선택할 수 있는 다양한 제품을 제공했습니다.","level":24,"category":"빈도 학습"},{"id":13050,"term":"arrogant","meaning":"거만한; 오만한","partOfSpeech":"adj.","example":"The arrogant manager never listened to his team.","exampleTranslation":"거만한 매니저는 팀원들의 말을 전혀 듣지 않았습니다.","level":24,"category":"빈도 학습"},{"id":13051,"term":"arrow","meaning":"화살; 화살표","partOfSpeech":"n.","example":"The hunter aimed the arrow at the distant target.","exampleTranslation":"사냥꾼은 멀리 있는 표적에 화살을 겨눴습니다.","level":24,"category":"빈도 학습"},{"id":13052,"term":"articulate","meaning":"명확하게 표현하다; 말을 잘하는","partOfSpeech":"v.","example":"She tried to articulate her concerns clearly during the meeting.","exampleTranslation":"그녀는 회의 중 자신의 우려를 명확하게 표현하려고 했습니다.","level":24,"category":"빈도 학습"},{"id":13053,"term":"artificial","meaning":"인공의; 인위적인","partOfSpeech":"adj.","example":"The park used artificial lighting to brighten the path at night.","exampleTranslation":"공원은 밤에 길을 밝히기 위해 인공 조명을 사용했습니다.","level":24,"category":"빈도 학습"},{"id":13054,"term":"ash","meaning":"재; 잿더미","partOfSpeech":"n.","example":"After the fire, only ash remained on the ground.","exampleTranslation":"화재 이후 땅 위에는 재만 남아 있었습니다.","level":24,"category":"빈도 학습"},{"id":13055,"term":"aspire","meaning":"열망하다; 갈망하다","partOfSpeech":"v.","example":"Many young athletes aspire to compete in the Olympics one day.","exampleTranslation":"많은 젊은 선수들이 언젠가 올림픽에 출전하기를 열망합니다.","level":24,"category":"빈도 학습"},{"id":13056,"term":"assassin","meaning":"암살자","partOfSpeech":"n.","example":"The novel's plot centers on a hired assassin tracking a target.","exampleTranslation":"그 소설의 줄거리는 표적을 추적하는 고용된 암살자를 중심으로 전개됩니다.","level":24,"category":"빈도 학습"},{"id":13057,"term":"astonish","meaning":"깜짝 놀라게 하다; 경악시키다","partOfSpeech":"v.","example":"Magic tricks always astonish young children at birthday parties.","exampleTranslation":"마술 묘기는 생일 파티에서 항상 어린아이들을 깜짝 놀라게 합니다.","level":24,"category":"빈도 학습"},{"id":13058,"term":"astronomy","meaning":"천문학","partOfSpeech":"n.","example":"He studied astronomy to learn about stars and galaxies.","exampleTranslation":"그는 별과 은하에 대해 배우기 위해 천문학을 공부했습니다.","level":24,"category":"빈도 학습"},{"id":13059,"term":"attain","meaning":"달성하다; 이루다","partOfSpeech":"v.","example":"Hard work helped her attain the goals she set for herself.","exampleTranslation":"열심히 노력한 덕분에 그녀는 스스로 세운 목표를 달성했습니다.","level":24,"category":"빈도 학습"},{"id":13060,"term":"attorney","meaning":"변호사; 법무사","partOfSpeech":"n.","example":"The attorney advised her client not to speak to the press.","exampleTranslation":"변호사는 의뢰인에게 언론과 대화하지 말라고 조언했습니다.","level":24,"category":"빈도 학습"},{"id":13061,"term":"auction","meaning":"경매; 경매에 부치다","partOfSpeech":"n.","example":"The rare painting sold for millions at the auction last weekend.","exampleTranslation":"희귀한 그림이 지난 주말 경매에서 수백만 달러에 팔렸습니다.","level":24,"category":"빈도 학습"},{"id":13062,"term":"audio","meaning":"음성; 오디오","partOfSpeech":"n.","example":"Please check that the audio is working before the presentation starts.","exampleTranslation":"발표가 시작되기 전에 오디오가 제대로 작동하는지 확인해 주세요.","level":24,"category":"빈도 학습"},{"id":13063,"term":"authentic","meaning":"진품의; 진정한","partOfSpeech":"adj.","example":"The museum confirmed that the vase was authentic and very old.","exampleTranslation":"박물관은 그 꽃병이 진품이며 매우 오래된 것임을 확인했습니다.","level":24,"category":"빈도 학습"},{"id":13064,"term":"automobile","meaning":"자동차","partOfSpeech":"n.","example":"The first automobile was invented in the late nineteenth century.","exampleTranslation":"최초의 자동차는 19세기 후반에 발명되었습니다.","level":24,"category":"빈도 학습"},{"id":13065,"term":"autonomy","meaning":"자율성; 자치","partOfSpeech":"n.","example":"Employees perform better when they have autonomy over their tasks.","exampleTranslation":"직원들은 자신의 업무에 대한 자율성이 있을 때 더 잘 수행합니다.","level":24,"category":"빈도 학습"},{"id":13066,"term":"avenue","meaning":"대로; 방법","partOfSpeech":"n.","example":"The main avenue through the city is lined with old trees.","exampleTranslation":"도시를 가로지르는 중앙 대로는 오래된 나무들로 늘어서 있습니다.","level":24,"category":"빈도 학습"},{"id":13067,"term":"await","meaning":"기다리다; 대기하다","partOfSpeech":"v.","example":"A large crowd gathered to await the arrival of the parade.","exampleTranslation":"많은 군중이 퍼레이드 도착을 기다리기 위해 모였습니다.","level":24,"category":"빈도 학습"},{"id":13068,"term":"axe","meaning":"도끼","partOfSpeech":"n.","example":"The lumberjack used a heavy axe to chop firewood.","exampleTranslation":"벌목꾼은 무거운 도끼를 사용하여 장작을 팼습니다.","level":24,"category":"빈도 학습"},{"id":13069,"term":"aye","meaning":"찬성; 네(예스)","partOfSpeech":"adv.","example":"All members voted aye to approve the new budget proposal.","exampleTranslation":"모든 회원들이 새 예산안 승인에 찬성표를 던졌습니다.","level":24,"category":"빈도 학습"},{"id":13070,"term":"ballet","meaning":"발레","partOfSpeech":"n.","example":"She practiced ballet for ten years before joining a professional company.","exampleTranslation":"그녀는 전문 단체에 합류하기 전 10년간 발레를 연습했습니다.","level":24,"category":"빈도 학습"},{"id":13071,"term":"balloon","meaning":"풍선; 기구","partOfSpeech":"n.","example":"The child cried when her balloon flew away into the sky.","exampleTranslation":"풍선이 하늘로 날아가 버리자 아이가 울었습니다.","level":24,"category":"빈도 학습"},{"id":13072,"term":"ballot","meaning":"투표; 투표용지","partOfSpeech":"n.","example":"Every citizen cast their ballot at the local polling station.","exampleTranslation":"모든 시민이 지역 투표소에서 투표용지를 던졌습니다.","level":24,"category":"빈도 학습"},{"id":13073,"term":"bankrupt","meaning":"파산한; 지급 불능의","partOfSpeech":"adj.","example":"The bankrupt store closed its doors and sold all its inventory.","exampleTranslation":"파산한 가게는 문을 닫고 모든 재고를 팔았습니다.","level":24,"category":"빈도 학습"},{"id":13074,"term":"barn","meaning":"헛간; 창고","partOfSpeech":"n.","example":"The farmer stored hay and tools inside the old red barn.","exampleTranslation":"농부는 낡은 빨간 헛간 안에 건초와 도구를 보관했습니다.","level":24,"category":"빈도 학습"},{"id":13075,"term":"barrel","meaning":"통; 배럴","partOfSpeech":"n.","example":"The winery aged its wine in a wooden barrel for two years.","exampleTranslation":"그 와이너리는 와인을 나무 통에서 2년간 숙성시켰습니다.","level":24,"category":"빈도 학습"},{"id":13076,"term":"baseball","meaning":"야구","partOfSpeech":"n.","example":"They watched a baseball game at the stadium on Saturday evening.","exampleTranslation":"그들은 토요일 저녁에 경기장에서 야구 경기를 관람했습니다.","level":24,"category":"빈도 학습"},{"id":13077,"term":"basement","meaning":"지하실; 지하층","partOfSpeech":"n.","example":"They converted the basement into a cozy home theater room.","exampleTranslation":"그들은 지하실을 아늑한 홈시어터 방으로 개조했습니다.","level":24,"category":"빈도 학습"},{"id":13078,"term":"basin","meaning":"대야; 분지","partOfSpeech":"n.","example":"She filled the basin with warm water to wash her hands.","exampleTranslation":"그녀는 손을 씻기 위해 대야에 따뜻한 물을 채웠습니다.","level":24,"category":"빈도 학습"},{"id":13079,"term":"bass","meaning":"베이스(저음); 농어","partOfSpeech":"n.","example":"The bass in that song gives the music a deep, rich sound.","exampleTranslation":"그 노래의 베이스는 음악에 깊고 풍부한 소리를 줍니다.","level":24,"category":"빈도 학습"},{"id":13080,"term":"bathe","meaning":"목욕하다; 씻다","partOfSpeech":"v.","example":"Parents often bathe young children before bedtime each night.","exampleTranslation":"부모들은 매일 밤 취침 전에 어린아이들을 목욕시키곤 합니다.","level":24,"category":"빈도 학습"},{"id":13081,"term":"battered","meaning":"낡고 망가진; 심하게 두드려진","partOfSpeech":"adj.","example":"He found a battered old suitcase at the back of the garage.","exampleTranslation":"그는 차고 뒤편에서 낡고 망가진 낡은 여행 가방을 발견했습니다.","level":24,"category":"빈도 학습"},{"id":13082,"term":"bead","meaning":"구슬; 작은 방울","partOfSpeech":"n.","example":"She threaded each bead carefully onto the necklace string.","exampleTranslation":"그녀는 목걸이 실에 구슬 하나하나를 조심스럽게 꿰었습니다.","level":24,"category":"빈도 학습"},{"id":13083,"term":"beard","meaning":"수염","partOfSpeech":"n.","example":"He grew a full beard during his winter vacation in the mountains.","exampleTranslation":"그는 산에서의 겨울 휴가 동안 수염을 풍성하게 길렀습니다.","level":24,"category":"빈도 학습"},{"id":13084,"term":"beast","meaning":"짐승; 야수","partOfSpeech":"n.","example":"The legend tells of a terrible beast that roamed the dark forest.","exampleTranslation":"전설에는 어두운 숲을 돌아다니는 무시무시한 짐승 이야기가 전해집니다.","level":24,"category":"빈도 학습"},{"id":13085,"term":"belly","meaning":"배; 복부","partOfSpeech":"n.","example":"The puppy rolled onto its belly and waited for a rub.","exampleTranslation":"강아지가 배를 위로 하고 뒤집어 누워 쓰다듬어 주기를 기다렸습니다.","level":24,"category":"빈도 학습"},{"id":13086,"term":"beneficial","meaning":"유익한; 이로운","partOfSpeech":"adj.","example":"Regular exercise is beneficial for both physical and mental health.","exampleTranslation":"규칙적인 운동은 신체적, 정신적 건강 모두에 유익합니다.","level":24,"category":"빈도 학습"},{"id":13087,"term":"betray","meaning":"배신하다; 배반하다","partOfSpeech":"v.","example":"It hurt deeply to discover that a close friend could betray your trust.","exampleTranslation":"친한 친구가 신뢰를 배신할 수 있다는 사실을 알게 되어 깊이 상처받았습니다.","level":24,"category":"빈도 학습"},{"id":13088,"term":"bicycle","meaning":"자전거","partOfSpeech":"n.","example":"She rode her bicycle to work every morning to stay fit.","exampleTranslation":"그녀는 건강을 유지하기 위해 매일 아침 자전거를 타고 출근했습니다.","level":24,"category":"빈도 학습"},{"id":13089,"term":"biography","meaning":"전기; 일대기","partOfSpeech":"n.","example":"The biography of the scientist inspired many young readers worldwide.","exampleTranslation":"그 과학자의 전기는 전 세계의 많은 젊은 독자들에게 영감을 주었습니다.","level":24,"category":"빈도 학습"},{"id":13090,"term":"biology","meaning":"생물학","partOfSpeech":"n.","example":"Students learn about cells and organisms in their biology class.","exampleTranslation":"학생들은 생물학 수업에서 세포와 유기체에 대해 배웁니다.","level":24,"category":"빈도 학습"},{"id":13091,"term":"bizarre","meaning":"기이한; 이상한","partOfSpeech":"adj.","example":"The neighbors found the man's bizarre behavior very unsettling.","exampleTranslation":"이웃들은 그 남자의 기이한 행동이 매우 불안하다고 생각했습니다.","level":24,"category":"빈도 학습"},{"id":13092,"term":"blade","meaning":"날; 칼날","partOfSpeech":"n.","example":"The chef sharpened the blade of the knife before cutting vegetables.","exampleTranslation":"요리사는 채소를 자르기 전에 칼의 날을 갈았습니다.","level":24,"category":"빈도 학습"},{"id":13093,"term":"blaze","meaning":"화염; 활활 타오르다","partOfSpeech":"n.","example":"Firefighters worked through the night to contain the blaze.","exampleTranslation":"소방관들은 화염을 잡기 위해 밤새 일했습니다.","level":24,"category":"빈도 학습"},{"id":13094,"term":"blink","meaning":"눈을 깜빡이다; 깜빡임","partOfSpeech":"v.","example":"He had to blink several times to adjust to the bright sunlight.","exampleTranslation":"그는 밝은 햇빛에 눈을 맞추기 위해 여러 번 눈을 깜빡여야 했습니다.","level":24,"category":"빈도 학습"},{"id":13095,"term":"blur","meaning":"흐릿하게 하다; 흐릿함","partOfSpeech":"v.","example":"Tears can blur your vision and make it hard to see clearly.","exampleTranslation":"눈물은 시야를 흐릿하게 하여 선명하게 보기 어렵게 만들 수 있습니다.","level":24,"category":"빈도 학습"},{"id":13096,"term":"boarder","meaning":"하숙인; 기숙사생","partOfSpeech":"n.","example":"The landlady rented a room to a boarder who worked downtown.","exampleTranslation":"집주인 아주머니는 시내에서 일하는 하숙인에게 방 하나를 임대했습니다.","level":24,"category":"빈도 학습"},{"id":13097,"term":"boast","meaning":"자랑하다; 뽐내다","partOfSpeech":"v.","example":"He loved to boast about his high scores to his classmates.","exampleTranslation":"그는 반 친구들에게 자신의 높은 점수를 자랑하는 것을 좋아했습니다.","level":24,"category":"빈도 학습"},{"id":13098,"term":"bold","meaning":"대담한; 용감한","partOfSpeech":"adj.","example":"The bold explorer set off alone into the uncharted wilderness.","exampleTranslation":"대담한 탐험가는 미지의 황야로 혼자 출발했습니다.","level":24,"category":"빈도 학습"},{"id":13099,"term":"bolt","meaning":"볼트; 빗장; 번개","partOfSpeech":"n.","example":"A single bolt of lightning lit up the entire dark sky.","exampleTranslation":"단 하나의 번개가 어두운 하늘 전체를 밝혔습니다.","level":24,"category":"빈도 학습"},{"id":13100,"term":"bonus","meaning":"보너스; 추가 혜택","partOfSpeech":"n.","example":"All employees received a year-end bonus for their hard work.","exampleTranslation":"모든 직원이 열심히 일한 것에 대해 연말 보너스를 받았습니다.","level":24,"category":"빈도 학습"},{"id":13101,"term":"bounds","meaning":"한계; 경계","partOfSpeech":"n.","example":"The student's enthusiasm went beyond the bounds of the classroom.","exampleTranslation":"그 학생의 열정은 교실의 한계를 넘어섰습니다.","level":24,"category":"빈도 학습"},{"id":13102,"term":"brass","meaning":"놋쇠; 황동","partOfSpeech":"n.","example":"The old doorknob was made of polished brass.","exampleTranslation":"오래된 문손잡이는 광이 난 황동으로 만들어졌습니다.","level":24,"category":"빈도 학습"},{"id":13103,"term":"breach","meaning":"위반; 침해","partOfSpeech":"n.","example":"Sharing that information was a clear breach of privacy.","exampleTranslation":"그 정보를 공유하는 것은 명백한 개인정보 침해였습니다.","level":24,"category":"빈도 학습"},{"id":13104,"term":"breeze","meaning":"산들바람; 미풍","partOfSpeech":"n.","example":"A cool breeze blew through the open window on a hot summer day.","exampleTranslation":"더운 여름날 열린 창문으로 시원한 산들바람이 불어왔습니다.","level":24,"category":"빈도 학습"},{"id":13105,"term":"brew","meaning":"양조하다; (차·커피를) 끓이다","partOfSpeech":"v.","example":"He likes to brew his own coffee every morning before work.","exampleTranslation":"그는 출근 전 매일 아침 직접 커피를 끓이는 것을 좋아합니다.","level":24,"category":"빈도 학습"},{"id":13106,"term":"bride","meaning":"신부","partOfSpeech":"n.","example":"The bride walked slowly down the aisle toward the altar.","exampleTranslation":"신부는 제단을 향해 통로를 천천히 걸어 내려갔습니다.","level":24,"category":"빈도 학습"},{"id":13107,"term":"broker","meaning":"중개인; 브로커","partOfSpeech":"n.","example":"The broker helped us find a good deal on a new apartment.","exampleTranslation":"중개인이 새 아파트에서 좋은 거래를 찾도록 도와주었습니다.","level":24,"category":"빈도 학습"},{"id":13108,"term":"bronze","meaning":"청동; 동메달","partOfSpeech":"n.","example":"The ancient statue was cast in bronze over two thousand years ago.","exampleTranslation":"그 고대 조각상은 2천 년 전에 청동으로 주조되었습니다.","level":24,"category":"빈도 학습"},{"id":13109,"term":"bruise","meaning":"멍; 타박상","partOfSpeech":"n.","example":"She had a painful bruise on her arm after falling off her bike.","exampleTranslation":"그녀는 자전거에서 떨어진 후 팔에 아픈 멍이 생겼습니다.","level":24,"category":"빈도 학습"},{"id":13110,"term":"brute","meaning":"짐승 같은 사람; 야만적인","partOfSpeech":"n.","example":"Only a brute would treat animals so carelessly and cruelly.","exampleTranslation":"짐승 같은 사람만이 동물을 그렇게 부주의하고 잔인하게 다룰 것입니다.","level":24,"category":"빈도 학습"},{"id":13111,"term":"bubble","meaning":"거품; 방울","partOfSpeech":"n.","example":"The child blew a bubble that floated gently across the yard.","exampleTranslation":"아이가 마당을 가로질러 부드럽게 떠다니는 거품을 불었습니다.","level":24,"category":"빈도 학습"},{"id":13112,"term":"bulb","meaning":"전구; 알뿌리","partOfSpeech":"n.","example":"Please replace the broken bulb in the kitchen ceiling light.","exampleTranslation":"주방 천장 조명의 깨진 전구를 교체해 주세요.","level":24,"category":"빈도 학습"},{"id":13113,"term":"bulk","meaning":"대부분; 부피","partOfSpeech":"n.","example":"The bulk of the work was done before the deadline.","exampleTranslation":"대부분의 작업은 마감일 전에 완료되었습니다.","level":24,"category":"빈도 학습"},{"id":13114,"term":"bull","meaning":"황소; 수컷 소","partOfSpeech":"n.","example":"The farmer kept a large bull in the field with the cows.","exampleTranslation":"농부는 소들과 함께 큰 황소를 들판에 두었습니다.","level":24,"category":"빈도 학습"},{"id":13115,"term":"bullet","meaning":"총알; 탄환","partOfSpeech":"n.","example":"The detective found a bullet lodged in the old wooden wall.","exampleTranslation":"형사는 오래된 나무 벽에 박힌 총알을 발견했습니다.","level":24,"category":"빈도 학습"},{"id":13116,"term":"bully","meaning":"괴롭히는 사람; 약자를 괴롭히다","partOfSpeech":"n.","example":"The teacher stepped in when she noticed a bully harassing younger students.","exampleTranslation":"선생님은 한 괴롭히는 아이가 어린 학생들을 괴롭히는 것을 보고 개입했습니다.","level":24,"category":"빈도 학습"},{"id":13117,"term":"bundle","meaning":"묶음; 꾸러미","partOfSpeech":"n.","example":"She carried a bundle of newspapers under her arm every morning.","exampleTranslation":"그녀는 매일 아침 팔 아래에 신문 묶음을 들고 다녔습니다.","level":24,"category":"빈도 학습"},{"id":13118,"term":"bureaucracy","meaning":"관료제; 행정 절차","partOfSpeech":"n.","example":"The long process was slowed down by unnecessary bureaucracy.","exampleTranslation":"그 긴 과정은 불필요한 관료제로 인해 더뎌졌습니다.","level":24,"category":"빈도 학습"},{"id":13119,"term":"bureaucrat","meaning":"관료; 행정 공무원","partOfSpeech":"n.","example":"The local bureaucrat required three forms of identification to process the request.","exampleTranslation":"지역 관료는 요청을 처리하는 데 세 가지 신분증을 요구했습니다.","level":24,"category":"빈도 학습"},{"id":13120,"term":"butterfly","meaning":"나비","partOfSpeech":"n.","example":"A colorful butterfly landed softly on the flower in the garden.","exampleTranslation":"화려한 나비 한 마리가 정원의 꽃 위에 부드럽게 내려앉았습니다.","level":24,"category":"빈도 학습"},{"id":13121,"term":"buzz","meaning":"윙윙거리는 소리; 소문","partOfSpeech":"n.","example":"There was a buzz of excitement in the crowd before the concert started.","exampleTranslation":"콘서트가 시작되기 전 군중 사이에 흥분된 윙윙거리는 소리가 있었습니다.","level":24,"category":"빈도 학습"},{"id":13122,"term":"cab","meaning":"택시; 캡","partOfSpeech":"n.","example":"She hailed a cab outside the hotel to get to the airport on time.","exampleTranslation":"그녀는 제때 공항에 도착하기 위해 호텔 밖에서 택시를 불렀습니다.","level":24,"category":"빈도 학습"},{"id":13123,"term":"cabin","meaning":"오두막; 선실","partOfSpeech":"n.","example":"They spent the weekend at a cozy cabin in the mountains.","exampleTranslation":"그들은 산속의 아늑한 오두막에서 주말을 보냈습니다.","level":24,"category":"빈도 학습"},{"id":13124,"term":"cafe","meaning":"카페; 커피숍","partOfSpeech":"n.","example":"We met at a small cafe near the park to catch up over coffee.","exampleTranslation":"우리는 커피를 마시며 안부를 나누기 위해 공원 근처의 작은 카페에서 만났습니다.","level":24,"category":"빈도 학습"},{"id":13125,"term":"calendar","meaning":"달력; 일정표","partOfSpeech":"n.","example":"He marked the important meeting date on the office calendar.","exampleTranslation":"그는 사무실 달력에 중요한 회의 날짜를 표시했습니다.","level":24,"category":"빈도 학습"},{"id":13126,"term":"campus","meaning":"캠퍼스; 대학 구내","partOfSpeech":"n.","example":"Students gathered on the campus lawn to enjoy the sunny afternoon.","exampleTranslation":"학생들이 화창한 오후를 즐기기 위해 캠퍼스 잔디밭에 모였습니다.","level":24,"category":"빈도 학습"},{"id":13127,"term":"canal","meaning":"운하; 수로","partOfSpeech":"n.","example":"Boats traveled slowly along the canal through the heart of the city.","exampleTranslation":"보트들이 도시 중심을 가로지르는 운하를 따라 천천히 이동했습니다.","level":24,"category":"빈도 학습"},{"id":13128,"term":"candle","meaning":"양초","partOfSpeech":"n.","example":"She lit a candle to create a warm and relaxing atmosphere at dinner.","exampleTranslation":"그녀는 저녁 식사 자리에 따뜻하고 편안한 분위기를 만들기 위해 양초를 켰습니다.","level":24,"category":"빈도 학습"},{"id":13129,"term":"canvas","meaning":"캔버스; 화포","partOfSpeech":"n.","example":"The artist stretched a fresh canvas across the wooden frame before painting.","exampleTranslation":"화가는 그림을 그리기 전에 나무 프레임 위에 새 캔버스를 펼쳤습니다.","level":24,"category":"빈도 학습"},{"id":13130,"term":"capitalism","meaning":"자본주의","partOfSpeech":"n.","example":"Economists debate whether capitalism leads to greater inequality over time.","exampleTranslation":"경제학자들은 자본주의가 시간이 지남에 따라 더 큰 불평등으로 이어지는지 논쟁합니다.","level":24,"category":"빈도 학습"},{"id":13131,"term":"capitalist","meaning":"자본가; 자본주의자","partOfSpeech":"n.","example":"The venture capitalist invested heavily in several technology startups.","exampleTranslation":"그 벤처 자본가는 여러 기술 스타트업에 많은 투자를 했습니다.","level":24,"category":"빈도 학습"},{"id":13132,"term":"cargo","meaning":"화물; 짐","partOfSpeech":"n.","example":"The ship carried a large cargo of electronics from Asia to Europe.","exampleTranslation":"그 배는 아시아에서 유럽으로 대량의 전자제품 화물을 운반했습니다.","level":24,"category":"빈도 학습"},{"id":13133,"term":"carriage","meaning":"마차; 객차","partOfSpeech":"n.","example":"The royal family rode in a golden carriage through the city streets.","exampleTranslation":"왕실 가족은 도시 거리를 황금 마차를 타고 이동했습니다.","level":24,"category":"빈도 학습"},{"id":13134,"term":"cartoon","meaning":"만화; 만화 영화","partOfSpeech":"n.","example":"My kids love watching a funny cartoon on Saturday mornings.","exampleTranslation":"우리 아이들은 토요일 아침에 재미있는 만화 보는 것을 좋아합니다.","level":24,"category":"빈도 학습"},{"id":13135,"term":"casualty","meaning":"사상자; 피해자","partOfSpeech":"n.","example":"The news reported that there was one casualty in the traffic accident.","exampleTranslation":"뉴스에서 그 교통사고에 사상자가 한 명 발생했다고 보도했습니다.","level":24,"category":"빈도 학습"},{"id":13136,"term":"cater","meaning":"음식을 제공하다; 요구를 충족시키다","partOfSpeech":"v.","example":"The restaurant will cater to guests with special dietary needs at the event.","exampleTranslation":"그 식당은 행사에서 특별한 식이 요구가 있는 손님들을 위해 음식을 제공할 것입니다.","level":25,"category":"빈도 학습"},{"id":13137,"term":"cathedral","meaning":"대성당","partOfSpeech":"n.","example":"Tourists came from around the world to see the famous Gothic cathedral.","exampleTranslation":"관광객들이 유명한 고딕 대성당을 보기 위해 전 세계에서 왔습니다.","level":25,"category":"빈도 학습"},{"id":13138,"term":"caution","meaning":"주의; 경고","partOfSpeech":"n.","example":"The sign advised drivers to proceed with caution on the icy road.","exampleTranslation":"표지판은 운전자들에게 빙판 도로에서 주의를 기울이며 진행하라고 권고했습니다.","level":25,"category":"빈도 학습"},{"id":13139,"term":"cautious","meaning":"신중한; 조심스러운","partOfSpeech":"adj.","example":"She is always cautious when making financial decisions for the family.","exampleTranslation":"그녀는 가족을 위한 재정 결정을 내릴 때 항상 신중합니다.","level":25,"category":"빈도 학습"},{"id":13140,"term":"cave","meaning":"동굴","partOfSpeech":"n.","example":"The explorers discovered ancient paintings inside a dark cave.","exampleTranslation":"탐험가들은 어두운 동굴 안에서 고대 그림을 발견했습니다.","level":25,"category":"빈도 학습"},{"id":13141,"term":"celebrity","meaning":"유명인; 명사","partOfSpeech":"n.","example":"The young celebrity arrived at the award show surrounded by fans.","exampleTranslation":"젊은 유명인이 팬들에 둘러싸여 시상식에 도착했습니다.","level":25,"category":"빈도 학습"},{"id":13142,"term":"cemetery","meaning":"묘지; 공동묘지","partOfSpeech":"n.","example":"The family visited the cemetery every year on the anniversary of her passing.","exampleTranslation":"가족은 그녀의 기일마다 매년 묘지를 방문했습니다.","level":25,"category":"빈도 학습"},{"id":13143,"term":"censor","meaning":"검열하다; 검열관","partOfSpeech":"v.","example":"The government decided to censor certain websites that spread false information.","exampleTranslation":"정부는 허위 정보를 퍼뜨리는 특정 웹사이트를 검열하기로 결정했습니다.","level":25,"category":"빈도 학습"},{"id":13144,"term":"census","meaning":"인구 조사; 센서스","partOfSpeech":"n.","example":"The government conducts a census every ten years to count the population.","exampleTranslation":"정부는 인구를 파악하기 위해 10년마다 인구 조사를 실시합니다.","level":25,"category":"빈도 학습"},{"id":13145,"term":"certificate","meaning":"증명서; 자격증","partOfSpeech":"n.","example":"She received a certificate after completing the online language course.","exampleTranslation":"그녀는 온라인 어학 강좌를 완료한 후 수료증을 받았습니다.","level":25,"category":"빈도 학습"},{"id":13146,"term":"certify","meaning":"인증하다; 증명하다","partOfSpeech":"v.","example":"The organization will certify that all products meet international safety standards.","exampleTranslation":"그 기관은 모든 제품이 국제 안전 기준을 충족한다고 인증할 것입니다.","level":25,"category":"빈도 학습"},{"id":13147,"term":"champagne","meaning":"샴페인","partOfSpeech":"n.","example":"They toasted with a glass of champagne to celebrate the New Year.","exampleTranslation":"그들은 새해를 축하하기 위해 샴페인 한 잔으로 건배했습니다.","level":25,"category":"빈도 학습"},{"id":13148,"term":"chancellor","meaning":"총리; 수상; 총장","partOfSpeech":"n.","example":"The chancellor announced major education reforms at the press conference.","exampleTranslation":"총리는 기자 회견에서 주요 교육 개혁을 발표했습니다.","level":25,"category":"빈도 학습"},{"id":13149,"term":"chaos","meaning":"혼돈; 혼란","partOfSpeech":"n.","example":"The sudden power outage caused chaos in the busy shopping mall.","exampleTranslation":"갑작스러운 정전이 붐비는 쇼핑몰에서 혼란을 일으켰습니다.","level":25,"category":"빈도 학습"},{"id":13150,"term":"chapel","meaning":"예배당; 작은 교회","partOfSpeech":"n.","example":"The wedding took place in a small chapel near the park.","exampleTranslation":"결혼식은 공원 근처의 작은 예배당에서 열렸어요.","level":25,"category":"빈도 학습"},{"id":13151,"term":"chef","meaning":"요리사; 주방장","partOfSpeech":"n.","example":"The chef prepared a special dish for the guests.","exampleTranslation":"요리사가 손님들을 위해 특별한 요리를 준비했어요.","level":25,"category":"빈도 학습"},{"id":13152,"term":"chemistry","meaning":"화학; (사람 간의) 케미","partOfSpeech":"n.","example":"She studied chemistry at the university for four years.","exampleTranslation":"그녀는 대학에서 4년간 화학을 공부했어요.","level":25,"category":"빈도 학습"},{"id":13153,"term":"chin","meaning":"턱; 아래턱","partOfSpeech":"n.","example":"He rested his chin on his hand while thinking.","exampleTranslation":"그는 생각하면서 손 위에 턱을 얹었어요.","level":25,"category":"빈도 학습"},{"id":13154,"term":"choir","meaning":"합창단; 성가대","partOfSpeech":"n.","example":"The choir performed beautifully at the holiday concert.","exampleTranslation":"합창단이 연말 콘서트에서 아름답게 공연했어요.","level":25,"category":"빈도 학습"},{"id":13155,"term":"choke","meaning":"질식하다; 막히다","partOfSpeech":"v.","example":"Be careful not to choke on food when eating quickly.","exampleTranslation":"빨리 먹을 때 음식에 목이 막히지 않도록 조심하세요.","level":25,"category":"빈도 학습"},{"id":13156,"term":"cholesterol","meaning":"콜레스테롤","partOfSpeech":"n.","example":"The doctor advised him to lower his cholesterol through diet.","exampleTranslation":"의사는 그에게 식단을 통해 콜레스테롤을 낮추라고 조언했어요.","level":25,"category":"빈도 학습"},{"id":13157,"term":"chronic","meaning":"만성적인; 고질적인","partOfSpeech":"adj.","example":"He has been dealing with chronic back pain for many years.","exampleTranslation":"그는 수년째 만성 요통을 앓고 있어요.","level":25,"category":"빈도 학습"},{"id":13158,"term":"chronicle","meaning":"연대기; 역사적 기록","partOfSpeech":"n.","example":"The book is a chronicle of events during the civil war.","exampleTranslation":"그 책은 내전 동안의 사건들을 담은 연대기예요.","level":25,"category":"빈도 학습"},{"id":13159,"term":"chunk","meaning":"덩어리; 큰 조각","partOfSpeech":"n.","example":"She cut a large chunk of cheese for the appetizer.","exampleTranslation":"그녀는 전채 요리로 큰 덩어리의 치즈를 잘랐어요.","level":25,"category":"빈도 학습"},{"id":13160,"term":"cinema","meaning":"영화관; 영화 산업","partOfSpeech":"n.","example":"They went to the cinema to watch the new action film.","exampleTranslation":"그들은 새 액션 영화를 보러 영화관에 갔어요.","level":25,"category":"빈도 학습"},{"id":13161,"term":"civic","meaning":"시민의; 도시의","partOfSpeech":"adj.","example":"Voting is an important civic duty for every citizen.","exampleTranslation":"투표는 모든 시민의 중요한 시민적 의무예요.","level":25,"category":"빈도 학습"},{"id":13162,"term":"clash","meaning":"충돌하다; 부딪히다","partOfSpeech":"v.","example":"The two groups clash over their different opinions every time.","exampleTranslation":"두 집단은 서로 다른 의견 때문에 매번 충돌해요.","level":25,"category":"빈도 학습"},{"id":13163,"term":"classification","meaning":"분류; 등급 구분","partOfSpeech":"n.","example":"The classification of animals by species helps scientists study them.","exampleTranslation":"동물을 종별로 분류하면 과학자들이 연구하는 데 도움이 돼요.","level":25,"category":"빈도 학습"},{"id":13164,"term":"classify","meaning":"분류하다; 구분하다","partOfSpeech":"v.","example":"Scientists classify plants based on their structure and genetics.","exampleTranslation":"과학자들은 구조와 유전자를 바탕으로 식물을 분류해요.","level":25,"category":"빈도 학습"},{"id":13165,"term":"clay","meaning":"점토; 찰흙","partOfSpeech":"n.","example":"The children shaped figures out of clay during art class.","exampleTranslation":"아이들은 미술 시간에 찰흙으로 조형물을 만들었어요.","level":25,"category":"빈도 학습"},{"id":13166,"term":"clerk","meaning":"점원; 사무원","partOfSpeech":"n.","example":"The clerk at the front desk helped us check in quickly.","exampleTranslation":"안내 데스크의 사무원이 우리가 빠르게 체크인할 수 있도록 도와줬어요.","level":25,"category":"빈도 학습"},{"id":13167,"term":"click","meaning":"클릭하다; 딸깍 소리를 내다","partOfSpeech":"v.","example":"Please click the button to submit your application form.","exampleTranslation":"지원서를 제출하려면 버튼을 클릭해 주세요.","level":25,"category":"빈도 학습"},{"id":13168,"term":"cling","meaning":"매달리다; 달라붙다","partOfSpeech":"v.","example":"The wet shirt tends to cling to your skin in hot weather.","exampleTranslation":"더운 날씨에 젖은 셔츠가 피부에 달라붙는 경향이 있어요.","level":25,"category":"빈도 학습"},{"id":13169,"term":"clone","meaning":"복제품; 복제하다","partOfSpeech":"n.","example":"Scientists created a clone of the rare plant to preserve it.","exampleTranslation":"과학자들은 희귀 식물을 보존하기 위해 복제품을 만들었어요.","level":25,"category":"빈도 학습"},{"id":13170,"term":"closure","meaning":"종결; 폐쇄","partOfSpeech":"n.","example":"The closure of the old factory affected hundreds of workers.","exampleTranslation":"오래된 공장의 폐쇄는 수백 명의 근로자에게 영향을 미쳤어요.","level":25,"category":"빈도 학습"},{"id":13171,"term":"clutch","meaning":"꽉 잡다; 움켜쥐다","partOfSpeech":"v.","example":"She had to clutch the railing tightly to keep her balance.","exampleTranslation":"그녀는 균형을 유지하기 위해 난간을 꽉 잡아야 했어요.","level":25,"category":"빈도 학습"},{"id":13172,"term":"coffin","meaning":"관; 棺","partOfSpeech":"n.","example":"The coffin was carried slowly by six pallbearers at the funeral.","exampleTranslation":"장례식에서 관이 여섯 명의 운구자에 의해 천천히 운반되었어요.","level":25,"category":"빈도 학습"},{"id":13173,"term":"cognitive","meaning":"인지의; 인식과 관련된","partOfSpeech":"adj.","example":"Regular exercise can improve cognitive function in older adults.","exampleTranslation":"규칙적인 운동은 노인의 인지 기능을 향상시킬 수 있어요.","level":25,"category":"빈도 학습"},{"id":13174,"term":"coherent","meaning":"일관된; 논리적으로 통하는","partOfSpeech":"adj.","example":"She gave a coherent explanation that everyone could easily follow.","exampleTranslation":"그녀는 모두가 쉽게 이해할 수 있는 일관된 설명을 했어요.","level":25,"category":"빈도 학습"},{"id":13175,"term":"collar","meaning":"칼라; 옷깃; 목줄","partOfSpeech":"n.","example":"He adjusted his collar before walking into the job interview.","exampleTranslation":"그는 취업 면접에 들어가기 전에 칼라를 다듬었어요.","level":25,"category":"빈도 학습"},{"id":13176,"term":"colonel","meaning":"대령","partOfSpeech":"n.","example":"The colonel gave orders to the soldiers before the mission began.","exampleTranslation":"대령은 임무가 시작되기 전에 병사들에게 명령을 내렸어요.","level":25,"category":"빈도 학습"},{"id":13177,"term":"comic","meaning":"만화; 웃기는","partOfSpeech":"n.","example":"He reads a new comic every week at the bookstore.","exampleTranslation":"그는 매주 서점에서 새 만화를 읽어요.","level":25,"category":"빈도 학습"},{"id":13178,"term":"commentator","meaning":"해설가; 평론가","partOfSpeech":"n.","example":"The sports commentator described every play during the live game.","exampleTranslation":"스포츠 해설가가 생중계 경기 동안 모든 플레이를 설명했어요.","level":25,"category":"빈도 학습"},{"id":13179,"term":"commodity","meaning":"상품; 원자재","partOfSpeech":"n.","example":"Oil is a valuable commodity traded across the global market.","exampleTranslation":"석유는 전 세계 시장에서 거래되는 귀중한 상품이에요.","level":25,"category":"빈도 학습"},{"id":13180,"term":"compact","meaning":"소형의; 촘촘한","partOfSpeech":"adj.","example":"This compact camera is easy to carry anywhere you go.","exampleTranslation":"이 소형 카메라는 어디든 가지고 다니기 편해요.","level":25,"category":"빈도 학습"},{"id":13181,"term":"comparative","meaning":"비교의; 상대적인","partOfSpeech":"adj.","example":"The report includes a comparative study of two different methods.","exampleTranslation":"그 보고서에는 두 가지 다른 방법에 대한 비교 연구가 포함되어 있어요.","level":25,"category":"빈도 학습"},{"id":13182,"term":"compatible","meaning":"호환 가능한; 함께 어울리는","partOfSpeech":"adj.","example":"Make sure the new software is compatible with your operating system.","exampleTranslation":"새 소프트웨어가 운영체제와 호환 가능한지 확인하세요.","level":25,"category":"빈도 학습"},{"id":13183,"term":"compel","meaning":"강요하다; ~하게 만들다","partOfSpeech":"v.","example":"The new rules compel all drivers to wear seatbelts at all times.","exampleTranslation":"새 규칙은 모든 운전자가 항상 안전벨트를 착용하도록 강요해요.","level":25,"category":"빈도 학습"},{"id":13184,"term":"competence","meaning":"능력; 역량","partOfSpeech":"n.","example":"The manager assessed each employee's competence before the promotion.","exampleTranslation":"관리자는 승진 전에 각 직원의 역량을 평가했어요.","level":25,"category":"빈도 학습"},{"id":13185,"term":"compile","meaning":"편집하다; 모아서 정리하다","partOfSpeech":"v.","example":"She will compile all the research data into a single report.","exampleTranslation":"그녀는 모든 연구 데이터를 하나의 보고서로 편집할 거예요.","level":25,"category":"빈도 학습"},{"id":13186,"term":"complement","meaning":"보완하다; 완벽하게 맞다","partOfSpeech":"v.","example":"The white wine will complement the fish dish perfectly tonight.","exampleTranslation":"오늘 밤 화이트 와인이 생선 요리를 완벽하게 보완해 줄 거예요.","level":25,"category":"빈도 학습"},{"id":13187,"term":"compliance","meaning":"준수; 순응","partOfSpeech":"n.","example":"All companies must ensure compliance with the new safety regulations.","exampleTranslation":"모든 회사는 새로운 안전 규정을 준수해야 해요.","level":25,"category":"빈도 학습"},{"id":13188,"term":"comprehend","meaning":"이해하다; 파악하다","partOfSpeech":"v.","example":"It is hard to comprehend the full scale of the disaster.","exampleTranslation":"재난의 전체 규모를 이해하기는 어려워요.","level":25,"category":"빈도 학습"},{"id":13189,"term":"compress","meaning":"압축하다; 압박하다","partOfSpeech":"v.","example":"You can compress the file to save storage space on your device.","exampleTranslation":"기기의 저장 공간을 절약하기 위해 파일을 압축할 수 있어요.","level":25,"category":"빈도 학습"},{"id":13190,"term":"con","meaning":"단점; 사기; 속이다","partOfSpeech":"n.","example":"Every plan has a pro and a con that you should weigh carefully.","exampleTranslation":"모든 계획에는 신중하게 따져봐야 할 장점과 단점이 있어요.","level":25,"category":"빈도 학습"},{"id":13191,"term":"conceal","meaning":"숨기다; 감추다","partOfSpeech":"v.","example":"She tried to conceal her nervousness before giving the speech.","exampleTranslation":"그녀는 연설 전에 긴장감을 감추려고 했어요.","level":25,"category":"빈도 학습"},{"id":13192,"term":"concede","meaning":"인정하다; 양보하다","partOfSpeech":"v.","example":"He had to concede that his original plan had several flaws.","exampleTranslation":"그는 자신의 원래 계획에 몇 가지 결함이 있음을 인정해야 했어요.","level":25,"category":"빈도 학습"},{"id":13193,"term":"concession","meaning":"양보; 특허권; 매점","partOfSpeech":"n.","example":"Both sides made a concession to reach a fair agreement.","exampleTranslation":"양측은 공정한 합의에 도달하기 위해 양보를 했어요.","level":25,"category":"빈도 학습"},{"id":13194,"term":"configure","meaning":"설정하다; 구성하다","partOfSpeech":"v.","example":"You need to configure the router before using the new network.","exampleTranslation":"새 네트워크를 사용하기 전에 라우터를 설정해야 해요.","level":25,"category":"빈도 학습"},{"id":13195,"term":"conform","meaning":"따르다; 순응하다","partOfSpeech":"v.","example":"New employees are expected to conform to the company's dress code.","exampleTranslation":"신입 사원들은 회사의 복장 규정을 따를 것으로 기대돼요.","level":25,"category":"빈도 학습"},{"id":13196,"term":"congratulate","meaning":"축하하다","partOfSpeech":"v.","example":"Everyone gathered to congratulate her on winning the award.","exampleTranslation":"모두가 그녀의 수상을 축하하기 위해 모였어요.","level":25,"category":"빈도 학습"},{"id":13197,"term":"congregate","meaning":"모이다; 집합하다","partOfSpeech":"v.","example":"People congregate in the town square every Saturday morning.","exampleTranslation":"사람들은 매주 토요일 아침에 마을 광장에 모여요.","level":25,"category":"빈도 학습"},{"id":13198,"term":"conscience","meaning":"양심; 도덕적 감각","partOfSpeech":"n.","example":"His conscience would not let him keep the lost wallet.","exampleTranslation":"그의 양심이 잃어버린 지갑을 가지고 있지 못하게 했어요.","level":25,"category":"빈도 학습"},{"id":13199,"term":"consensus","meaning":"합의; 의견 일치","partOfSpeech":"n.","example":"The team reached a consensus on the best approach to the problem.","exampleTranslation":"팀은 문제에 대한 최선의 접근 방식에 대해 합의에 도달했어요.","level":25,"category":"빈도 학습"},{"id":13200,"term":"consistency","meaning":"일관성; 한결같음","partOfSpeech":"n.","example":"Consistency in practice is the key to mastering any skill.","exampleTranslation":"꾸준한 연습이 어떤 기술이든 완성하는 열쇠입니다.","level":25,"category":"빈도 학습"},{"id":13201,"term":"console","meaning":"위로하다; 위안을 주다","partOfSpeech":"v.","example":"She tried to console her friend after the loss.","exampleTranslation":"그녀는 상실 후 친구를 위로하려고 노력했습니다.","level":25,"category":"빈도 학습"},{"id":13202,"term":"consolidate","meaning":"통합하다; 강화하다","partOfSpeech":"v.","example":"The company decided to consolidate its two offices into one.","exampleTranslation":"회사는 두 사무소를 하나로 통합하기로 결정했습니다.","level":25,"category":"빈도 학습"},{"id":13203,"term":"conspiracy","meaning":"음모; 공모","partOfSpeech":"n.","example":"The investigators uncovered a conspiracy to commit fraud.","exampleTranslation":"수사관들은 사기를 저지르려는 음모를 밝혀냈습니다.","level":25,"category":"빈도 학습"},{"id":13204,"term":"constituency","meaning":"선거구; 지지층","partOfSpeech":"n.","example":"The senator visited every town in her constituency before the election.","exampleTranslation":"상원의원은 선거 전에 자신의 선거구 내 모든 마을을 방문했습니다.","level":25,"category":"빈도 학습"},{"id":13205,"term":"contaminate","meaning":"오염시키다; 더럽히다","partOfSpeech":"v.","example":"Industrial waste can contaminate nearby rivers and harm wildlife.","exampleTranslation":"산업 폐기물은 인근 강을 오염시키고 야생동물에게 해를 끼칠 수 있습니다.","level":25,"category":"빈도 학습"},{"id":13206,"term":"contemplate","meaning":"심사숙고하다; 곰곰이 생각하다","partOfSpeech":"v.","example":"He sat quietly to contemplate his next major career move.","exampleTranslation":"그는 다음 중요한 진로 선택을 곰곰이 생각하기 위해 조용히 앉아 있었습니다.","level":25,"category":"빈도 학습"},{"id":13207,"term":"contempt","meaning":"경멸; 멸시","partOfSpeech":"n.","example":"She could not hide her contempt for his dishonest behavior.","exampleTranslation":"그녀는 그의 부정직한 행동에 대한 경멸을 숨길 수 없었습니다.","level":25,"category":"빈도 학습"},{"id":13208,"term":"contingent","meaning":"~에 달려 있는; 조건부의","partOfSpeech":"adj.","example":"The project approval is contingent on securing enough funding.","exampleTranslation":"프로젝트 승인은 충분한 자금 확보에 달려 있습니다.","level":25,"category":"빈도 학습"},{"id":13209,"term":"contrary","meaning":"반대의; 상반되는","partOfSpeech":"adj.","example":"Contrary to popular belief, bats are not actually blind.","exampleTranslation":"대중적인 믿음과 반대로, 박쥐는 실제로 눈이 멀지 않았습니다.","level":25,"category":"빈도 학습"},{"id":13210,"term":"convenience","meaning":"편의; 편리함","partOfSpeech":"n.","example":"Online shopping offers great convenience for busy people.","exampleTranslation":"온라인 쇼핑은 바쁜 사람들에게 큰 편의를 제공합니다.","level":25,"category":"빈도 학습"},{"id":13211,"term":"conversion","meaning":"전환; 변환","partOfSpeech":"n.","example":"The conversion of the old factory into apartments took two years.","exampleTranslation":"오래된 공장을 아파트로 전환하는 데 2년이 걸렸습니다.","level":25,"category":"빈도 학습"},{"id":13212,"term":"copper","meaning":"구리; 동","partOfSpeech":"n.","example":"Electrical wires are often made of copper because it conducts electricity well.","exampleTranslation":"전선은 전기 전도성이 좋아서 구리로 만들어지는 경우가 많습니다.","level":25,"category":"빈도 학습"},{"id":13213,"term":"copyright","meaning":"저작권; 판권","partOfSpeech":"n.","example":"You must obtain permission before using an image protected by copyright.","exampleTranslation":"저작권으로 보호된 이미지를 사용하기 전에 허락을 받아야 합니다.","level":25,"category":"빈도 학습"},{"id":13214,"term":"cord","meaning":"끈; 줄; 전선","partOfSpeech":"n.","example":"Please untangle the cord before plugging in the lamp.","exampleTranslation":"램프를 연결하기 전에 전선을 풀어 주세요.","level":25,"category":"빈도 학습"},{"id":13215,"term":"corn","meaning":"옥수수","partOfSpeech":"n.","example":"Farmers in this region grow corn as their main crop.","exampleTranslation":"이 지역의 농부들은 옥수수를 주요 작물로 재배합니다.","level":25,"category":"빈도 학습"},{"id":13216,"term":"corps","meaning":"부대; 단체","partOfSpeech":"n.","example":"The marine corps trained for months before the mission.","exampleTranslation":"해병대 부대는 임무 전 몇 달간 훈련했습니다.","level":25,"category":"빈도 학습"},{"id":13217,"term":"costume","meaning":"의상; 복장","partOfSpeech":"n.","example":"She wore a beautiful costume for the Halloween party.","exampleTranslation":"그녀는 핼러윈 파티를 위해 아름다운 의상을 입었습니다.","level":25,"category":"빈도 학습"},{"id":13218,"term":"couch","meaning":"소파; 긴 의자","partOfSpeech":"n.","example":"He fell asleep on the couch while watching television.","exampleTranslation":"그는 텔레비전을 보다가 소파에서 잠들었습니다.","level":25,"category":"빈도 학습"},{"id":13219,"term":"counterpart","meaning":"대응하는 사람; 상대방","partOfSpeech":"n.","example":"The minister met with his counterpart from the neighboring country.","exampleTranslation":"장관은 이웃 나라의 대응 관료를 만났습니다.","level":25,"category":"빈도 학습"},{"id":13220,"term":"coup","meaning":"쿠데타; 대성공","partOfSpeech":"n.","example":"The military staged a coup and seized control of the government.","exampleTranslation":"군부는 쿠데타를 일으켜 정부를 장악했습니다.","level":25,"category":"빈도 학습"},{"id":13221,"term":"courtesy","meaning":"예의; 정중함","partOfSpeech":"n.","example":"He showed great courtesy by holding the door open for everyone.","exampleTranslation":"그는 모든 사람을 위해 문을 잡아줌으로써 큰 예의를 보였습니다.","level":25,"category":"빈도 학습"},{"id":13222,"term":"credible","meaning":"믿을 수 있는; 신뢰할 만한","partOfSpeech":"adj.","example":"The journalist published a credible report backed by solid evidence.","exampleTranslation":"그 기자는 탄탄한 증거에 뒷받침된 믿을 수 있는 보도를 발표했습니다.","level":25,"category":"빈도 학습"},{"id":13223,"term":"critique","meaning":"비평; 평론","partOfSpeech":"n.","example":"The professor gave a detailed critique of each student's essay.","exampleTranslation":"교수는 각 학생의 에세이에 대해 상세한 비평을 했습니다.","level":25,"category":"빈도 학습"},{"id":13224,"term":"crude","meaning":"조잡한; 미가공의; 천연 그대로의","partOfSpeech":"adj.","example":"The factory refines crude oil into usable fuel.","exampleTranslation":"공장은 원유를 사용 가능한 연료로 정제합니다.","level":25,"category":"빈도 학습"},{"id":13225,"term":"crumble","meaning":"부스러지다; 무너지다","partOfSpeech":"v.","example":"Old buildings can crumble if they are not properly maintained.","exampleTranslation":"낡은 건물은 제대로 관리하지 않으면 무너질 수 있습니다.","level":25,"category":"빈도 학습"},{"id":13226,"term":"crust","meaning":"껍질; 지각; 빵 껍데기","partOfSpeech":"n.","example":"The crust of the bread was crispy and golden brown.","exampleTranslation":"빵의 껍질은 바삭하고 황금빛 갈색이었습니다.","level":25,"category":"빈도 학습"},{"id":13227,"term":"cube","meaning":"정육면체; 주사위 모양","partOfSpeech":"n.","example":"She dropped a cube of sugar into her coffee.","exampleTranslation":"그녀는 커피에 각설탕 한 조각을 떨어뜨렸습니다.","level":25,"category":"빈도 학습"},{"id":13228,"term":"cult","meaning":"숭배 집단; 광적인 추종","partOfSpeech":"n.","example":"The film became a cult classic among science fiction fans.","exampleTranslation":"그 영화는 공상과학 팬들 사이에서 열성적인 추종을 받는 고전이 되었습니다.","level":25,"category":"빈도 학습"},{"id":13229,"term":"cultivate","meaning":"경작하다; 기르다; 함양하다","partOfSpeech":"v.","example":"Farmers cultivate the land every spring before planting seeds.","exampleTranslation":"농부들은 씨앗을 심기 전에 매봄 땅을 경작합니다.","level":25,"category":"빈도 학습"},{"id":13230,"term":"curse","meaning":"저주; 욕설","partOfSpeech":"n.","example":"The villagers believed the old house was under a curse.","exampleTranslation":"마을 사람들은 그 오래된 집이 저주에 걸려 있다고 믿었습니다.","level":25,"category":"빈도 학습"},{"id":13231,"term":"custody","meaning":"양육권; 구금; 보관","partOfSpeech":"n.","example":"The court granted sole custody of the child to the mother.","exampleTranslation":"법원은 어머니에게 아이의 단독 양육권을 부여했습니다.","level":25,"category":"빈도 학습"},{"id":13232,"term":"cynical","meaning":"냉소적인; 비판적인","partOfSpeech":"adj.","example":"He became cynical about politics after years of broken promises.","exampleTranslation":"수년간 지켜지지 않은 약속들 이후 그는 정치에 냉소적이 되었습니다.","level":25,"category":"빈도 학습"},{"id":13233,"term":"dam","meaning":"댐; 둑","partOfSpeech":"n.","example":"The dam holds back millions of gallons of water for the city.","exampleTranslation":"댐은 도시를 위해 수백만 갤런의 물을 막고 있습니다.","level":25,"category":"빈도 학습"},{"id":13234,"term":"dash","meaning":"돌진하다; 급히 가다","partOfSpeech":"v.","example":"He had to dash to the station to catch the last train.","exampleTranslation":"그는 막차를 타기 위해 역으로 급히 달려가야 했습니다.","level":25,"category":"빈도 학습"},{"id":13235,"term":"deaf","meaning":"청각 장애가 있는; 듣지 못하는","partOfSpeech":"adj.","example":"The school offers special programs for students who are deaf.","exampleTranslation":"그 학교는 청각 장애가 있는 학생들을 위한 특별 프로그램을 제공합니다.","level":25,"category":"빈도 학습"},{"id":13236,"term":"debut","meaning":"데뷔; 첫 등장","partOfSpeech":"n.","example":"The young singer made a stunning debut at the national concert.","exampleTranslation":"그 젊은 가수는 국가 콘서트에서 놀라운 데뷔를 했습니다.","level":25,"category":"빈도 학습"},{"id":13237,"term":"decay","meaning":"부패하다; 쇠퇴하다","partOfSpeech":"v.","example":"Fallen leaves decay and return nutrients to the soil.","exampleTranslation":"낙엽은 부패하여 토양에 영양분을 돌려줍니다.","level":25,"category":"빈도 학습"},{"id":13238,"term":"decisive","meaning":"결정적인; 단호한","partOfSpeech":"adj.","example":"A decisive victory in the final match secured the championship.","exampleTranslation":"결승전에서의 결정적인 승리가 우승을 확정 지었습니다.","level":25,"category":"빈도 학습"},{"id":13239,"term":"deduct","meaning":"공제하다; 빼다","partOfSpeech":"v.","example":"The employer will deduct taxes from your monthly salary.","exampleTranslation":"고용주는 월급에서 세금을 공제할 것입니다.","level":25,"category":"빈도 학습"},{"id":13240,"term":"deem","meaning":"여기다; 간주하다","partOfSpeech":"v.","example":"The committee will deem the proposal acceptable if all conditions are met.","exampleTranslation":"모든 조건이 충족되면 위원회는 그 제안을 수용 가능한 것으로 간주할 것입니다.","level":25,"category":"빈도 학습"},{"id":13241,"term":"deer","meaning":"사슴","partOfSpeech":"n.","example":"A deer stood at the edge of the forest watching us quietly.","exampleTranslation":"사슴 한 마리가 숲 가장자리에 서서 조용히 우리를 바라보고 있었습니다.","level":25,"category":"빈도 학습"},{"id":13242,"term":"defect","meaning":"결함; 결점","partOfSpeech":"n.","example":"The manufacturer recalled the product due to a safety defect.","exampleTranslation":"제조사는 안전 결함으로 인해 제품을 리콜했습니다.","level":25,"category":"빈도 학습"},{"id":13243,"term":"defer","meaning":"미루다; 연기하다","partOfSpeech":"v.","example":"They chose to defer the meeting until all members could attend.","exampleTranslation":"그들은 모든 회원이 참석할 수 있을 때까지 회의를 미루기로 결정했습니다.","level":26,"category":"빈도 학습"},{"id":13244,"term":"deficiency","meaning":"결핍; 부족; 부족분","partOfSpeech":"n.","example":"A vitamin D deficiency can weaken your bones over time.","exampleTranslation":"비타민 D 결핍은 시간이 지남에 따라 뼈를 약하게 만들 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13245,"term":"defy","meaning":"거부하다; 반항하다; 무시하다","partOfSpeech":"v.","example":"Her achievements defy all expectations for someone her age.","exampleTranslation":"그녀의 성취는 그 나이또래에 대한 모든 기대를 뛰어넘습니다.","level":26,"category":"빈도 학습"},{"id":13246,"term":"delicate","meaning":"섬세한; 연약한; 미묘한","partOfSpeech":"adj.","example":"The surgeon performed a delicate operation on the patient's brain.","exampleTranslation":"외과의사는 환자의 뇌에 섬세한 수술을 시행했습니다.","level":26,"category":"빈도 학습"},{"id":13247,"term":"demography","meaning":"인구통계학; 인구 구조","partOfSpeech":"n.","example":"The study of demography helps governments plan for future housing needs.","exampleTranslation":"인구통계학 연구는 정부가 미래의 주거 수요를 계획하는 데 도움을 줍니다.","level":26,"category":"빈도 학습"},{"id":13248,"term":"dependence","meaning":"의존; 종속","partOfSpeech":"n.","example":"His dependence on coffee made it hard for him to start the day without it.","exampleTranslation":"커피에 대한 의존 때문에 그는 커피 없이 하루를 시작하기가 힘들었습니다.","level":26,"category":"빈도 학습"},{"id":13249,"term":"deprive","meaning":"빼앗다; 박탈하다","partOfSpeech":"v.","example":"Lack of sleep can deprive the body of the rest it needs to recover.","exampleTranslation":"수면 부족은 몸이 회복하는 데 필요한 휴식을 빼앗을 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13250,"term":"despair","meaning":"절망; 자포자기","partOfSpeech":"n.","example":"After losing his job, despair overwhelmed him completely.","exampleTranslation":"직장을 잃은 후 절망이 그를 완전히 짓눌렀습니다.","level":26,"category":"빈도 학습"},{"id":13251,"term":"dispatch","meaning":"발송하다; 급파하다","partOfSpeech":"v.","example":"The company will dispatch a technician to fix the issue.","exampleTranslation":"회사는 문제를 해결하기 위해 기술자를 급파할 것입니다.","level":26,"category":"빈도 학습"},{"id":13252,"term":"destination","meaning":"목적지; 도착지","partOfSpeech":"n.","example":"Paris is a popular tourist destination for travelers worldwide.","exampleTranslation":"파리는 전 세계 여행자들에게 인기 있는 관광 목적지입니다.","level":26,"category":"빈도 학습"},{"id":13253,"term":"destiny","meaning":"운명; 숙명","partOfSpeech":"n.","example":"She believed that destiny brought them together at that moment.","exampleTranslation":"그녀는 운명이 그 순간 그들을 함께 이끌었다고 믿었습니다.","level":26,"category":"빈도 학습"},{"id":13254,"term":"detach","meaning":"분리하다; 떼어내다","partOfSpeech":"v.","example":"You can detach the keyboard from the tablet for easier use.","exampleTranslation":"더 편리하게 사용하기 위해 태블릿에서 키보드를 분리할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13255,"term":"detain","meaning":"억류하다; 구금하다","partOfSpeech":"v.","example":"Police can detain a suspect for up to 24 hours without charge.","exampleTranslation":"경찰은 기소 없이 용의자를 최대 24시간 동안 구금할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13256,"term":"deter","meaning":"막다; 단념시키다","partOfSpeech":"v.","example":"Security cameras can deter thieves from entering the store.","exampleTranslation":"보안 카메라는 도둑이 가게에 들어오는 것을 막을 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13257,"term":"deteriorate","meaning":"악화되다; 나빠지다","partOfSpeech":"v.","example":"His health began to deteriorate after years of poor diet.","exampleTranslation":"수년간의 불량한 식습관 후 그의 건강이 악화되기 시작했습니다.","level":26,"category":"빈도 학습"},{"id":13258,"term":"devil","meaning":"악마; 마귀","partOfSpeech":"n.","example":"The old story warns that the devil tempts people in disguise.","exampleTranslation":"오래된 이야기는 악마가 변장하여 사람들을 유혹한다고 경고합니다.","level":26,"category":"빈도 학습"},{"id":13259,"term":"devise","meaning":"고안하다; 발명하다","partOfSpeech":"v.","example":"The engineers had to devise a new solution to the problem.","exampleTranslation":"엔지니어들은 그 문제에 대한 새로운 해결책을 고안해야 했습니다.","level":26,"category":"빈도 학습"},{"id":13260,"term":"diabetes","meaning":"당뇨병","partOfSpeech":"n.","example":"A healthy diet can help prevent diabetes in many people.","exampleTranslation":"건강한 식단은 많은 사람들에게 당뇨병을 예방하는 데 도움이 됩니다.","level":26,"category":"빈도 학습"},{"id":13261,"term":"diagnose","meaning":"진단하다","partOfSpeech":"v.","example":"Doctors can diagnose many diseases with a simple blood test.","exampleTranslation":"의사들은 간단한 혈액 검사로 많은 질병을 진단할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13262,"term":"diagnosis","meaning":"진단; 진단 결과","partOfSpeech":"n.","example":"The doctor gave her a diagnosis after reviewing all test results.","exampleTranslation":"의사는 모든 검사 결과를 검토한 후 그녀에게 진단을 내렸습니다.","level":26,"category":"빈도 학습"},{"id":13263,"term":"diagram","meaning":"도표; 다이어그램","partOfSpeech":"n.","example":"The teacher drew a diagram on the board to explain the process.","exampleTranslation":"선생님은 과정을 설명하기 위해 칠판에 도표를 그렸습니다.","level":26,"category":"빈도 학습"},{"id":13264,"term":"dial","meaning":"전화를 걸다; 다이얼을 돌리다","partOfSpeech":"v.","example":"Please dial the emergency number if you see anything suspicious.","exampleTranslation":"의심스러운 것을 발견하면 긴급 번호로 전화를 거세요.","level":26,"category":"빈도 학습"},{"id":13265,"term":"diameter","meaning":"지름; 직경","partOfSpeech":"n.","example":"The pipe has a diameter of about ten centimeters.","exampleTranslation":"그 파이프의 지름은 약 10센티미터입니다.","level":26,"category":"빈도 학습"},{"id":13266,"term":"diamond","meaning":"다이아몬드; 금강석","partOfSpeech":"n.","example":"A diamond is one of the hardest natural materials on Earth.","exampleTranslation":"다이아몬드는 지구상에서 가장 단단한 천연 물질 중 하나입니다.","level":26,"category":"빈도 학습"},{"id":13267,"term":"diary","meaning":"일기; 일지","partOfSpeech":"n.","example":"She keeps a diary to record her thoughts every evening.","exampleTranslation":"그녀는 매일 저녁 생각을 기록하기 위해 일기를 씁니다.","level":26,"category":"빈도 학습"},{"id":13268,"term":"dictionary","meaning":"사전","partOfSpeech":"n.","example":"You can use a dictionary to look up the meaning of any word.","exampleTranslation":"사전을 사용하여 어떤 단어의 의미도 찾아볼 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13269,"term":"differentiate","meaning":"구별하다; 차별화하다","partOfSpeech":"v.","example":"It is hard to differentiate between the two identical twins.","exampleTranslation":"두 일란성 쌍둥이를 구별하기가 어렵습니다.","level":26,"category":"빈도 학습"},{"id":13270,"term":"digest","meaning":"소화하다; 이해하다","partOfSpeech":"v.","example":"The stomach takes time to digest a large meal properly.","exampleTranslation":"위장이 많은 양의 음식을 제대로 소화하는 데는 시간이 걸립니다.","level":26,"category":"빈도 학습"},{"id":13271,"term":"dignity","meaning":"품위; 존엄성","partOfSpeech":"n.","example":"Every person deserves to be treated with dignity and respect.","exampleTranslation":"모든 사람은 품위와 존중으로 대우받을 자격이 있습니다.","level":26,"category":"빈도 학습"},{"id":13272,"term":"dilemma","meaning":"딜레마; 진퇴양난","partOfSpeech":"n.","example":"He faced a dilemma between staying at work and going home early.","exampleTranslation":"그는 직장에 남는 것과 일찍 집에 가는 것 사이에서 딜레마에 빠졌습니다.","level":26,"category":"빈도 학습"},{"id":13273,"term":"dim","meaning":"어두운; 희미한","partOfSpeech":"adj.","example":"The room was too dim to read a book comfortably.","exampleTranslation":"방이 너무 어두워서 편안하게 책을 읽을 수가 없었습니다.","level":26,"category":"빈도 학습"},{"id":13274,"term":"diminish","meaning":"줄다; 감소하다","partOfSpeech":"v.","example":"Regular exercise can diminish the risk of heart disease.","exampleTranslation":"규칙적인 운동은 심장 질환의 위험을 줄일 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13275,"term":"dioxide","meaning":"이산화물","partOfSpeech":"n.","example":"Carbon dioxide is one of the main greenhouse gases in our atmosphere.","exampleTranslation":"이산화탄소는 우리 대기의 주요 온실가스 중 하나입니다.","level":26,"category":"빈도 학습"},{"id":13276,"term":"dip","meaning":"담그다; 살짝 넣다","partOfSpeech":"v.","example":"She likes to dip her bread into the warm soup before eating.","exampleTranslation":"그녀는 먹기 전에 빵을 따뜻한 수프에 담그는 것을 좋아합니다.","level":26,"category":"빈도 학습"},{"id":13277,"term":"disadvantage","meaning":"불리한 점; 단점","partOfSpeech":"n.","example":"One disadvantage of living downtown is the constant noise.","exampleTranslation":"도심에 사는 것의 한 가지 단점은 끊임없는 소음입니다.","level":26,"category":"빈도 학습"},{"id":13278,"term":"discard","meaning":"버리다; 폐기하다","partOfSpeech":"v.","example":"Please discard any old documents that are no longer needed.","exampleTranslation":"더 이상 필요하지 않은 오래된 문서는 버려 주세요.","level":26,"category":"빈도 학습"},{"id":13279,"term":"disclose","meaning":"공개하다; 드러내다","partOfSpeech":"v.","example":"Companies must disclose all financial risks to their investors.","exampleTranslation":"회사는 투자자들에게 모든 재정적 위험을 공개해야 합니다.","level":26,"category":"빈도 학습"},{"id":13280,"term":"disclosure","meaning":"공개; 폭로","partOfSpeech":"n.","example":"Full disclosure of the contract terms is required by law.","exampleTranslation":"계약 조건의 완전한 공개는 법으로 요구됩니다.","level":26,"category":"빈도 학습"},{"id":13281,"term":"discourage","meaning":"낙담시키다; 단념하게 하다","partOfSpeech":"v.","example":"A bad grade should not discourage you from trying again.","exampleTranslation":"나쁜 성적이 다시 시도하는 것을 단념하게 해서는 안 됩니다.","level":26,"category":"빈도 학습"},{"id":13282,"term":"disguise","meaning":"변장; 위장","partOfSpeech":"n.","example":"The spy wore a disguise so no one could recognize him.","exampleTranslation":"스파이는 아무도 그를 알아볼 수 없도록 변장을 했습니다.","level":26,"category":"빈도 학습"},{"id":13283,"term":"disperse","meaning":"흩어지다; 분산시키다","partOfSpeech":"v.","example":"The wind can disperse seeds across a very wide area.","exampleTranslation":"바람은 씨앗을 매우 넓은 지역에 걸쳐 분산시킬 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13284,"term":"displace","meaning":"대체하다; 이동시키다","partOfSpeech":"v.","example":"Automation may displace many workers in manufacturing industries.","exampleTranslation":"자동화는 제조업의 많은 근로자들을 대체할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13285,"term":"dissolve","meaning":"녹이다; 용해되다","partOfSpeech":"v.","example":"Sugar will dissolve quickly in a cup of hot water.","exampleTranslation":"설탕은 뜨거운 물 한 컵에 빠르게 녹을 것입니다.","level":26,"category":"빈도 학습"},{"id":13286,"term":"distort","meaning":"왜곡하다; 변형하다","partOfSpeech":"v.","example":"Loud speakers can distort the sound if the volume is too high.","exampleTranslation":"볼륨이 너무 높으면 스피커가 소리를 왜곡할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13287,"term":"distract","meaning":"산만하게 하다; 주의를 분산시키다","partOfSpeech":"v.","example":"Loud music can distract students who are trying to study.","exampleTranslation":"시끄러운 음악은 공부하려는 학생들의 주의를 산만하게 할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13288,"term":"distress","meaning":"고통; 괴로움","partOfSpeech":"n.","example":"The child cried out in distress after falling off the bicycle.","exampleTranslation":"아이는 자전거에서 떨어진 후 고통 속에서 울부짖었습니다.","level":26,"category":"빈도 학습"},{"id":13289,"term":"dividend","meaning":"배당금; 이익 배분","partOfSpeech":"n.","example":"The company paid a generous dividend to all its shareholders.","exampleTranslation":"회사는 모든 주주들에게 넉넉한 배당금을 지급했습니다.","level":26,"category":"빈도 학습"},{"id":13290,"term":"divine","meaning":"신성한; 신의","partOfSpeech":"adj.","example":"Many people believe that life is a divine gift to be cherished.","exampleTranslation":"많은 사람들은 삶이 소중히 여겨야 할 신성한 선물이라고 믿습니다.","level":26,"category":"빈도 학습"},{"id":13291,"term":"dock","meaning":"부두; 선착장","partOfSpeech":"n.","example":"The fishermen left the dock early in the morning to catch fish.","exampleTranslation":"어부들은 물고기를 잡기 위해 이른 아침에 부두를 떠났습니다.","level":26,"category":"빈도 학습"},{"id":13292,"term":"documentary","meaning":"다큐멘터리; 기록물","partOfSpeech":"n.","example":"We watched a fascinating documentary about ocean wildlife last night.","exampleTranslation":"우리는 어젯밤 해양 야생 동물에 관한 매혹적인 다큐멘터리를 봤습니다.","level":26,"category":"빈도 학습"},{"id":13293,"term":"dolphin","meaning":"돌고래","partOfSpeech":"n.","example":"A dolphin can communicate with other dolphins using clicks and whistles.","exampleTranslation":"돌고래는 딸깍 소리와 휘파람으로 다른 돌고래와 소통할 수 있습니다.","level":26,"category":"빈도 학습"},{"id":13294,"term":"domain","meaning":"영역; 분야","partOfSpeech":"n.","example":"Artificial intelligence is a rapidly growing domain in technology.","exampleTranslation":"인공지능은 기술 분야에서 빠르게 성장하는 영역입니다.","level":26,"category":"빈도 학습"},{"id":13295,"term":"dome","meaning":"돔; 반구형 지붕","partOfSpeech":"n.","example":"The capitol building has a large dome visible from miles away.","exampleTranslation":"국회의사당 건물에는 수 킬로미터 밖에서도 보이는 큰 돔이 있습니다.","level":26,"category":"빈도 학습"},{"id":13296,"term":"donor","meaning":"기증자; 기부자","partOfSpeech":"n.","example":"A generous donor gave one million dollars to the local hospital.","exampleTranslation":"한 관대한 기부자가 지역 병원에 100만 달러를 기부했습니다.","level":26,"category":"빈도 학습"},{"id":13297,"term":"dot","meaning":"점; 작은 점","partOfSpeech":"n.","example":"She placed a small dot at the end of each sentence in the list.","exampleTranslation":"그녀는 목록의 각 문장 끝에 작은 점을 찍었습니다.","level":26,"category":"빈도 학습"},{"id":13298,"term":"drip","meaning":"똑똑 떨어지다; 방울방울 흐르다","partOfSpeech":"v.","example":"Water began to drip from the leaking pipe in the ceiling.","exampleTranslation":"천장의 새는 파이프에서 물이 똑똑 떨어지기 시작했습니다.","level":26,"category":"빈도 학습"},{"id":13299,"term":"drown","meaning":"익사하다; 물에 빠지다","partOfSpeech":"v.","example":"Every summer, people drown because they swim without a life jacket.","exampleTranslation":"매년 여름, 사람들은 구명조끼 없이 수영을 하다가 익사합니다.","level":26,"category":"빈도 학습"},{"id":13300,"term":"dual","meaning":"이중의; 두 가지의","partOfSpeech":"adj.","example":"This laptop has a dual camera system for better photos.","exampleTranslation":"이 노트북은 더 좋은 사진을 위한 이중 카메라 시스템을 갖추고 있어요.","level":26,"category":"빈도 학습"},{"id":13301,"term":"dull","meaning":"지루한; 흐릿한; 둔한","partOfSpeech":"adj.","example":"The lecture was so dull that many students fell asleep.","exampleTranslation":"강의가 너무 지루해서 많은 학생들이 잠들었어요.","level":26,"category":"빈도 학습"},{"id":13302,"term":"duration","meaning":"지속 시간; 기간","partOfSpeech":"n.","example":"The duration of the flight from Seoul to New York is about fourteen hours.","exampleTranslation":"서울에서 뉴욕까지 비행 시간은 약 14시간이에요.","level":26,"category":"빈도 학습"},{"id":13303,"term":"dwell","meaning":"거주하다; 살다","partOfSpeech":"v.","example":"Many artists dwell in small studio apartments in the city.","exampleTranslation":"많은 예술가들이 도시의 작은 스튜디오 아파트에 거주해요.","level":26,"category":"빈도 학습"},{"id":13304,"term":"dynamic","meaning":"역동적인; 활기찬","partOfSpeech":"adj.","example":"She is a dynamic leader who always motivates her team.","exampleTranslation":"그녀는 항상 팀에 동기를 부여하는 역동적인 리더예요.","level":26,"category":"빈도 학습"},{"id":13305,"term":"eagle","meaning":"독수리","partOfSpeech":"n.","example":"An eagle soared high above the mountain peaks.","exampleTranslation":"독수리 한 마리가 산봉우리 위로 높이 날아올랐어요.","level":26,"category":"빈도 학습"},{"id":13306,"term":"earl","meaning":"백작 (영국 귀족 작위)","partOfSpeech":"n.","example":"The earl owned a large estate in the English countryside.","exampleTranslation":"그 백작은 영국 시골에 넓은 영지를 소유하고 있었어요.","level":26,"category":"빈도 학습"},{"id":13307,"term":"ecological","meaning":"생태학적인; 생태계의","partOfSpeech":"adj.","example":"The factory caused serious ecological damage to the nearby river.","exampleTranslation":"그 공장은 인근 강에 심각한 생태계 피해를 일으켰어요.","level":26,"category":"빈도 학습"},{"id":13308,"term":"ego","meaning":"자아; 자존심","partOfSpeech":"n.","example":"His big ego made it hard for him to accept criticism.","exampleTranslation":"그의 강한 자존심 때문에 비판을 받아들이기가 어려웠어요.","level":26,"category":"빈도 학습"},{"id":13309,"term":"elbow","meaning":"팔꿈치","partOfSpeech":"n.","example":"She rested her elbow on the table while reading the book.","exampleTranslation":"그녀는 책을 읽으면서 팔꿈치를 테이블에 올렸어요.","level":26,"category":"빈도 학습"},{"id":13310,"term":"electron","meaning":"전자 (원자 구성 입자)","partOfSpeech":"n.","example":"An electron carries a negative electric charge.","exampleTranslation":"전자는 음전하를 띠고 있어요.","level":26,"category":"빈도 학습"},{"id":13311,"term":"elegant","meaning":"우아한; 품위 있는","partOfSpeech":"adj.","example":"She wore an elegant dress to the award ceremony.","exampleTranslation":"그녀는 시상식에 우아한 드레스를 입고 갔어요.","level":26,"category":"빈도 학습"},{"id":13312,"term":"elementary","meaning":"초등의; 기초적인","partOfSpeech":"adj.","example":"The teacher explained the elementary rules of grammar to her students.","exampleTranslation":"선생님은 학생들에게 기초적인 문법 규칙을 설명했어요.","level":26,"category":"빈도 학습"},{"id":13313,"term":"eligible","meaning":"자격이 있는; 적격인","partOfSpeech":"adj.","example":"Only citizens over eighteen are eligible to vote in the election.","exampleTranslation":"18세 이상의 시민만 선거에서 투표할 자격이 있어요.","level":26,"category":"빈도 학습"},{"id":13314,"term":"embody","meaning":"구현하다; 체현하다","partOfSpeech":"v.","example":"This sculpture seems to embody the spirit of freedom.","exampleTranslation":"이 조각상은 자유의 정신을 구현하는 것 같아요.","level":26,"category":"빈도 학습"},{"id":13315,"term":"emperor","meaning":"황제","partOfSpeech":"n.","example":"The emperor ruled over a vast empire for forty years.","exampleTranslation":"그 황제는 40년 동안 광대한 제국을 통치했어요.","level":26,"category":"빈도 학습"},{"id":13316,"term":"empirical","meaning":"경험적인; 실증적인","partOfSpeech":"adj.","example":"Scientists need empirical evidence before accepting a new theory.","exampleTranslation":"과학자들은 새로운 이론을 받아들이기 전에 실증적인 증거가 필요해요.","level":26,"category":"빈도 학습"},{"id":13317,"term":"enact","meaning":"법률로 제정하다; 시행하다","partOfSpeech":"v.","example":"Congress plans to enact new environmental protection laws this year.","exampleTranslation":"의회는 올해 새로운 환경 보호법을 제정할 계획이에요.","level":26,"category":"빈도 학습"},{"id":13318,"term":"enclose","meaning":"동봉하다; 에워싸다","partOfSpeech":"v.","example":"Please enclose a copy of your ID with the application form.","exampleTranslation":"신청서와 함께 신분증 사본을 동봉해 주세요.","level":26,"category":"빈도 학습"},{"id":13319,"term":"endeavor","meaning":"노력하다; 분투하다; 노력","partOfSpeech":"v.","example":"We must endeavor to find a solution before the deadline.","exampleTranslation":"우리는 마감 전에 해결책을 찾기 위해 노력해야 해요.","level":26,"category":"빈도 학습"},{"id":13320,"term":"endow","meaning":"부여하다; 기부하다","partOfSpeech":"v.","example":"The billionaire decided to endow the university with a new library.","exampleTranslation":"그 억만장자는 대학교에 새 도서관을 기부하기로 결정했어요.","level":26,"category":"빈도 학습"},{"id":13321,"term":"enlarge","meaning":"확대하다; 넓히다","partOfSpeech":"v.","example":"The city plans to enlarge the park to accommodate more visitors.","exampleTranslation":"시는 더 많은 방문객을 수용하기 위해 공원을 넓힐 계획이에요.","level":26,"category":"빈도 학습"},{"id":13322,"term":"enlighten","meaning":"깨우치다; 계몽하다","partOfSpeech":"v.","example":"The documentary helped enlighten viewers about climate change.","exampleTranslation":"그 다큐멘터리는 시청자들이 기후 변화에 대해 깨우치는 데 도움이 됐어요.","level":26,"category":"빈도 학습"},{"id":13323,"term":"enrich","meaning":"풍요롭게 하다; 강화하다","partOfSpeech":"v.","example":"Traveling abroad can enrich your understanding of different cultures.","exampleTranslation":"해외 여행은 다양한 문화에 대한 이해를 풍요롭게 해줄 수 있어요.","level":26,"category":"빈도 학습"},{"id":13324,"term":"enroll","meaning":"등록하다; 입학하다","partOfSpeech":"v.","example":"You must enroll in the course before the registration deadline.","exampleTranslation":"등록 마감일 전에 수업에 등록해야 해요.","level":26,"category":"빈도 학습"},{"id":13325,"term":"entity","meaning":"실체; 독립 개체","partOfSpeech":"n.","example":"A corporation is a legal entity that can own property.","exampleTranslation":"주식회사는 재산을 소유할 수 있는 법인 실체예요.","level":26,"category":"빈도 학습"},{"id":13326,"term":"entrepreneur","meaning":"기업가; 창업자","partOfSpeech":"n.","example":"A successful entrepreneur must be willing to take calculated risks.","exampleTranslation":"성공적인 기업가는 계산된 위험을 기꺼이 감수해야 해요.","level":26,"category":"빈도 학습"},{"id":13327,"term":"envy","meaning":"부러워하다; 질투하다; 부러움","partOfSpeech":"v.","example":"Many people envy those who can work from home every day.","exampleTranslation":"많은 사람들이 매일 재택근무를 할 수 있는 사람들을 부러워해요.","level":26,"category":"빈도 학습"},{"id":13328,"term":"equity","meaning":"공정성; 자기자본; 형평성","partOfSpeech":"n.","example":"The company promotes equity in the workplace for all employees.","exampleTranslation":"그 회사는 모든 직원을 위한 직장 내 형평성을 증진해요.","level":26,"category":"빈도 학습"},{"id":13329,"term":"erect","meaning":"세우다; 건립하다; 직립의","partOfSpeech":"v.","example":"Workers plan to erect a new statue in the center of the plaza.","exampleTranslation":"작업자들은 광장 중앙에 새 동상을 세울 계획이에요.","level":26,"category":"빈도 학습"},{"id":13330,"term":"erupt","meaning":"분출하다; 폭발하다","partOfSpeech":"v.","example":"Volcanoes can erupt without much warning and cause widespread damage.","exampleTranslation":"화산은 별다른 경고 없이 분출하여 광범위한 피해를 일으킬 수 있어요.","level":26,"category":"빈도 학습"},{"id":13331,"term":"escort","meaning":"호위하다; 동행하다; 호위","partOfSpeech":"v.","example":"Security officers escort the president wherever he travels.","exampleTranslation":"경호원들은 대통령이 이동하는 곳마다 호위해요.","level":26,"category":"빈도 학습"},{"id":13332,"term":"essence","meaning":"본질; 핵심; 에센스","partOfSpeech":"n.","example":"Honesty is the essence of a truly trustworthy relationship.","exampleTranslation":"정직함은 진정으로 믿을 수 있는 관계의 본질이에요.","level":26,"category":"빈도 학습"},{"id":13333,"term":"et","meaning":"그리고 (라틴어 'et al.' 등에서 쓰이는 접속사)","partOfSpeech":"conj.","example":"The paper was written by Smith et al. and published last year.","exampleTranslation":"그 논문은 Smith 외 공저자들이 저술했으며 작년에 출판됐어요.","level":26,"category":"빈도 학습"},{"id":13334,"term":"ethical","meaning":"윤리적인; 도덕적인","partOfSpeech":"adj.","example":"Doctors must make ethical decisions even in difficult situations.","exampleTranslation":"의사들은 어려운 상황에서도 윤리적인 결정을 내려야 해요.","level":26,"category":"빈도 학습"},{"id":13335,"term":"ethics","meaning":"윤리학; 도덕 원칙","partOfSpeech":"n.","example":"Business ethics requires companies to be honest with their customers.","exampleTranslation":"기업 윤리는 회사가 고객에게 정직할 것을 요구해요.","level":26,"category":"빈도 학습"},{"id":13336,"term":"evacuate","meaning":"대피하다; 소개하다","partOfSpeech":"v.","example":"Authorities ordered residents to evacuate the area before the hurricane.","exampleTranslation":"당국은 허리케인이 오기 전에 주민들에게 지역을 대피하라고 명령했어요.","level":26,"category":"빈도 학습"},{"id":13337,"term":"eve","meaning":"전날 밤; 전날","partOfSpeech":"n.","example":"Everyone gathered to celebrate on the eve of the new year.","exampleTranslation":"모두가 새해 전날 밤에 축하하기 위해 모였어요.","level":26,"category":"빈도 학습"},{"id":13338,"term":"evoke","meaning":"불러일으키다; 환기시키다","partOfSpeech":"v.","example":"That old song can evoke strong memories of my childhood.","exampleTranslation":"그 오래된 노래는 내 어린 시절의 강렬한 기억을 불러일으킬 수 있어요.","level":26,"category":"빈도 학습"},{"id":13339,"term":"exaggerate","meaning":"과장하다","partOfSpeech":"v.","example":"He tends to exaggerate how long it takes him to finish his work.","exampleTranslation":"그는 일을 끝내는 데 걸리는 시간을 과장하는 경향이 있어요.","level":26,"category":"빈도 학습"},{"id":13340,"term":"excavate","meaning":"발굴하다; 굴착하다","partOfSpeech":"v.","example":"Archaeologists plan to excavate the ancient ruins next summer.","exampleTranslation":"고고학자들은 내년 여름에 고대 유적을 발굴할 계획이에요.","level":26,"category":"빈도 학습"},{"id":13341,"term":"exclaim","meaning":"외치다; 소리치다","partOfSpeech":"v.","example":"The children exclaim with delight when they see the fireworks.","exampleTranslation":"아이들은 불꽃놀이를 보면 기쁨에 겨워 외쳐요.","level":26,"category":"빈도 학습"},{"id":13342,"term":"exclusion","meaning":"배제; 제외","partOfSpeech":"n.","example":"The exclusion of certain groups from the vote caused public outrage.","exampleTranslation":"특정 집단을 투표에서 배제한 것이 공분을 일으켰어요.","level":26,"category":"빈도 학습"},{"id":13343,"term":"exempt","meaning":"면제하다; 면제된","partOfSpeech":"v.","example":"The government decided to exempt low-income families from the tax.","exampleTranslation":"정부는 저소득 가정을 세금에서 면제하기로 결정했어요.","level":26,"category":"빈도 학습"},{"id":13344,"term":"exert","meaning":"발휘하다; 행사하다","partOfSpeech":"v.","example":"You need to exert more effort if you want to improve your grades.","exampleTranslation":"성적을 올리고 싶다면 더 많은 노력을 발휘해야 해요.","level":26,"category":"빈도 학습"},{"id":13345,"term":"exile","meaning":"망명; 추방; 추방하다","partOfSpeech":"n.","example":"The political leader lived in exile for more than ten years.","exampleTranslation":"그 정치 지도자는 10년 넘게 망명 생활을 했어요.","level":26,"category":"빈도 학습"},{"id":13346,"term":"exotic","meaning":"이국적인; 외래의","partOfSpeech":"adj.","example":"The market sells exotic fruits that are hard to find locally.","exampleTranslation":"그 시장은 현지에서 찾기 힘든 이국적인 과일을 판매해요.","level":26,"category":"빈도 학습"},{"id":13347,"term":"expedition","meaning":"탐험; 원정","partOfSpeech":"n.","example":"The team prepared for a six-month expedition to the Arctic region.","exampleTranslation":"팀은 북극 지역으로 떠날 6개월간의 탐험을 준비했어요.","level":26,"category":"빈도 학습"},{"id":13348,"term":"expertise","meaning":"전문 지식; 전문성","partOfSpeech":"n.","example":"The company hired consultants with expertise in digital marketing.","exampleTranslation":"그 회사는 디지털 마케팅 전문 지식을 가진 컨설턴트를 고용했어요.","level":26,"category":"빈도 학습"},{"id":13349,"term":"explode","meaning":"폭발하다; 급증하다","partOfSpeech":"v.","example":"The old gas pipe could explode if no one repairs it soon.","exampleTranslation":"아무도 빨리 수리하지 않으면 오래된 가스관이 폭발할 수 있어요.","level":26,"category":"빈도 학습"},{"id":13350,"term":"eyebrow","meaning":"눈썹","partOfSpeech":"n.","example":"She raised her eyebrow in surprise at the news.","exampleTranslation":"그녀는 그 소식에 놀라 눈썹을 치켜올렸다.","level":27,"category":"빈도 학습"},{"id":13351,"term":"faction","meaning":"파벌; 분파","partOfSpeech":"n.","example":"A rebel faction within the party refused to accept the decision.","exampleTranslation":"당내 반란 파벌은 그 결정을 받아들이기를 거부했다.","level":27,"category":"빈도 학습"},{"id":13352,"term":"fake","meaning":"가짜의; 위조의","partOfSpeech":"adj.","example":"The museum discovered that the painting was fake.","exampleTranslation":"박물관은 그 그림이 가짜임을 발견했다.","level":27,"category":"빈도 학습"},{"id":13353,"term":"fame","meaning":"명성; 명예","partOfSpeech":"n.","example":"His fame spread quickly after the movie was released.","exampleTranslation":"영화가 개봉된 후 그의 명성은 빠르게 퍼졌다.","level":27,"category":"빈도 학습"},{"id":13354,"term":"fatal","meaning":"치명적인; 죽음을 초래하는","partOfSpeech":"adj.","example":"The doctor warned that the disease could be fatal if untreated.","exampleTranslation":"의사는 치료하지 않으면 그 병이 치명적일 수 있다고 경고했다.","level":27,"category":"빈도 학습"},{"id":13355,"term":"fax","meaning":"팩스; 팩시밀리","partOfSpeech":"n.","example":"Please send the signed contract by fax before noon.","exampleTranslation":"정오 전에 서명된 계약서를 팩스로 보내 주세요.","level":27,"category":"빈도 학습"},{"id":13356,"term":"federate","meaning":"연합하다; 연방을 이루다","partOfSpeech":"v.","example":"The small states agreed to federate under a common constitution.","exampleTranslation":"소규모 주들은 공동 헌법 아래 연합하기로 합의했다.","level":27,"category":"빈도 학습"},{"id":13357,"term":"feminine","meaning":"여성적인; 여성다운","partOfSpeech":"adj.","example":"The dress had a classic and feminine design that she loved.","exampleTranslation":"그 드레스는 그녀가 좋아하는 고전적이고 여성스러운 디자인이었다.","level":27,"category":"빈도 학습"},{"id":13358,"term":"ferry","meaning":"여객선; 나룻배","partOfSpeech":"n.","example":"We took the ferry to cross the river to the other island.","exampleTranslation":"우리는 강을 건너 다른 섬으로 가기 위해 여객선을 탔다.","level":27,"category":"빈도 학습"},{"id":13359,"term":"fined","meaning":"벌금이 부과된; 과태료를 물게 된","partOfSpeech":"adj.","example":"The company was fined for violating environmental regulations.","exampleTranslation":"그 회사는 환경 규정을 위반하여 벌금이 부과되었다.","level":27,"category":"빈도 학습"},{"id":13360,"term":"fiscal","meaning":"재정의; 회계의","partOfSpeech":"adj.","example":"The government announced new fiscal policies to reduce the deficit.","exampleTranslation":"정부는 적자를 줄이기 위한 새로운 재정 정책을 발표했다.","level":27,"category":"빈도 학습"},{"id":13361,"term":"fist","meaning":"주먹","partOfSpeech":"n.","example":"He raised his fist in the air to celebrate the victory.","exampleTranslation":"그는 승리를 축하하며 공중으로 주먹을 들어 올렸다.","level":27,"category":"빈도 학습"},{"id":13362,"term":"flank","meaning":"측면; 옆구리","partOfSpeech":"n.","example":"The soldiers attacked the enemy from the left flank.","exampleTranslation":"병사들은 적의 왼쪽 측면에서 공격했다.","level":27,"category":"빈도 학습"},{"id":13363,"term":"flap","meaning":"펄럭이다; 파닥거리다","partOfSpeech":"v.","example":"The bird began to flap its wings and rise into the sky.","exampleTranslation":"그 새는 날개를 퍼덕이며 하늘로 날아오르기 시작했다.","level":27,"category":"빈도 학습"},{"id":13364,"term":"flaw","meaning":"결함; 흠","partOfSpeech":"n.","example":"The inspector found a flaw in the design of the bridge.","exampleTranslation":"검사관은 다리 설계에서 결함을 발견했다.","level":27,"category":"빈도 학습"},{"id":13365,"term":"fleet","meaning":"함대; 선단","partOfSpeech":"n.","example":"The navy sent its entire fleet to patrol the coastline.","exampleTranslation":"해군은 해안선을 순찰하기 위해 함대 전체를 파견했다.","level":27,"category":"빈도 학습"},{"id":13366,"term":"flick","meaning":"튕기다; 가볍게 치다","partOfSpeech":"v.","example":"She used her finger to flick the switch on the wall.","exampleTranslation":"그녀는 손가락으로 벽에 있는 스위치를 가볍게 튕겼다.","level":27,"category":"빈도 학습"},{"id":13367,"term":"flicker","meaning":"깜빡이다; 흔들리다","partOfSpeech":"v.","example":"The candle began to flicker in the gentle breeze.","exampleTranslation":"촛불이 살랑이는 바람에 깜빡이기 시작했다.","level":27,"category":"빈도 학습"},{"id":13368,"term":"fling","meaning":"던지다; 내팽개치다","partOfSpeech":"v.","example":"In anger, he decided to fling the papers across the room.","exampleTranslation":"화가 난 그는 서류들을 방 건너편으로 던져버리기로 했다.","level":27,"category":"빈도 학습"},{"id":13369,"term":"flock","meaning":"무리; 떼","partOfSpeech":"n.","example":"A flock of birds flew overhead in a perfect V shape.","exampleTranslation":"새 떼가 완벽한 V자 형태로 머리 위를 날아갔다.","level":27,"category":"빈도 학습"},{"id":13370,"term":"flour","meaning":"밀가루","partOfSpeech":"n.","example":"You need two cups of flour to make this bread recipe.","exampleTranslation":"이 빵 레시피를 만들려면 밀가루 두 컵이 필요하다.","level":27,"category":"빈도 학습"},{"id":13371,"term":"flourish","meaning":"번성하다; 번창하다","partOfSpeech":"v.","example":"Small businesses tend to flourish in a stable economy.","exampleTranslation":"소규모 사업체들은 안정적인 경제에서 번성하는 경향이 있다.","level":27,"category":"빈도 학습"},{"id":13372,"term":"fluid","meaning":"유체; 액체","partOfSpeech":"n.","example":"The doctor told him to drink plenty of fluid every day.","exampleTranslation":"의사는 그에게 매일 수분을 충분히 섭취하라고 말했다.","level":27,"category":"빈도 학습"},{"id":13373,"term":"flush","meaning":"붉어지다; (물을) 내려보내다","partOfSpeech":"v.","example":"Remember to flush the toilet after you use it.","exampleTranslation":"사용 후에는 꼭 변기 물을 내려주세요.","level":27,"category":"빈도 학습"},{"id":13374,"term":"fog","meaning":"안개","partOfSpeech":"n.","example":"Thick fog made it difficult to see the road ahead.","exampleTranslation":"짙은 안개 때문에 앞쪽 도로를 보기가 어려웠다.","level":27,"category":"빈도 학습"},{"id":13375,"term":"fond","meaning":"좋아하는; 애정 어린","partOfSpeech":"adj.","example":"She has always been fond of classical music since childhood.","exampleTranslation":"그녀는 어릴 때부터 항상 클래식 음악을 좋아했다.","level":27,"category":"빈도 학습"},{"id":13376,"term":"forbid","meaning":"금지하다; 허락하지 않다","partOfSpeech":"v.","example":"School rules forbid students from using phones in class.","exampleTranslation":"학교 규칙은 수업 중 휴대폰 사용을 금지한다.","level":27,"category":"빈도 학습"},{"id":13377,"term":"fore","meaning":"앞쪽; 앞부분","partOfSpeech":"n.","example":"The captain stood at the fore of the ship to navigate.","exampleTranslation":"선장은 항해를 위해 배의 앞부분에 서 있었다.","level":27,"category":"빈도 학습"},{"id":13378,"term":"forehead","meaning":"이마","partOfSpeech":"n.","example":"She pressed a cool cloth against her forehead to reduce the fever.","exampleTranslation":"그녀는 열을 낮추기 위해 이마에 차가운 수건을 댔다.","level":27,"category":"빈도 학습"},{"id":13379,"term":"foresee","meaning":"예견하다; 미리 내다보다","partOfSpeech":"v.","example":"No one could foresee the dramatic changes that technology would bring.","exampleTranslation":"기술이 가져올 극적인 변화를 아무도 예견할 수 없었다.","level":27,"category":"빈도 학습"},{"id":13380,"term":"forge","meaning":"위조하다; (쇠를) 단조하다","partOfSpeech":"v.","example":"The criminal tried to forge the official documents to cross the border.","exampleTranslation":"그 범죄자는 국경을 넘기 위해 공식 서류를 위조하려 했다.","level":27,"category":"빈도 학습"},{"id":13381,"term":"fork","meaning":"포크; 갈림길","partOfSpeech":"n.","example":"Please put a fork and a knife on each side of the plate.","exampleTranslation":"접시 양쪽에 포크와 나이프를 하나씩 놓아 주세요.","level":27,"category":"빈도 학습"},{"id":13382,"term":"fort","meaning":"요새; 성채","partOfSpeech":"n.","example":"The soldiers built a fort to defend the border of the territory.","exampleTranslation":"병사들은 영토의 국경을 방어하기 위해 요새를 세웠다.","level":27,"category":"빈도 학습"},{"id":13383,"term":"forum","meaning":"포럼; 토론의 장","partOfSpeech":"n.","example":"The city held a public forum to discuss the new transportation plan.","exampleTranslation":"시는 새로운 교통 계획을 논의하기 위한 공개 포럼을 열었다.","level":27,"category":"빈도 학습"},{"id":13384,"term":"fossil","meaning":"화석","partOfSpeech":"n.","example":"Scientists found a rare dinosaur fossil buried deep in the rock.","exampleTranslation":"과학자들이 암석 깊숙이 묻혀 있는 희귀한 공룡 화석을 발견했다.","level":27,"category":"빈도 학습"},{"id":13385,"term":"foul","meaning":"더러운; 불쾌한","partOfSpeech":"adj.","example":"A foul smell came from the garbage that had been left outside.","exampleTranslation":"밖에 버려진 쓰레기에서 불쾌한 냄새가 풍겨왔다.","level":27,"category":"빈도 학습"},{"id":13386,"term":"fraction","meaning":"분수; 일부분","partOfSpeech":"n.","example":"Only a small fraction of the applicants passed the entrance exam.","exampleTranslation":"지원자 중 아주 일부만이 입학 시험에 합격했다.","level":27,"category":"빈도 학습"},{"id":13387,"term":"fracture","meaning":"골절; 균열","partOfSpeech":"n.","example":"The X-ray showed a fracture in the bone near his wrist.","exampleTranslation":"엑스레이 결과 손목 근처 뼈에 골절이 있는 것으로 나타났다.","level":27,"category":"빈도 학습"},{"id":13388,"term":"fragile","meaning":"깨지기 쉬운; 취약한","partOfSpeech":"adj.","example":"The fragile vase must be wrapped carefully before shipping.","exampleTranslation":"그 깨지기 쉬운 꽃병은 배송 전에 조심스럽게 포장해야 한다.","level":27,"category":"빈도 학습"},{"id":13389,"term":"franchise","meaning":"프랜차이즈; 독점 판매권","partOfSpeech":"n.","example":"He bought a franchise and opened his own fast food restaurant.","exampleTranslation":"그는 프랜차이즈 권리를 구입하여 자신의 패스트푸드 레스토랑을 열었다.","level":27,"category":"빈도 학습"},{"id":13390,"term":"fraud","meaning":"사기; 속임수","partOfSpeech":"n.","example":"The bank detected fraud in several customer accounts last month.","exampleTranslation":"은행은 지난달 여러 고객 계좌에서 사기 행위를 탐지했다.","level":27,"category":"빈도 학습"},{"id":13391,"term":"fringe","meaning":"가장자리; 주변부","partOfSpeech":"n.","example":"The artist lived on the fringe of the city in a small studio.","exampleTranslation":"그 예술가는 도시 변두리에 있는 작은 작업실에서 살았다.","level":27,"category":"빈도 학습"},{"id":13392,"term":"frontier","meaning":"개척지; 국경지대","partOfSpeech":"n.","example":"Space exploration is considered the final frontier of human achievement.","exampleTranslation":"우주 탐험은 인류 성취의 마지막 개척지로 여겨진다.","level":27,"category":"빈도 학습"},{"id":13393,"term":"frown","meaning":"찡그리다; 눈살을 찌푸리다","partOfSpeech":"v.","example":"He tends to frown whenever he reads a confusing document.","exampleTranslation":"그는 혼란스러운 서류를 읽을 때마다 눈살을 찌푸리는 경향이 있다.","level":27,"category":"빈도 학습"},{"id":13394,"term":"furious","meaning":"몹시 화난; 격노한","partOfSpeech":"adj.","example":"The manager was furious when he found out about the missing report.","exampleTranslation":"관리자는 보고서가 없어진 사실을 알고 몹시 화가 났다.","level":27,"category":"빈도 학습"},{"id":13395,"term":"fuse","meaning":"퓨즈; 도화선","partOfSpeech":"n.","example":"The electrician replaced the fuse after the power went out.","exampleTranslation":"전기 기사는 정전이 된 후 퓨즈를 교체했다.","level":27,"category":"빈도 학습"},{"id":13396,"term":"galaxy","meaning":"은하; 은하계","partOfSpeech":"n.","example":"Our solar system is located in the Milky Way galaxy.","exampleTranslation":"우리 태양계는 은하수 은하계에 위치해 있다.","level":27,"category":"빈도 학습"},{"id":13397,"term":"gallon","meaning":"갤런(부피 단위)","partOfSpeech":"n.","example":"The tank can hold up to ten gallon of water at a time.","exampleTranslation":"그 탱크는 한 번에 최대 10갤런의 물을 담을 수 있다.","level":27,"category":"빈도 학습"},{"id":13398,"term":"gamble","meaning":"도박하다; 위험을 감수하다","partOfSpeech":"v.","example":"It is risky to gamble with your savings on uncertain investments.","exampleTranslation":"불확실한 투자에 저축을 걸고 도박하는 것은 위험하다.","level":27,"category":"빈도 학습"},{"id":13399,"term":"garlic","meaning":"마늘","partOfSpeech":"n.","example":"This recipe calls for two cloves of garlic to add flavor.","exampleTranslation":"이 레시피는 풍미를 더하기 위해 마늘 두 쪽이 필요하다.","level":27,"category":"빈도 학습"},{"id":13400,"term":"gasp","meaning":"숨을 헐떡이다; 깜짝 놀라 숨을 들이쉬다","partOfSpeech":"v.","example":"The audience gasp in shock when the magician vanished.","exampleTranslation":"마술사가 사라지자 관중은 놀라 숨을 들이켰어요.","level":27,"category":"빈도 학습"},{"id":13401,"term":"gauge","meaning":"측정하다; 가늠하다","partOfSpeech":"v.","example":"It is hard to gauge how long the project will take.","exampleTranslation":"프로젝트가 얼마나 걸릴지 가늠하기 어렵습니다.","level":27,"category":"빈도 학습"},{"id":13402,"term":"genius","meaning":"천재; 뛰어난 재능","partOfSpeech":"n.","example":"Everyone agreed that the young musician was a true genius.","exampleTranslation":"모두가 그 젊은 음악가가 진정한 천재라는 데 동의했어요.","level":27,"category":"빈도 학습"},{"id":13403,"term":"genre","meaning":"장르; 유형","partOfSpeech":"n.","example":"Mystery is her favorite genre of fiction to read.","exampleTranslation":"미스터리는 그녀가 가장 좋아하는 소설 장르예요.","level":27,"category":"빈도 학습"},{"id":13404,"term":"geology","meaning":"지질학","partOfSpeech":"n.","example":"She studied geology to understand how mountains are formed.","exampleTranslation":"그녀는 산이 어떻게 형성되는지 이해하기 위해 지질학을 공부했어요.","level":27,"category":"빈도 학습"},{"id":13405,"term":"geometry","meaning":"기하학","partOfSpeech":"n.","example":"Geometry helps students understand shapes and angles in space.","exampleTranslation":"기하학은 학생들이 공간 속의 도형과 각도를 이해하도록 도와줍니다.","level":27,"category":"빈도 학습"},{"id":13406,"term":"glamour","meaning":"매혹; 화려함","partOfSpeech":"n.","example":"The old Hollywood films were full of glamour and style.","exampleTranslation":"옛 할리우드 영화는 매혹과 스타일로 가득했어요.","level":27,"category":"빈도 학습"},{"id":13407,"term":"glare","meaning":"노려보다; 눈부신 빛","partOfSpeech":"v.","example":"She would glare at anyone who talked during the performance.","exampleTranslation":"그녀는 공연 중에 말하는 사람을 누구든 노려보곤 했어요.","level":27,"category":"빈도 학습"},{"id":13408,"term":"gleam","meaning":"반짝이다; 희미하게 빛나다","partOfSpeech":"v.","example":"Moonlight can gleam on the surface of a calm lake.","exampleTranslation":"달빛이 잔잔한 호수 표면에서 반짝일 수 있어요.","level":27,"category":"빈도 학습"},{"id":13409,"term":"glide","meaning":"미끄러지듯 움직이다; 활공하다","partOfSpeech":"v.","example":"The eagle can glide for miles without flapping its wings.","exampleTranslation":"독수리는 날개를 퍼덕이지 않고도 수 킬로미터를 활공할 수 있어요.","level":27,"category":"빈도 학습"},{"id":13410,"term":"glimpse","meaning":"잠깐 봄; 흘낏 보다","partOfSpeech":"n.","example":"I caught a glimpse of the deer before it ran into the forest.","exampleTranslation":"사슴이 숲으로 달려가기 전에 잠깐 보았어요.","level":27,"category":"빈도 학습"},{"id":13411,"term":"gloom","meaning":"어둠; 우울함","partOfSpeech":"n.","example":"A sense of gloom settled over the town after the accident.","exampleTranslation":"사고 이후 마을에 우울함이 내려앉았어요.","level":27,"category":"빈도 학습"},{"id":13412,"term":"glove","meaning":"장갑","partOfSpeech":"n.","example":"Always wear a glove when handling hot pans in the kitchen.","exampleTranslation":"주방에서 뜨거운 냄비를 다룰 때는 항상 장갑을 착용하세요.","level":27,"category":"빈도 학습"},{"id":13413,"term":"glue","meaning":"접착제; 붙이다","partOfSpeech":"n.","example":"She used glue to fix the broken handle on her favorite mug.","exampleTranslation":"그녀는 좋아하는 머그잔의 깨진 손잡이를 접착제로 고쳤어요.","level":27,"category":"빈도 학습"},{"id":13414,"term":"goat","meaning":"염소","partOfSpeech":"n.","example":"A goat will eat almost any plant it finds in the field.","exampleTranslation":"염소는 들판에서 발견하는 거의 모든 식물을 먹어요.","level":27,"category":"빈도 학습"},{"id":13415,"term":"gospel","meaning":"복음; 진리로 받아들여지는 것","partOfSpeech":"n.","example":"The minister read from the gospel every Sunday morning.","exampleTranslation":"목사는 매주 일요일 아침마다 복음을 읽었어요.","level":27,"category":"빈도 학습"},{"id":13416,"term":"gossip","meaning":"소문; 험담하다","partOfSpeech":"n.","example":"Office gossip can damage trust among team members quickly.","exampleTranslation":"직장 내 소문은 팀원 간의 신뢰를 빠르게 손상시킬 수 있어요.","level":27,"category":"빈도 학습"},{"id":13417,"term":"graph","meaning":"그래프; 도표","partOfSpeech":"n.","example":"The graph clearly shows how sales increased over the year.","exampleTranslation":"그래프는 연간 판매량이 어떻게 증가했는지 명확히 보여줘요.","level":27,"category":"빈도 학습"},{"id":13418,"term":"gravel","meaning":"자갈","partOfSpeech":"n.","example":"They laid gravel on the path to prevent mud after rain.","exampleTranslation":"비 후에 진흙탕이 되지 않도록 길에 자갈을 깔았어요.","level":27,"category":"빈도 학습"},{"id":13419,"term":"graze","meaning":"풀을 뜯어먹다; 스치다","partOfSpeech":"v.","example":"Sheep graze peacefully on the hillside every morning.","exampleTranslation":"양들이 매일 아침 언덕 위에서 평화롭게 풀을 뜯어요.","level":27,"category":"빈도 학습"},{"id":13420,"term":"grease","meaning":"기름; 윤활유","partOfSpeech":"n.","example":"The mechanic wiped the grease off his hands after fixing the engine.","exampleTranslation":"정비사는 엔진을 고친 후 손의 기름을 닦았어요.","level":27,"category":"빈도 학습"},{"id":13421,"term":"greed","meaning":"탐욕; 욕심","partOfSpeech":"n.","example":"His greed led him to make several dishonest business decisions.","exampleTranslation":"그의 탐욕이 여러 부정직한 사업 결정을 내리게 했어요.","level":27,"category":"빈도 학습"},{"id":13422,"term":"greenhouse","meaning":"온실","partOfSpeech":"n.","example":"She grows tomatoes in a greenhouse throughout the winter months.","exampleTranslation":"그녀는 겨울 내내 온실에서 토마토를 재배해요.","level":27,"category":"빈도 학습"},{"id":13423,"term":"grid","meaning":"격자; 전력망","partOfSpeech":"n.","example":"The city map was laid out on a simple grid pattern.","exampleTranslation":"도시 지도는 단순한 격자 패턴으로 구성되어 있었어요.","level":27,"category":"빈도 학습"},{"id":13424,"term":"grief","meaning":"슬픔; 비탄","partOfSpeech":"n.","example":"The family needed time to process their grief after the loss.","exampleTranslation":"가족은 상실 후 슬픔을 추스를 시간이 필요했어요.","level":27,"category":"빈도 학습"},{"id":13425,"term":"grim","meaning":"암울한; 엄격한","partOfSpeech":"adj.","example":"The report painted a grim picture of the economy next year.","exampleTranslation":"그 보고서는 내년 경제에 대해 암울한 그림을 그렸어요.","level":27,"category":"빈도 학습"},{"id":13426,"term":"grind","meaning":"갈다; 분쇄하다","partOfSpeech":"v.","example":"You need to grind the coffee beans fresh each morning.","exampleTranslation":"매일 아침 커피 원두를 신선하게 갈아야 해요.","level":27,"category":"빈도 학습"},{"id":13427,"term":"guardian","meaning":"보호자; 수호자","partOfSpeech":"n.","example":"A legal guardian must sign the form on behalf of the child.","exampleTranslation":"법적 보호자가 아이를 대신하여 서류에 서명해야 해요.","level":27,"category":"빈도 학습"},{"id":13428,"term":"guerilla","meaning":"게릴라; 비정규 전투원","partOfSpeech":"n.","example":"The guerilla used surprise tactics to attack the supply lines.","exampleTranslation":"게릴라는 기습 전술을 써서 보급선을 공격했어요.","level":27,"category":"빈도 학습"},{"id":13429,"term":"gulf","meaning":"만(灣); 큰 격차","partOfSpeech":"n.","example":"There is a wide gulf between the two sides in the negotiation.","exampleTranslation":"협상에서 양측 사이에는 큰 격차가 있어요.","level":27,"category":"빈도 학습"},{"id":13430,"term":"gut","meaning":"장; 직감","partOfSpeech":"n.","example":"He trusted his gut and decided not to sign the contract.","exampleTranslation":"그는 직감을 믿고 계약에 서명하지 않기로 했어요.","level":27,"category":"빈도 학습"},{"id":13431,"term":"habitat","meaning":"서식지; 생활 환경","partOfSpeech":"n.","example":"Deforestation is destroying the natural habitat of many animals.","exampleTranslation":"삼림 벌채가 많은 동물의 자연 서식지를 파괴하고 있어요.","level":27,"category":"빈도 학습"},{"id":13432,"term":"hammer","meaning":"망치; 망치로 치다","partOfSpeech":"n.","example":"He used a hammer to nail the picture frame to the wall.","exampleTranslation":"그는 망치를 사용해 액자를 벽에 못으로 박았어요.","level":27,"category":"빈도 학습"},{"id":13433,"term":"handicap","meaning":"장애; 불리한 조건","partOfSpeech":"n.","example":"A language barrier can be a serious handicap in a new country.","exampleTranslation":"언어 장벽은 새로운 나라에서 심각한 장애가 될 수 있어요.","level":27,"category":"빈도 학습"},{"id":13434,"term":"handsome","meaning":"잘생긴; 상당한","partOfSpeech":"adj.","example":"Everyone noticed the handsome man who just entered the room.","exampleTranslation":"방금 방에 들어온 잘생긴 남자를 모두가 알아봤어요.","level":27,"category":"빈도 학습"},{"id":13435,"term":"harass","meaning":"괴롭히다; 희롱하다","partOfSpeech":"v.","example":"It is illegal to harass coworkers in the workplace.","exampleTranslation":"직장에서 동료를 괴롭히는 것은 불법이에요.","level":27,"category":"빈도 학습"},{"id":13436,"term":"hardware","meaning":"하드웨어; 철물","partOfSpeech":"n.","example":"The computer's hardware needs an upgrade to run newer software.","exampleTranslation":"최신 소프트웨어를 실행하려면 컴퓨터 하드웨어를 업그레이드해야 해요.","level":27,"category":"빈도 학습"},{"id":13437,"term":"harmony","meaning":"조화; 화음","partOfSpeech":"n.","example":"The choir sang in perfect harmony during the final performance.","exampleTranslation":"합창단은 마지막 공연에서 완벽한 화음을 이루며 노래했어요.","level":27,"category":"빈도 학습"},{"id":13438,"term":"harvest","meaning":"수확; 수확하다","partOfSpeech":"n.","example":"Farmers celebrate a good harvest at the end of autumn.","exampleTranslation":"농부들은 가을이 끝날 때 풍년 수확을 축하해요.","level":27,"category":"빈도 학습"},{"id":13439,"term":"haste","meaning":"서두름; 급함","partOfSpeech":"n.","example":"She made several mistakes because of haste during the exam.","exampleTranslation":"시험 도중 서두름 때문에 여러 실수를 했어요.","level":27,"category":"빈도 학습"},{"id":13440,"term":"hatch","meaning":"부화하다; 계획을 꾸미다","partOfSpeech":"v.","example":"Baby turtles hatch from their eggs and head straight to the sea.","exampleTranslation":"아기 거북이는 알에서 부화해 곧장 바다로 향해요.","level":27,"category":"빈도 학습"},{"id":13441,"term":"haul","meaning":"끌어당기다; 운반하다","partOfSpeech":"v.","example":"It took three workers to haul the heavy equipment up the stairs.","exampleTranslation":"무거운 장비를 계단으로 끌어올리는 데 세 명의 인부가 필요했어요.","level":27,"category":"빈도 학습"},{"id":13442,"term":"haunt","meaning":"출몰하다; 마음을 사로잡다","partOfSpeech":"v.","example":"Old regrets can haunt a person for many years.","exampleTranslation":"오래된 후회는 수년간 사람의 마음을 사로잡을 수 있어요.","level":27,"category":"빈도 학습"},{"id":13443,"term":"heir","meaning":"상속인; 후계자","partOfSpeech":"n.","example":"The eldest son was named the heir to the family estate.","exampleTranslation":"장남이 가족 재산의 상속인으로 지명되었어요.","level":27,"category":"빈도 학습"},{"id":13444,"term":"helicopter","meaning":"헬리콥터","partOfSpeech":"n.","example":"A helicopter airlifted the injured hiker from the mountain.","exampleTranslation":"헬리콥터가 부상당한 등산객을 산에서 공수했어요.","level":27,"category":"빈도 학습"},{"id":13445,"term":"herb","meaning":"허브; 약초","partOfSpeech":"n.","example":"Basil is a popular herb used in Italian cooking.","exampleTranslation":"바질은 이탈리아 요리에 사용되는 인기 있는 허브예요.","level":27,"category":"빈도 학습"},{"id":13446,"term":"herd","meaning":"떼; 무리","partOfSpeech":"n.","example":"A herd of buffalo crossed the river at sunrise.","exampleTranslation":"버팔로 떼가 일출 때 강을 건넜어요.","level":27,"category":"빈도 학습"},{"id":13447,"term":"hierarchy","meaning":"계층 구조; 위계질서","partOfSpeech":"n.","example":"A strict hierarchy exists within most large corporations.","exampleTranslation":"대부분의 대기업 내에는 엄격한 계층 구조가 존재해요.","level":27,"category":"빈도 학습"},{"id":13448,"term":"hollow","meaning":"속이 빈; 공허한","partOfSpeech":"adj.","example":"The squirrel stored nuts inside a hollow tree trunk.","exampleTranslation":"다람쥐는 속이 빈 나무 줄기 안에 견과류를 저장했어요.","level":27,"category":"빈도 학습"},{"id":13449,"term":"homosexual","meaning":"동성애자; 동성애의","partOfSpeech":"adj.","example":"The law now protects homosexual couples from discrimination.","exampleTranslation":"법이 이제 동성애 커플을 차별로부터 보호해요.","level":27,"category":"빈도 학습"},{"id":13450,"term":"hood","meaning":"후드; (자동차) 보닛","partOfSpeech":"n.","example":"She pulled her hood over her head to block the rain.","exampleTranslation":"그녀는 빗물을 막으려고 머리 위로 후드를 당겼어요.","level":27,"category":"빈도 학습"},{"id":13451,"term":"hop","meaning":"깡충 뛰다; 훌쩍 이동하다","partOfSpeech":"v.","example":"The children love to hop on one foot across the playground.","exampleTranslation":"아이들은 놀이터에서 한 발로 깡충깡충 뛰는 것을 좋아해요.","level":27,"category":"빈도 학습"},{"id":13452,"term":"horizon","meaning":"수평선; 시야의 한계","partOfSpeech":"n.","example":"We watched the sun slowly sink below the horizon.","exampleTranslation":"우리는 태양이 수평선 아래로 천천히 지는 것을 바라봤어요.","level":27,"category":"빈도 학습"},{"id":13453,"term":"horizontal","meaning":"수평의; 가로 방향의","partOfSpeech":"adj.","example":"Draw a horizontal line across the middle of the page.","exampleTranslation":"페이지 중앙을 가로질러 수평선을 그으세요.","level":27,"category":"빈도 학습"},{"id":13454,"term":"hormone","meaning":"호르몬","partOfSpeech":"n.","example":"The doctor explained that a hormone controls your sleep cycle.","exampleTranslation":"의사는 호르몬이 수면 주기를 조절한다고 설명했어요.","level":27,"category":"빈도 학습"},{"id":13455,"term":"horn","meaning":"뿔; 경적","partOfSpeech":"n.","example":"The driver pressed the horn to warn the pedestrian.","exampleTranslation":"운전자는 보행자에게 경고하기 위해 경적을 눌렀어요.","level":27,"category":"빈도 학습"},{"id":13456,"term":"hostage","meaning":"인질","partOfSpeech":"n.","example":"Police negotiators worked to free every hostage safely.","exampleTranslation":"경찰 협상가들은 모든 인질을 안전하게 구출하기 위해 노력했어요.","level":28,"category":"빈도 학습"},{"id":13457,"term":"hug","meaning":"포옹하다; 껴안다","partOfSpeech":"v.","example":"She ran to hug her grandmother at the airport.","exampleTranslation":"그녀는 공항에서 할머니를 포옹하러 달려갔어요.","level":28,"category":"빈도 학습"},{"id":13458,"term":"humble","meaning":"겸손한; 소박한","partOfSpeech":"adj.","example":"Despite his fame, the actor remained humble and approachable.","exampleTranslation":"명성에도 불구하고 그 배우는 겸손하고 친근한 태도를 유지했어요.","level":28,"category":"빈도 학습"},{"id":13459,"term":"humiliate","meaning":"창피를 주다; 굴욕감을 주다","partOfSpeech":"v.","example":"It is never acceptable to humiliate someone in front of their peers.","exampleTranslation":"동료들 앞에서 누군가에게 창피를 주는 것은 결코 용납될 수 없어요.","level":28,"category":"빈도 학습"},{"id":13460,"term":"hurricane","meaning":"허리케인; 강력한 열대성 폭풍","partOfSpeech":"n.","example":"The hurricane caused widespread damage along the coast.","exampleTranslation":"허리케인은 해안을 따라 광범위한 피해를 입혔어요.","level":28,"category":"빈도 학습"},{"id":13461,"term":"hut","meaning":"오두막; 간이 건물","partOfSpeech":"n.","example":"The hikers took shelter in a small hut during the storm.","exampleTranslation":"등산객들은 폭풍 동안 작은 오두막에서 피신했어요.","level":28,"category":"빈도 학습"},{"id":13462,"term":"hybrid","meaning":"혼합형; 두 가지를 결합한","partOfSpeech":"adj.","example":"Many drivers choose a hybrid vehicle to save on fuel costs.","exampleTranslation":"많은 운전자들이 연료비를 절감하기 위해 혼합형 차량을 선택해요.","level":28,"category":"빈도 학습"},{"id":13463,"term":"hydrogen","meaning":"수소","partOfSpeech":"n.","example":"Scientists are developing cars that run on hydrogen as a clean fuel.","exampleTranslation":"과학자들은 청정 연료인 수소로 달리는 자동차를 개발하고 있어요.","level":28,"category":"빈도 학습"},{"id":13464,"term":"identical","meaning":"동일한; 완전히 같은","partOfSpeech":"adj.","example":"The two paintings looked identical to the untrained eye.","exampleTranslation":"두 그림은 전문가가 아닌 눈에는 동일하게 보였어요.","level":28,"category":"빈도 학습"},{"id":13465,"term":"ideological","meaning":"이념적인; 사상적인","partOfSpeech":"adj.","example":"The two parties have deep ideological differences on economic policy.","exampleTranslation":"두 정당은 경제 정책에 대해 깊은 이념적 차이를 가지고 있어요.","level":28,"category":"빈도 학습"},{"id":13466,"term":"idle","meaning":"게으른; 놀고 있는","partOfSpeech":"adj.","example":"The machines sat idle in the factory during the holiday break.","exampleTranslation":"공장의 기계들은 휴일 동안 가동을 멈추고 놀고 있었어요.","level":28,"category":"빈도 학습"},{"id":13467,"term":"illuminate","meaning":"밝히다; 조명하다","partOfSpeech":"v.","example":"Candles were used to illuminate the room during the power outage.","exampleTranslation":"정전 동안 방을 밝히기 위해 양초를 사용했어요.","level":28,"category":"빈도 학습"},{"id":13468,"term":"illusion","meaning":"환상; 착각","partOfSpeech":"n.","example":"The magician created the illusion that the coin had vanished.","exampleTranslation":"마술사는 동전이 사라진 것처럼 보이는 환상을 연출했어요.","level":28,"category":"빈도 학습"},{"id":13469,"term":"imitate","meaning":"흉내 내다; 모방하다","partOfSpeech":"v.","example":"Young children often imitate the behavior of their parents.","exampleTranslation":"어린아이들은 종종 부모의 행동을 흉내 내요.","level":28,"category":"빈도 학습"},{"id":13470,"term":"immense","meaning":"거대한; 막대한","partOfSpeech":"adj.","example":"Building the dam required immense effort from thousands of workers.","exampleTranslation":"댐 건설에는 수천 명의 노동자들의 거대한 노력이 필요했어요.","level":28,"category":"빈도 학습"},{"id":13471,"term":"immigrate","meaning":"이민 오다; 이주해 들어오다","partOfSpeech":"v.","example":"His grandparents decided to immigrate to Canada for a better life.","exampleTranslation":"그의 조부모님은 더 나은 삶을 위해 캐나다로 이민 오기로 결심했어요.","level":28,"category":"빈도 학습"},{"id":13472,"term":"impair","meaning":"손상시키다; 약화시키다","partOfSpeech":"v.","example":"Too much screen time can impair your ability to focus on tasks.","exampleTranslation":"지나친 화면 사용은 업무에 집중하는 능력을 손상시킬 수 있어요.","level":28,"category":"빈도 학습"},{"id":13473,"term":"impatient","meaning":"조급한; 참을성 없는","partOfSpeech":"adj.","example":"He grew impatient waiting in line for over an hour.","exampleTranslation":"그는 한 시간 넘게 줄을 서서 기다리다가 조급해졌어요.","level":28,"category":"빈도 학습"},{"id":13474,"term":"implicit","meaning":"암묵적인; 명시되지 않은","partOfSpeech":"adj.","example":"There was an implicit agreement that no one would mention the issue.","exampleTranslation":"그 문제를 언급하지 않겠다는 암묵적인 합의가 있었어요.","level":28,"category":"빈도 학습"},{"id":13475,"term":"impulse","meaning":"충동; 자극","partOfSpeech":"n.","example":"She bought the dress on impulse without checking the price tag.","exampleTranslation":"그녀는 가격표를 확인하지 않고 충동적으로 그 드레스를 샀어요.","level":28,"category":"빈도 학습"},{"id":13476,"term":"incidence","meaning":"발생률; 발생 빈도","partOfSpeech":"n.","example":"The incidence of allergies has risen sharply over the past decade.","exampleTranslation":"알레르기 발생률이 지난 10년 동안 급격히 상승했어요.","level":28,"category":"빈도 학습"},{"id":13477,"term":"incline","meaning":"기울다; ~하는 경향이 있다","partOfSpeech":"v.","example":"Most experts incline toward the view that exercise prevents disease.","exampleTranslation":"대부분의 전문가들은 운동이 질병을 예방한다는 견해 쪽으로 기울어요.","level":28,"category":"빈도 학습"},{"id":13478,"term":"inclusion","meaning":"포함; 포용","partOfSpeech":"n.","example":"The company promotes inclusion by welcoming people of all backgrounds.","exampleTranslation":"그 회사는 모든 배경의 사람들을 환영함으로써 포용을 장려해요.","level":28,"category":"빈도 학습"},{"id":13479,"term":"indifferent","meaning":"무관심한; 냉담한","partOfSpeech":"adj.","example":"She seemed indifferent to the criticism and kept working calmly.","exampleTranslation":"그녀는 비판에 무관심한 듯 보이며 침착하게 계속 일했어요.","level":28,"category":"빈도 학습"},{"id":13480,"term":"indigenous","meaning":"토착의; 원주민의","partOfSpeech":"adj.","example":"The museum showcases art created by indigenous communities of the region.","exampleTranslation":"박물관은 그 지역 토착 공동체가 만든 예술품을 전시해요.","level":28,"category":"빈도 학습"},{"id":13481,"term":"indirect","meaning":"간접적인; 돌아가는","partOfSpeech":"adj.","example":"She took an indirect route to avoid the heavy traffic downtown.","exampleTranslation":"그녀는 도심의 극심한 교통 체증을 피하기 위해 간접적인 경로를 택했어요.","level":28,"category":"빈도 학습"},{"id":13482,"term":"induce","meaning":"유도하다; 유발하다","partOfSpeech":"v.","example":"Warm milk before bed can induce a feeling of relaxation.","exampleTranslation":"잠자리에 들기 전 따뜻한 우유는 편안함을 유도할 수 있어요.","level":28,"category":"빈도 학습"},{"id":13483,"term":"indulge","meaning":"탐닉하다; 마음껏 즐기다","partOfSpeech":"v.","example":"It is fine to indulge in a piece of cake on special occasions.","exampleTranslation":"특별한 날에 케이크 한 조각을 마음껏 즐기는 것은 괜찮아요.","level":28,"category":"빈도 학습"},{"id":13484,"term":"infer","meaning":"추론하다; 추측하다","partOfSpeech":"v.","example":"From her tone, we can infer that she was not happy with the result.","exampleTranslation":"그녀의 말투로 보아 결과에 만족하지 못했다는 것을 추론할 수 있어요.","level":28,"category":"빈도 학습"},{"id":13485,"term":"infinite","meaning":"무한한; 끝없는","partOfSpeech":"adj.","example":"The universe appears to have infinite space that we cannot fully explore.","exampleTranslation":"우주는 우리가 완전히 탐험할 수 없는 무한한 공간을 가진 것처럼 보여요.","level":28,"category":"빈도 학습"},{"id":13486,"term":"inflame","meaning":"악화시키다; 자극하여 흥분시키다","partOfSpeech":"v.","example":"His harsh words only served to inflame the already tense situation.","exampleTranslation":"그의 거친 말은 이미 긴장된 상황을 더욱 악화시키는 데만 쓰였어요.","level":28,"category":"빈도 학습"},{"id":13487,"term":"informal","meaning":"비공식적인; 격식 없는","partOfSpeech":"adj.","example":"The team held an informal meeting over coffee to share ideas.","exampleTranslation":"팀은 아이디어를 나누기 위해 커피를 마시며 비공식적인 회의를 열었어요.","level":28,"category":"빈도 학습"},{"id":13488,"term":"infrastructure","meaning":"기반 시설; 인프라","partOfSpeech":"n.","example":"The government plans to invest heavily in infrastructure to improve transport.","exampleTranslation":"정부는 교통을 개선하기 위해 기반 시설에 대규모 투자를 계획하고 있어요.","level":28,"category":"빈도 학습"},{"id":13489,"term":"inherent","meaning":"본질적인; 타고난","partOfSpeech":"adj.","example":"There is an inherent risk in any type of outdoor adventure sport.","exampleTranslation":"모든 종류의 야외 모험 스포츠에는 본질적인 위험이 있어요.","level":28,"category":"빈도 학습"},{"id":13490,"term":"inhibit","meaning":"억제하다; 방해하다","partOfSpeech":"v.","example":"Stress can inhibit the body's natural ability to heal itself.","exampleTranslation":"스트레스는 신체의 자연 치유 능력을 억제할 수 있어요.","level":28,"category":"빈도 학습"},{"id":13491,"term":"ink","meaning":"잉크; 먹","partOfSpeech":"n.","example":"The printer ran out of ink in the middle of printing the report.","exampleTranslation":"프린터가 보고서를 인쇄하는 도중에 잉크가 떨어졌어요.","level":28,"category":"빈도 학습"},{"id":13492,"term":"inn","meaning":"여관; 소규모 숙박 시설","partOfSpeech":"n.","example":"They spent the night at a cozy inn near the mountain trail.","exampleTranslation":"그들은 산길 근처의 아늑한 여관에서 하룻밤을 보냈어요.","level":28,"category":"빈도 학습"},{"id":13493,"term":"innovative","meaning":"혁신적인; 창의적인","partOfSpeech":"adj.","example":"The startup introduced an innovative solution to reduce food waste.","exampleTranslation":"그 스타트업은 음식물 쓰레기를 줄이기 위한 혁신적인 해결책을 도입했어요.","level":28,"category":"빈도 학습"},{"id":13494,"term":"insect","meaning":"곤충; 벌레","partOfSpeech":"n.","example":"Scientists discovered a new insect species deep in the rainforest.","exampleTranslation":"과학자들이 열대우림 깊숙이에서 새로운 곤충 종을 발견했어요.","level":28,"category":"빈도 학습"},{"id":13495,"term":"insulate","meaning":"단열(절연)하다; 차단하다","partOfSpeech":"v.","example":"We need to insulate the walls to keep the house warm in winter.","exampleTranslation":"겨울에 집을 따뜻하게 유지하려면 벽을 단열해야 해요.","level":28,"category":"빈도 학습"},{"id":13496,"term":"insult","meaning":"모욕하다; 무시하다","partOfSpeech":"v.","example":"It is rude to insult someone because of their cultural background.","exampleTranslation":"문화적 배경을 이유로 누군가를 모욕하는 것은 무례한 행동이에요.","level":28,"category":"빈도 학습"},{"id":13497,"term":"intact","meaning":"손상되지 않은; 온전한","partOfSpeech":"adj.","example":"Remarkably, the old building remained intact after the earthquake.","exampleTranslation":"놀랍게도 그 오래된 건물은 지진 후에도 온전하게 남아 있었어요.","level":28,"category":"빈도 학습"},{"id":13498,"term":"integral","meaning":"필수적인; 핵심을 이루는","partOfSpeech":"adj.","example":"Good communication is integral to the success of any team project.","exampleTranslation":"원활한 소통은 모든 팀 프로젝트의 성공에 필수적이에요.","level":28,"category":"빈도 학습"},{"id":13499,"term":"integrity","meaning":"성실성; 도덕적 온전함","partOfSpeech":"n.","example":"Voters look for a leader who shows integrity in both public and private life.","exampleTranslation":"유권자들은 공적·사적 생활 모두에서 성실성을 보여주는 지도자를 원해요.","level":28,"category":"빈도 학습"},{"id":13500,"term":"intelligent","meaning":"똑똑한; 지능이 높은","partOfSpeech":"adj.","example":"She is intelligent enough to solve complex math problems.","exampleTranslation":"그녀는 복잡한 수학 문제를 풀 만큼 충분히 똑똑하다.","level":28,"category":"빈도 학습"},{"id":13501,"term":"interface","meaning":"접점; 인터페이스","partOfSpeech":"n.","example":"The new interface makes the software much easier to use.","exampleTranslation":"새 인터페이스 덕분에 소프트웨어를 훨씬 더 쉽게 사용할 수 있다.","level":28,"category":"빈도 학습"},{"id":13502,"term":"interim","meaning":"임시의; 중간의","partOfSpeech":"adj.","example":"The board appointed an interim manager until a permanent one is found.","exampleTranslation":"이사회는 정식 관리자가 결정될 때까지 임시 관리자를 임명했다.","level":28,"category":"빈도 학습"},{"id":13503,"term":"interval","meaning":"간격; 사이","partOfSpeech":"n.","example":"The buses run at a regular interval of fifteen minutes.","exampleTranslation":"버스는 15분 간격으로 정기적으로 운행된다.","level":28,"category":"빈도 학습"},{"id":13504,"term":"intimidate","meaning":"위협하다; 겁주다","partOfSpeech":"v.","example":"Bullies often intimidate smaller students in school hallways.","exampleTranslation":"괴롭히는 아이들은 학교 복도에서 작은 학생들을 자주 위협한다.","level":28,"category":"빈도 학습"},{"id":13505,"term":"intrigue","meaning":"흥미를 불러일으키다; 음모","partOfSpeech":"v.","example":"Ancient mysteries always intrigue historians and archaeologists.","exampleTranslation":"고대의 수수께끼는 항상 역사가와 고고학자들의 흥미를 자아낸다.","level":28,"category":"빈도 학습"},{"id":13506,"term":"invade","meaning":"침략하다; 침범하다","partOfSpeech":"v.","example":"Enemy forces tried to invade the small island nation.","exampleTranslation":"적군은 작은 섬나라를 침략하려 했다.","level":28,"category":"빈도 학습"},{"id":13507,"term":"invoke","meaning":"발동하다; 불러내다","partOfSpeech":"v.","example":"The lawyer decided to invoke an old legal precedent in court.","exampleTranslation":"변호사는 법정에서 오래된 법적 선례를 발동하기로 결정했다.","level":28,"category":"빈도 학습"},{"id":13508,"term":"irritate","meaning":"짜증나게 하다; 자극하다","partOfSpeech":"v.","example":"Loud noises tend to irritate people who are trying to concentrate.","exampleTranslation":"시끄러운 소음은 집중하려는 사람들을 짜증나게 하는 경향이 있다.","level":28,"category":"빈도 학습"},{"id":13509,"term":"jar","meaning":"병; 단지","partOfSpeech":"n.","example":"She kept homemade jam in a glass jar on the shelf.","exampleTranslation":"그녀는 선반 위 유리병에 직접 만든 잼을 보관했다.","level":28,"category":"빈도 학습"},{"id":13510,"term":"jazz","meaning":"재즈","partOfSpeech":"n.","example":"We listened to live jazz at a small club downtown.","exampleTranslation":"우리는 시내 작은 클럽에서 라이브 재즈 연주를 들었다.","level":28,"category":"빈도 학습"},{"id":13511,"term":"jerk","meaning":"홱 당기다; 얼간이","partOfSpeech":"v.","example":"He had to jerk the stuck door handle to open it.","exampleTranslation":"그는 열리지 않는 문 손잡이를 홱 당겨야 했다.","level":28,"category":"빈도 학습"},{"id":13512,"term":"jewelry","meaning":"보석류; 장신구","partOfSpeech":"n.","example":"She wore elegant jewelry to match her evening dress.","exampleTranslation":"그녀는 이브닝드레스에 어울리는 우아한 보석 장신구를 착용했다.","level":28,"category":"빈도 학습"},{"id":13513,"term":"judicial","meaning":"사법의; 재판의","partOfSpeech":"adj.","example":"The judicial process ensures that every citizen receives a fair trial.","exampleTranslation":"사법 절차는 모든 시민이 공정한 재판을 받도록 보장한다.","level":28,"category":"빈도 학습"},{"id":13514,"term":"jungle","meaning":"정글; 밀림","partOfSpeech":"n.","example":"Explorers had to cut through thick jungle to reach the ruins.","exampleTranslation":"탐험가들은 유적에 도달하기 위해 울창한 밀림을 헤치고 나아가야 했다.","level":28,"category":"빈도 학습"},{"id":13515,"term":"jurisdiction","meaning":"관할권; 사법권","partOfSpeech":"n.","example":"This crime falls under the jurisdiction of the federal court.","exampleTranslation":"이 범죄는 연방 법원의 관할권에 해당한다.","level":28,"category":"빈도 학습"},{"id":13516,"term":"juvenile","meaning":"청소년의; 미성숙한","partOfSpeech":"adj.","example":"The juvenile offender was sent to a rehabilitation center.","exampleTranslation":"미성년 범죄자는 재활 센터로 보내졌다.","level":28,"category":"빈도 학습"},{"id":13517,"term":"keyboard","meaning":"키보드; 건반","partOfSpeech":"n.","example":"He replaced his old keyboard with a mechanical one for better typing.","exampleTranslation":"그는 더 나은 타이핑을 위해 오래된 키보드를 기계식으로 교체했다.","level":28,"category":"빈도 학습"},{"id":13518,"term":"kidnap","meaning":"유괴하다; 납치하다","partOfSpeech":"v.","example":"Criminals sometimes kidnap wealthy individuals to demand ransom.","exampleTranslation":"범죄자들은 몸값을 요구하기 위해 부유한 사람들을 납치하기도 한다.","level":28,"category":"빈도 학습"},{"id":13519,"term":"kilogram","meaning":"킬로그램","partOfSpeech":"n.","example":"The recipe requires one kilogram of flour to make the bread.","exampleTranslation":"그 레시피는 빵을 만들기 위해 1킬로그램의 밀가루가 필요하다.","level":28,"category":"빈도 학습"},{"id":13520,"term":"kin","meaning":"친족; 혈육","partOfSpeech":"n.","example":"The hospital contacted his next of kin after the accident.","exampleTranslation":"병원은 사고 후 그의 가장 가까운 가족에게 연락했다.","level":28,"category":"빈도 학습"},{"id":13521,"term":"kit","meaning":"도구 세트; 장비 일식","partOfSpeech":"n.","example":"Always keep a first-aid kit in your car for emergencies.","exampleTranslation":"응급 상황을 대비해 차에 항상 응급 도구 세트를 비치해 두어라.","level":28,"category":"빈도 학습"},{"id":13522,"term":"kneel","meaning":"무릎을 꿇다","partOfSpeech":"v.","example":"The soldier had to kneel before presenting the award.","exampleTranslation":"그 군인은 훈장을 수여하기 전에 무릎을 꿇어야 했다.","level":28,"category":"빈도 학습"},{"id":13523,"term":"knot","meaning":"매듭; 묶다","partOfSpeech":"n.","example":"Tie a secure knot so the rope does not come loose.","exampleTranslation":"줄이 풀리지 않도록 단단한 매듭을 매어라.","level":28,"category":"빈도 학습"},{"id":13524,"term":"lace","meaning":"레이스; 끈","partOfSpeech":"n.","example":"The wedding dress was decorated with delicate white lace.","exampleTranslation":"웨딩드레스는 섬세한 흰색 레이스로 장식되어 있었다.","level":28,"category":"빈도 학습"},{"id":13525,"term":"ladder","meaning":"사다리; 단계","partOfSpeech":"n.","example":"The painter climbed a ladder to reach the top of the wall.","exampleTranslation":"화가는 벽 꼭대기에 닿기 위해 사다리를 올라갔다.","level":28,"category":"빈도 학습"},{"id":13526,"term":"lap","meaning":"무릎 위; 한 바퀴","partOfSpeech":"n.","example":"The cat curled up on her lap while she read a book.","exampleTranslation":"고양이는 그녀가 책을 읽는 동안 그녀의 무릎 위에 웅크리고 앉았다.","level":28,"category":"빈도 학습"},{"id":13527,"term":"laser","meaning":"레이저","partOfSpeech":"n.","example":"Doctors used a laser to correct the patient's vision problems.","exampleTranslation":"의사들은 환자의 시력 문제를 교정하기 위해 레이저를 사용했다.","level":28,"category":"빈도 학습"},{"id":13528,"term":"laundry","meaning":"세탁물; 빨래","partOfSpeech":"n.","example":"I need to do the laundry before I run out of clean clothes.","exampleTranslation":"깨끗한 옷이 떨어지기 전에 빨래를 해야 한다.","level":28,"category":"빈도 학습"},{"id":13529,"term":"leaf","meaning":"나뭇잎; 장(페이지)","partOfSpeech":"n.","example":"A single leaf fell from the tree and landed on the bench.","exampleTranslation":"나무에서 나뭇잎 한 장이 떨어져 벤치 위에 내려앉았다.","level":28,"category":"빈도 학습"},{"id":13530,"term":"legacy","meaning":"유산; 물려받은 것","partOfSpeech":"n.","example":"The scientist left a remarkable legacy for future generations.","exampleTranslation":"그 과학자는 미래 세대를 위해 놀라운 유산을 남겼다.","level":28,"category":"빈도 학습"},{"id":13531,"term":"legislature","meaning":"입법부; 의회","partOfSpeech":"n.","example":"The legislature passed a new law to protect consumer rights.","exampleTranslation":"입법부는 소비자 권리를 보호하기 위한 새 법을 통과시켰다.","level":28,"category":"빈도 학습"},{"id":13532,"term":"leisure","meaning":"여가; 한가한 시간","partOfSpeech":"n.","example":"Reading is one of her favorite leisure activities on weekends.","exampleTranslation":"독서는 주말에 그녀가 가장 좋아하는 여가 활동 중 하나다.","level":28,"category":"빈도 학습"},{"id":13533,"term":"lemon","meaning":"레몬","partOfSpeech":"n.","example":"She squeezed a lemon over the salad to add a fresh flavor.","exampleTranslation":"그녀는 신선한 맛을 더하기 위해 샐러드에 레몬즙을 짰다.","level":28,"category":"빈도 학습"},{"id":13534,"term":"lens","meaning":"렌즈; 수정체","partOfSpeech":"n.","example":"The photographer chose a wide-angle lens for the landscape shot.","exampleTranslation":"사진가는 풍경 사진을 위해 광각 렌즈를 선택했다.","level":28,"category":"빈도 학습"},{"id":13535,"term":"lesbian","meaning":"레즈비언; 여성 동성애자","partOfSpeech":"n.","example":"The documentary featured a lesbian couple talking about their daily lives.","exampleTranslation":"그 다큐멘터리는 일상에 대해 이야기하는 동성 커플을 담았다.","level":28,"category":"빈도 학습"},{"id":13536,"term":"lever","meaning":"지렛대; 레버","partOfSpeech":"n.","example":"Pull the lever on the right side to open the safety gate.","exampleTranslation":"안전문을 열려면 오른쪽 손잡이를 당기세요.","level":28,"category":"빈도 학습"},{"id":13537,"term":"lick","meaning":"핥다; 할다","partOfSpeech":"v.","example":"The puppy would lick your hand whenever you petted him.","exampleTranslation":"강아지는 쓰다듬을 때마다 손을 핥곤 했다.","level":28,"category":"빈도 학습"},{"id":13538,"term":"lieutenant","meaning":"중위; 부관","partOfSpeech":"n.","example":"The lieutenant gave orders to the soldiers before the mission.","exampleTranslation":"중위는 임무 전에 병사들에게 명령을 내렸다.","level":28,"category":"빈도 학습"},{"id":13539,"term":"likewise","meaning":"마찬가지로; 똑같이","partOfSpeech":"adv.","example":"He finished his work early, and his colleague did likewise.","exampleTranslation":"그는 일찍 일을 마쳤고, 동료도 마찬가지였다.","level":28,"category":"빈도 학습"},{"id":13540,"term":"limb","meaning":"팔다리; 사지","partOfSpeech":"n.","example":"The surgeon carefully operated on the injured limb.","exampleTranslation":"외과 의사는 부상당한 팔다리를 조심스럽게 수술했다.","level":28,"category":"빈도 학습"},{"id":13541,"term":"linear","meaning":"선형의; 직선의","partOfSpeech":"adj.","example":"The app displays progress in a linear chart from left to right.","exampleTranslation":"앱은 진행 상황을 왼쪽에서 오른쪽으로 직선 형태의 차트로 표시한다.","level":28,"category":"빈도 학습"},{"id":13542,"term":"linger","meaning":"오래 머물다; 남아 있다","partOfSpeech":"v.","example":"A pleasant smell tends to linger in the kitchen after cooking.","exampleTranslation":"요리 후에 좋은 냄새가 부엌에 오래 머무는 경향이 있다.","level":28,"category":"빈도 학습"},{"id":13543,"term":"linguistic","meaning":"언어의; 언어학의","partOfSpeech":"adj.","example":"The professor studies linguistic patterns across different cultures.","exampleTranslation":"교수는 다양한 문화에 걸친 언어적 패턴을 연구한다.","level":28,"category":"빈도 학습"},{"id":13544,"term":"literacy","meaning":"문해력; 읽고 쓰는 능력","partOfSpeech":"n.","example":"Improving literacy among children is a key education goal.","exampleTranslation":"어린이의 문해력 향상은 핵심 교육 목표다.","level":28,"category":"빈도 학습"},{"id":13545,"term":"liver","meaning":"간; 간장","partOfSpeech":"n.","example":"Drinking too much alcohol can seriously damage the liver.","exampleTranslation":"과도한 음주는 간에 심각한 손상을 줄 수 있다.","level":28,"category":"빈도 학습"},{"id":13546,"term":"loom","meaning":"어렴풋이 나타나다; 위협적으로 다가오다","partOfSpeech":"v.","example":"Dark storm clouds began to loom on the distant horizon.","exampleTranslation":"어두운 먹구름이 먼 지평선에 서서히 나타나기 시작했다.","level":28,"category":"빈도 학습"},{"id":13547,"term":"loop","meaning":"고리; 루프","partOfSpeech":"n.","example":"Thread the belt through the loop on your pants.","exampleTranslation":"벨트를 바지의 고리에 통과시켜라.","level":28,"category":"빈도 학습"},{"id":13548,"term":"lounge","meaning":"라운지; 휴게실","partOfSpeech":"n.","example":"We waited for our flight in the comfortable airport lounge.","exampleTranslation":"우리는 편안한 공항 라운지에서 비행기를 기다렸다.","level":28,"category":"빈도 학습"},{"id":13549,"term":"lung","meaning":"폐; 허파","partOfSpeech":"n.","example":"Smoking cigarettes can permanently damage your lung capacity.","exampleTranslation":"담배를 피우면 폐 기능이 영구적으로 손상될 수 있다.","level":28,"category":"빈도 학습"},{"id":13550,"term":"lyric","meaning":"가사; 서정적인 시","partOfSpeech":"n.","example":"She wrote every lyric of the song herself.","exampleTranslation":"그녀는 그 노래의 모든 가사를 직접 썼어요.","level":28,"category":"빈도 학습"},{"id":13551,"term":"magnificent","meaning":"웅장한; 훌륭한","partOfSpeech":"adj.","example":"The view from the hilltop was truly magnificent.","exampleTranslation":"언덕 꼭대기에서 바라본 경치는 정말 웅장했어요.","level":28,"category":"빈도 학습"},{"id":13552,"term":"magnitude","meaning":"규모; 크기","partOfSpeech":"n.","example":"Scientists measured the magnitude of the earthquake.","exampleTranslation":"과학자들이 지진의 규모를 측정했어요.","level":28,"category":"빈도 학습"},{"id":13553,"term":"mammal","meaning":"포유동물","partOfSpeech":"n.","example":"A whale is the largest mammal on Earth.","exampleTranslation":"고래는 지구에서 가장 큰 포유동물이에요.","level":28,"category":"빈도 학습"},{"id":13554,"term":"mandate","meaning":"명령; 권한","partOfSpeech":"n.","example":"The new president received a clear mandate from voters.","exampleTranslation":"새 대통령은 유권자들로부터 명확한 권한을 받았어요.","level":28,"category":"빈도 학습"},{"id":13555,"term":"manuscript","meaning":"원고; 필사본","partOfSpeech":"n.","example":"The author sent the final manuscript to the publisher.","exampleTranslation":"작가는 최종 원고를 출판사에 보냈어요.","level":28,"category":"빈도 학습"},{"id":13556,"term":"marble","meaning":"대리석; 구슬","partOfSpeech":"n.","example":"The floor was made of polished marble.","exampleTranslation":"바닥은 광을 낸 대리석으로 만들어졌어요.","level":28,"category":"빈도 학습"},{"id":13557,"term":"mat","meaning":"매트; 깔개","partOfSpeech":"n.","example":"Please wipe your shoes on the mat before entering.","exampleTranslation":"들어오기 전에 매트에 신발을 닦아 주세요.","level":28,"category":"빈도 학습"},{"id":13558,"term":"matrix","meaning":"행렬; 기반 구조","partOfSpeech":"n.","example":"The teacher drew a matrix on the board to explain the problem.","exampleTranslation":"선생님이 문제를 설명하기 위해 칠판에 행렬을 그렸어요.","level":28,"category":"빈도 학습"},{"id":13559,"term":"maximize","meaning":"최대화하다; 극대화하다","partOfSpeech":"v.","example":"We need to maximize our use of available resources.","exampleTranslation":"우리는 가용 자원의 활용을 최대화해야 해요.","level":28,"category":"빈도 학습"},{"id":13560,"term":"meantime","meaning":"그 동안; 그 사이에","partOfSpeech":"n.","example":"In the meantime, please wait here for further instructions.","exampleTranslation":"그 동안은 추가 지시를 기다리며 여기 있어 주세요.","level":28,"category":"빈도 학습"},{"id":13561,"term":"medal","meaning":"메달; 훈장","partOfSpeech":"n.","example":"She won a gold medal at the national swimming championship.","exampleTranslation":"그녀는 전국 수영 선수권 대회에서 금메달을 땄어요.","level":28,"category":"빈도 학습"},{"id":13562,"term":"mediate","meaning":"중재하다; 조정하다","partOfSpeech":"v.","example":"A neutral party was asked to mediate between the two companies.","exampleTranslation":"두 회사 사이를 중재하기 위해 중립적인 제3자가 요청되었어요.","level":28,"category":"빈도 학습"},{"id":13563,"term":"medieval","meaning":"중세의; 중세 시대의","partOfSpeech":"adj.","example":"The castle has a long medieval history dating back centuries.","exampleTranslation":"그 성은 수백 년 전으로 거슬러 올라가는 긴 중세 역사를 가지고 있어요.","level":29,"category":"빈도 학습"},{"id":13564,"term":"melody","meaning":"멜로디; 선율","partOfSpeech":"n.","example":"The melody of that old song stayed in my head all day.","exampleTranslation":"그 오래된 노래의 멜로디가 하루 종일 머릿속을 맴돌았어요.","level":29,"category":"빈도 학습"},{"id":13565,"term":"merchant","meaning":"상인; 무역상","partOfSpeech":"n.","example":"The merchant sold spices from distant lands.","exampleTranslation":"그 상인은 먼 나라에서 온 향신료를 팔았어요.","level":29,"category":"빈도 학습"},{"id":13566,"term":"mercy","meaning":"자비; 연민","partOfSpeech":"n.","example":"The judge showed mercy toward the first-time offender.","exampleTranslation":"판사는 초범에게 자비를 베풀었어요.","level":29,"category":"빈도 학습"},{"id":13567,"term":"merit","meaning":"장점; 가치","partOfSpeech":"n.","example":"Each application will be judged on its own merit.","exampleTranslation":"각 지원서는 그 자체의 가치에 따라 평가될 거예요.","level":29,"category":"빈도 학습"},{"id":13568,"term":"metaphor","meaning":"은유; 비유","partOfSpeech":"n.","example":"The poem uses a metaphor to describe life as a journey.","exampleTranslation":"그 시는 삶을 여행에 빗대는 은유를 사용해요.","level":29,"category":"빈도 학습"},{"id":13569,"term":"metropolitan","meaning":"대도시의; 수도권의","partOfSpeech":"adj.","example":"The metropolitan area has a population of over ten million.","exampleTranslation":"그 대도시 지역은 인구가 천만 명이 넘어요.","level":29,"category":"빈도 학습"},{"id":13570,"term":"mid","meaning":"중간의; 한가운데의","partOfSpeech":"adj.","example":"The meeting is scheduled for mid afternoon on Friday.","exampleTranslation":"회의는 금요일 오후 중간 시간대로 예정되어 있어요.","level":29,"category":"빈도 학습"},{"id":13571,"term":"mighty","meaning":"강력한; 힘센","partOfSpeech":"adj.","example":"A mighty storm swept through the coastal town last night.","exampleTranslation":"어젯밤 강력한 폭풍이 해안 마을을 휩쓸었어요.","level":29,"category":"빈도 학습"},{"id":13572,"term":"militant","meaning":"투쟁적인; 호전적인","partOfSpeech":"adj.","example":"The militant group refused to accept any compromise.","exampleTranslation":"그 호전적인 집단은 어떤 타협도 거부했어요.","level":29,"category":"빈도 학습"},{"id":13573,"term":"milligram","meaning":"밀리그램","partOfSpeech":"n.","example":"The doctor prescribed 500 milligram tablets for the infection.","exampleTranslation":"의사가 감염 치료를 위해 500밀리그램 정제를 처방했어요.","level":29,"category":"빈도 학습"},{"id":13574,"term":"mineral","meaning":"광물; 미네랄","partOfSpeech":"n.","example":"This water contains a high level of mineral content.","exampleTranslation":"이 물에는 미네랄 함량이 높아요.","level":29,"category":"빈도 학습"},{"id":13575,"term":"minimal","meaning":"최소한의; 아주 적은","partOfSpeech":"adj.","example":"The new design uses minimal furniture to create open space.","exampleTranslation":"새 디자인은 열린 공간을 만들기 위해 최소한의 가구를 사용해요.","level":29,"category":"빈도 학습"},{"id":13576,"term":"minimize","meaning":"최소화하다; 줄이다","partOfSpeech":"v.","example":"We should minimize waste by recycling as much as possible.","exampleTranslation":"가능한 한 많이 재활용해서 낭비를 최소화해야 해요.","level":29,"category":"빈도 학습"},{"id":13577,"term":"miracle","meaning":"기적; 놀라운 일","partOfSpeech":"n.","example":"It seemed like a miracle that everyone survived the crash.","exampleTranslation":"모든 사람이 충돌에서 살아남은 것은 기적처럼 보였어요.","level":29,"category":"빈도 학습"},{"id":13578,"term":"miserable","meaning":"비참한; 불행한","partOfSpeech":"adj.","example":"He felt miserable after failing the exam for the second time.","exampleTranslation":"그는 두 번째로 시험에 떨어진 후 비참한 기분이 들었어요.","level":29,"category":"빈도 학습"},{"id":13579,"term":"mist","meaning":"안개; 霧","partOfSpeech":"n.","example":"A thin mist covered the valley early in the morning.","exampleTranslation":"이른 아침 얇은 안개가 계곡을 뒤덮었어요.","level":29,"category":"빈도 학습"},{"id":13580,"term":"mobilize","meaning":"동원하다; 결집시키다","partOfSpeech":"v.","example":"The charity worked hard to mobilize volunteers for the event.","exampleTranslation":"그 자선단체는 행사를 위해 자원봉사자를 동원하기 위해 열심히 노력했어요.","level":29,"category":"빈도 학습"},{"id":13581,"term":"mock","meaning":"조롱하다; 흉내 내다","partOfSpeech":"v.","example":"It is unkind to mock someone for making a mistake.","exampleTranslation":"실수한 사람을 조롱하는 것은 불친절한 행동이에요.","level":29,"category":"빈도 학습"},{"id":13582,"term":"moisture","meaning":"수분; 습기","partOfSpeech":"n.","example":"Plants absorb moisture from the soil through their roots.","exampleTranslation":"식물은 뿌리를 통해 토양에서 수분을 흡수해요.","level":29,"category":"빈도 학습"},{"id":13583,"term":"momentum","meaning":"추진력; 탄력","partOfSpeech":"n.","example":"The team gained momentum after scoring two goals in a row.","exampleTranslation":"팀은 두 골을 연속으로 넣은 후 추진력을 얻었어요.","level":29,"category":"빈도 학습"},{"id":13584,"term":"monarch","meaning":"군주; 왕","partOfSpeech":"n.","example":"The monarch greeted foreign leaders at the royal palace.","exampleTranslation":"군주는 왕궁에서 외국 지도자들을 맞이했어요.","level":29,"category":"빈도 학습"},{"id":13585,"term":"monetary","meaning":"금전적인; 통화의","partOfSpeech":"adj.","example":"The government announced a new monetary policy to control inflation.","exampleTranslation":"정부는 인플레이션을 통제하기 위한 새로운 통화 정책을 발표했어요.","level":29,"category":"빈도 학습"},{"id":13586,"term":"monopoly","meaning":"독점; 전매","partOfSpeech":"n.","example":"The company has a monopoly on the local electricity supply.","exampleTranslation":"그 회사는 지역 전력 공급을 독점하고 있어요.","level":29,"category":"빈도 학습"},{"id":13587,"term":"monument","meaning":"기념비; 유적","partOfSpeech":"n.","example":"The city built a monument to honor the soldiers who died in the war.","exampleTranslation":"시는 전쟁에서 사망한 병사들을 기리기 위해 기념비를 세웠어요.","level":29,"category":"빈도 학습"},{"id":13588,"term":"mold","meaning":"틀; 곰팡이","partOfSpeech":"n.","example":"The baker poured the batter into a mold to shape the cake.","exampleTranslation":"제빵사는 케이크 모양을 잡기 위해 반죽을 틀에 부었어요.","level":29,"category":"빈도 학습"},{"id":13589,"term":"mourn","meaning":"슬퍼하다; 애도하다","partOfSpeech":"v.","example":"The whole community gathered to mourn the loss of a beloved teacher.","exampleTranslation":"온 지역 사회가 사랑받는 선생님의 죽음을 애도하기 위해 모였어요.","level":29,"category":"빈도 학습"},{"id":13590,"term":"ms","meaning":"~씨 (기혼·미혼 구분 없는 여성 경칭)","partOfSpeech":"n.","example":"Please address the letter to ms Johnson at the front desk.","exampleTranslation":"편지를 안내 데스크의 존슨 씨 앞으로 보내 주세요.","level":29,"category":"빈도 학습"},{"id":13591,"term":"multiply","meaning":"곱하다; 증가하다","partOfSpeech":"v.","example":"You need to multiply the length by the width to find the area.","exampleTranslation":"넓이를 구하려면 길이에 너비를 곱해야 해요.","level":29,"category":"빈도 학습"},{"id":13592,"term":"municipal","meaning":"시의; 지방 자치의","partOfSpeech":"adj.","example":"The municipal government decided to build a new public library.","exampleTranslation":"시 정부는 새로운 공공 도서관을 짓기로 결정했어요.","level":29,"category":"빈도 학습"},{"id":13593,"term":"murmur","meaning":"중얼거리다; 낮게 속삭이다","partOfSpeech":"v.","example":"He began to murmur a quiet prayer before the meal.","exampleTranslation":"그는 식사 전에 조용히 기도를 중얼거리기 시작했어요.","level":29,"category":"빈도 학습"},{"id":13594,"term":"mushroom","meaning":"버섯; 급속히 늘다","partOfSpeech":"n.","example":"She added a mushroom to the soup for extra flavor.","exampleTranslation":"그녀는 더 풍부한 맛을 위해 수프에 버섯을 넣었어요.","level":29,"category":"빈도 학습"},{"id":13595,"term":"mutter","meaning":"투덜거리다; 중얼거리다","partOfSpeech":"v.","example":"He started to mutter complaints under his breath during the meeting.","exampleTranslation":"그는 회의 중에 작은 소리로 불평을 투덜거리기 시작했어요.","level":29,"category":"빈도 학습"},{"id":13596,"term":"navigate","meaning":"항해하다; 길을 찾다","partOfSpeech":"v.","example":"It can be difficult to navigate through a busy city center.","exampleTranslation":"혼잡한 도심을 헤쳐 나가는 것은 어려울 수 있어요.","level":29,"category":"빈도 학습"},{"id":13597,"term":"necessity","meaning":"필요성; 필수품","partOfSpeech":"n.","example":"Clean water is a basic necessity for all living creatures.","exampleTranslation":"깨끗한 물은 모든 생물에게 기본적인 필수품이에요.","level":29,"category":"빈도 학습"},{"id":13598,"term":"needle","meaning":"바늘; 침","partOfSpeech":"n.","example":"She threaded a needle carefully before sewing the button back on.","exampleTranslation":"그녀는 단추를 다시 달기 전에 조심스럽게 바늘에 실을 꿰었어요.","level":29,"category":"빈도 학습"},{"id":13599,"term":"nightmare","meaning":"악몽; 끔찍한 경험","partOfSpeech":"n.","example":"The long traffic jam turned the commute into a nightmare.","exampleTranslation":"긴 교통 체증으로 인해 출퇴근길이 악몽으로 변했어요.","level":29,"category":"빈도 학습"},{"id":13600,"term":"noble","meaning":"고귀한; 숭고한","partOfSpeech":"adj.","example":"It was a noble gesture to donate all the prize money to charity.","exampleTranslation":"상금 전액을 자선단체에 기부한 것은 고귀한 행동이었어요.","level":29,"category":"빈도 학습"},{"id":13601,"term":"nonetheless","meaning":"그럼에도 불구하고; 그렇지만","partOfSpeech":"adv.","example":"The task was difficult; nonetheless, the team finished it on time.","exampleTranslation":"작업이 어려웠지만 그럼에도 불구하고 팀은 제시간에 마쳤어요.","level":29,"category":"빈도 학습"},{"id":13602,"term":"nonsense","meaning":"말도 안 되는 소리; 헛소리","partOfSpeech":"n.","example":"Stop talking nonsense and focus on solving the actual problem.","exampleTranslation":"말도 안 되는 소리 그만하고 실제 문제 해결에 집중하세요.","level":29,"category":"빈도 학습"},{"id":13603,"term":"noon","meaning":"정오; 낮 열두 시","partOfSpeech":"n.","example":"We agreed to meet at noon in front of the library.","exampleTranslation":"우리는 도서관 앞에서 정오에 만나기로 했어요.","level":29,"category":"빈도 학습"},{"id":13604,"term":"norm","meaning":"표준; 규범","partOfSpeech":"n.","example":"Working from home has become the norm for many companies.","exampleTranslation":"재택근무는 많은 기업에서 표준이 되었어요.","level":29,"category":"빈도 학습"},{"id":13605,"term":"notorious","meaning":"악명 높은; 나쁜 뜻으로 유명한","partOfSpeech":"adj.","example":"That intersection is notorious for causing accidents during rush hour.","exampleTranslation":"그 교차로는 출퇴근 시간에 사고를 일으키기로 악명 높아요.","level":29,"category":"빈도 학습"},{"id":13606,"term":"naught","meaning":"영(0); 무(無)","partOfSpeech":"n.","example":"All their hard work came to naught when the project was canceled.","exampleTranslation":"프로젝트가 취소되면서 그들의 노력이 모두 수포로 돌아갔어요.","level":29,"category":"빈도 학습"},{"id":13607,"term":"nursery","meaning":"보육원; 아이 방; 묘목장","partOfSpeech":"n.","example":"She painted the nursery walls a soft yellow before the baby arrived.","exampleTranslation":"아기가 태어나기 전에 그녀는 아이 방 벽을 부드러운 노란색으로 칠했어요.","level":29,"category":"빈도 학습"},{"id":13608,"term":"nutrition","meaning":"영양; 영양 섭취","partOfSpeech":"n.","example":"Good nutrition is essential for maintaining a healthy body and mind.","exampleTranslation":"올바른 영양 섭취는 건강한 몸과 마음을 유지하는 데 필수적이에요.","level":29,"category":"빈도 학습"},{"id":13609,"term":"obey","meaning":"따르다; 복종하다","partOfSpeech":"v.","example":"Drivers must obey all traffic laws to keep roads safe.","exampleTranslation":"운전자는 도로 안전을 위해 모든 교통 법규를 따라야 해요.","level":29,"category":"빈도 학습"},{"id":13610,"term":"obscure","meaning":"불분명한; 잘 알려지지 않은","partOfSpeech":"adj.","example":"The professor made an obscure reference that only experts understood.","exampleTranslation":"교수는 전문가들만 이해할 수 있는 불분명한 언급을 했어요.","level":29,"category":"빈도 학습"},{"id":13611,"term":"obsess","meaning":"집착하다; 사로잡히다","partOfSpeech":"v.","example":"It's unhealthy to obsess over every small mistake you make.","exampleTranslation":"자신이 저지른 사소한 실수 하나하나에 집착하는 것은 건강에 좋지 않아요.","level":29,"category":"빈도 학습"},{"id":13612,"term":"obstacle","meaning":"장애물; 방해물","partOfSpeech":"n.","example":"Lack of funding was the biggest obstacle to completing the research.","exampleTranslation":"자금 부족이 연구를 완료하는 데 가장 큰 장애물이었어요.","level":29,"category":"빈도 학습"},{"id":13613,"term":"obstruct","meaning":"막다; 방해하다","partOfSpeech":"v.","example":"Fallen trees obstruct the road after every major storm.","exampleTranslation":"큰 폭풍이 지나갈 때마다 쓰러진 나무들이 도로를 막아요.","level":29,"category":"빈도 학습"},{"id":13614,"term":"odor","meaning":"냄새; 기운","partOfSpeech":"n.","example":"A strange odor filled the kitchen when she opened the old refrigerator.","exampleTranslation":"그녀가 오래된 냉장고를 열었을 때 이상한 냄새가 주방에 가득 찼어요.","level":29,"category":"빈도 학습"},{"id":13615,"term":"offset","meaning":"상쇄하다; 벌충하다","partOfSpeech":"v.","example":"The company plants trees to offset its carbon emissions each year.","exampleTranslation":"그 회사는 매년 탄소 배출을 상쇄하기 위해 나무를 심어요.","level":29,"category":"빈도 학습"},{"id":13616,"term":"olive","meaning":"올리브; 올리브색","partOfSpeech":"n.","example":"She added a handful of olive slices to the salad for extra flavor.","exampleTranslation":"그녀는 풍미를 더하기 위해 샐러드에 올리브 슬라이스 한 줌을 넣었어요.","level":29,"category":"빈도 학습"},{"id":13617,"term":"omit","meaning":"빠뜨리다; 생략하다","partOfSpeech":"v.","example":"Be careful not to omit any required fields when filling out the form.","exampleTranslation":"양식을 작성할 때 필수 항목을 빠뜨리지 않도록 주의하세요.","level":29,"category":"빈도 학습"},{"id":13618,"term":"ongoing","meaning":"진행 중인; 계속되는","partOfSpeech":"adj.","example":"The ongoing investigation may take several more months to complete.","exampleTranslation":"진행 중인 조사는 완료하는 데 몇 달이 더 걸릴 수 있어요.","level":29,"category":"빈도 학습"},{"id":13619,"term":"oppress","meaning":"억압하다; 탄압하다","partOfSpeech":"v.","example":"Authoritarian governments often oppress citizens who speak out against them.","exampleTranslation":"권위주의 정부는 종종 자신들에게 반대 목소리를 내는 시민들을 억압해요.","level":29,"category":"빈도 학습"},{"id":13620,"term":"opt","meaning":"선택하다; 결정하다","partOfSpeech":"v.","example":"Many students opt to study abroad to improve their language skills.","exampleTranslation":"많은 학생들이 언어 실력을 향상시키기 위해 해외 유학을 선택해요.","level":29,"category":"빈도 학습"},{"id":13621,"term":"optic","meaning":"시각의; 눈과 관련된","partOfSpeech":"adj.","example":"The surgeon carefully examined the patient's optic nerve during the procedure.","exampleTranslation":"외과 의사는 시술 중 환자의 시신경을 주의 깊게 검사했어요.","level":29,"category":"빈도 학습"},{"id":13622,"term":"optimist","meaning":"낙관주의자; 긍정적인 사람","partOfSpeech":"n.","example":"As a true optimist, she always finds something positive in every situation.","exampleTranslation":"진정한 낙관주의자로서 그녀는 어떤 상황에서도 항상 긍정적인 면을 찾아요.","level":29,"category":"빈도 학습"},{"id":13623,"term":"orbit","meaning":"궤도; 공전하다","partOfSpeech":"n.","example":"The satellite was launched to orbit the Earth at a fixed altitude.","exampleTranslation":"그 위성은 일정한 고도에서 지구 궤도를 돌기 위해 발사되었어요.","level":29,"category":"빈도 학습"},{"id":13624,"term":"orchestra","meaning":"오케스트라; 관현악단","partOfSpeech":"n.","example":"The orchestra performed beautifully at the opening ceremony of the festival.","exampleTranslation":"오케스트라는 축제 개막식에서 아름다운 연주를 선보였어요.","level":29,"category":"빈도 학습"},{"id":13625,"term":"organism","meaning":"생물체; 유기체","partOfSpeech":"n.","example":"Every organism needs water to survive and carry out basic functions.","exampleTranslation":"모든 생물체는 살아남고 기본 기능을 수행하기 위해 물이 필요해요.","level":29,"category":"빈도 학습"},{"id":13626,"term":"originate","meaning":"시작되다; 비롯되다","partOfSpeech":"v.","example":"Many popular sports originate from ancient games played thousands of years ago.","exampleTranslation":"많은 인기 스포츠는 수천 년 전에 행해졌던 고대 게임에서 비롯돼요.","level":29,"category":"빈도 학습"},{"id":13627,"term":"orthodox","meaning":"정통적인; 전통적인","partOfSpeech":"adj.","example":"His orthodox approach to cooking follows classic recipes without any changes.","exampleTranslation":"그의 정통적인 요리 방식은 어떤 변형도 없이 고전 조리법을 따라요.","level":29,"category":"빈도 학습"},{"id":13628,"term":"ounce","meaning":"온스(무게 단위); 조금","partOfSpeech":"n.","example":"The recipe calls for exactly one ounce of dark chocolate per serving.","exampleTranslation":"그 레시피는 1인분에 정확히 다크 초콜릿 한 온스를 사용해요.","level":29,"category":"빈도 학습"},{"id":13629,"term":"outfit","meaning":"복장; 의상 한 벌","partOfSpeech":"n.","example":"She chose a casual outfit for the weekend trip to the mountains.","exampleTranslation":"그녀는 산으로 떠나는 주말 여행을 위해 캐주얼한 복장을 골랐어요.","level":29,"category":"빈도 학습"},{"id":13630,"term":"outlet","meaning":"배출구; 콘센트; 판매점","partOfSpeech":"n.","example":"Exercise is a healthy outlet for stress after a long workday.","exampleTranslation":"운동은 긴 근무일 후 스트레스를 해소하는 건강한 배출구예요.","level":29,"category":"빈도 학습"},{"id":13631,"term":"outlook","meaning":"전망; 시각; 견해","partOfSpeech":"n.","example":"The economic outlook for next year looks more promising than expected.","exampleTranslation":"내년 경제 전망은 예상보다 더 밝아 보여요.","level":29,"category":"빈도 학습"},{"id":13632,"term":"overhead","meaning":"머리 위의; 간접비","partOfSpeech":"adj.","example":"Please stow your bag in the overhead compartment before takeoff.","exampleTranslation":"이륙 전에 머리 위 수납공간에 가방을 넣어 주세요.","level":29,"category":"빈도 학습"},{"id":13633,"term":"overlap","meaning":"겹치다; 중복되다","partOfSpeech":"v.","example":"Our work schedules overlap on Wednesday afternoons so we can meet then.","exampleTranslation":"우리 업무 일정이 수요일 오후에 겹치니 그때 만날 수 있어요.","level":29,"category":"빈도 학습"},{"id":13634,"term":"overnight","meaning":"하룻밤 동안; 밤새","partOfSpeech":"adv.","example":"The temperature dropped overnight, so the roads were icy in the morning.","exampleTranslation":"기온이 밤새 떨어져서 아침에 도로가 얼어 있었어요.","level":29,"category":"빈도 학습"},{"id":13635,"term":"oversee","meaning":"감독하다; 관리하다","partOfSpeech":"v.","example":"The project manager will oversee all phases of the construction work.","exampleTranslation":"프로젝트 관리자가 건설 작업의 모든 단계를 감독할 것이에요.","level":29,"category":"빈도 학습"},{"id":13636,"term":"owl","meaning":"올빼미; 부엉이","partOfSpeech":"n.","example":"An owl sat silently on the branch and watched the forest below.","exampleTranslation":"올빼미 한 마리가 나뭇가지에 조용히 앉아 아래 숲을 바라봤어요.","level":29,"category":"빈도 학습"},{"id":13637,"term":"oxygen","meaning":"산소","partOfSpeech":"n.","example":"Plants produce oxygen through the process of photosynthesis during the day.","exampleTranslation":"식물은 낮 동안 광합성 과정을 통해 산소를 생산해요.","level":29,"category":"빈도 학습"},{"id":13638,"term":"ozone","meaning":"오존","partOfSpeech":"n.","example":"The ozone layer protects Earth from harmful ultraviolet radiation from the sun.","exampleTranslation":"오존층은 지구를 태양의 해로운 자외선으로부터 보호해요.","level":29,"category":"빈도 학습"},{"id":13639,"term":"packet","meaning":"소포; 꾸러미; 패킷","partOfSpeech":"n.","example":"She tore open the packet of sugar and stirred it into her coffee.","exampleTranslation":"그녀는 설탕 꾸러미를 뜯어 커피에 넣고 저었어요.","level":29,"category":"빈도 학습"},{"id":13640,"term":"parade","meaning":"퍼레이드; 행진","partOfSpeech":"n.","example":"The whole town gathered to watch the parade on Independence Day.","exampleTranslation":"독립기념일에 마을 전체가 퍼레이드를 보기 위해 모였어요.","level":29,"category":"빈도 학습"},{"id":13641,"term":"paradox","meaning":"역설; 모순","partOfSpeech":"n.","example":"It is a paradox that the busiest people often have more time for others.","exampleTranslation":"가장 바쁜 사람들이 오히려 다른 사람들을 위한 시간이 더 많다는 것은 역설이에요.","level":29,"category":"빈도 학습"},{"id":13642,"term":"parameter","meaning":"매개변수; 기준; 한계","partOfSpeech":"n.","example":"The engineer adjusted each parameter carefully to improve the system's performance.","exampleTranslation":"엔지니어는 시스템 성능을 향상시키기 위해 각 매개변수를 신중하게 조정했어요.","level":29,"category":"빈도 학습"},{"id":13643,"term":"particle","meaning":"입자; 미립자","partOfSpeech":"n.","example":"Scientists studied each particle of dust collected from the asteroid sample.","exampleTranslation":"과학자들은 소행성 샘플에서 수집한 먼지의 각 입자를 연구했어요.","level":29,"category":"빈도 학습"},{"id":13644,"term":"passive","meaning":"수동적인; 소극적인","partOfSpeech":"adj.","example":"A passive attitude at work can prevent you from getting promoted.","exampleTranslation":"직장에서 수동적인 태도는 승진을 방해할 수 있어요.","level":29,"category":"빈도 학습"},{"id":13645,"term":"patent","meaning":"특허; 특허권","partOfSpeech":"n.","example":"The inventor filed a patent to protect his new product from being copied.","exampleTranslation":"발명가는 새 제품이 복제되지 않도록 보호하기 위해 특허를 출원했어요.","level":29,"category":"빈도 학습"},{"id":13646,"term":"patience","meaning":"인내심; 참을성","partOfSpeech":"n.","example":"Teaching young children requires a great deal of patience and understanding.","exampleTranslation":"어린 아이들을 가르치는 데는 많은 인내심과 이해가 필요해요.","level":29,"category":"빈도 학습"},{"id":13647,"term":"patriot","meaning":"애국자; 나라를 사랑하는 사람","partOfSpeech":"n.","example":"Every patriot hopes to see their country prosper and live in peace.","exampleTranslation":"모든 애국자는 자신의 나라가 번영하고 평화롭게 살기를 바라요.","level":29,"category":"빈도 학습"},{"id":13648,"term":"patrol","meaning":"순찰하다; 순찰","partOfSpeech":"v.","example":"Security guards patrol the parking lot every hour throughout the night.","exampleTranslation":"경비원들은 밤새 매 시간마다 주차장을 순찰해요.","level":29,"category":"빈도 학습"},{"id":13649,"term":"patron","meaning":"후원자; 단골 고객","partOfSpeech":"n.","example":"A generous patron donated a large sum to support the local art museum.","exampleTranslation":"한 후원자가 지역 미술관을 지원하기 위해 큰 금액을 기부했어요.","level":29,"category":"빈도 학습"},{"id":13650,"term":"pearl","meaning":"진주; 귀중한 것","partOfSpeech":"n.","example":"She wore a necklace decorated with a single pearl.","exampleTranslation":"그녀는 진주 하나로 장식된 목걸이를 착용했어요.","level":29,"category":"빈도 학습"},{"id":13651,"term":"peculiar","meaning":"이상한; 독특한","partOfSpeech":"adj.","example":"There was a peculiar smell coming from the old building.","exampleTranslation":"오래된 건물에서 이상한 냄새가 났어요.","level":29,"category":"빈도 학습"},{"id":13652,"term":"peel","meaning":"껍질을 벗기다; 껍질","partOfSpeech":"v.","example":"Please peel the potatoes before you boil them.","exampleTranslation":"감자를 끓이기 전에 껍질을 벗겨 주세요.","level":29,"category":"빈도 학습"},{"id":13653,"term":"pencil","meaning":"연필","partOfSpeech":"n.","example":"She used a pencil to sketch the outline of the portrait.","exampleTranslation":"그녀는 연필로 초상화의 윤곽을 스케치했어요.","level":29,"category":"빈도 학습"},{"id":13654,"term":"penetrate","meaning":"침투하다; 꿰뚫다","partOfSpeech":"v.","example":"Sunlight can penetrate even thick clouds on a clear day.","exampleTranslation":"맑은 날에는 햇빛이 두꺼운 구름도 뚫고 들어올 수 있어요.","level":29,"category":"빈도 학습"},{"id":13655,"term":"periphery","meaning":"주변부; 외곽","partOfSpeech":"n.","example":"New housing developments are spreading to the periphery of the city.","exampleTranslation":"새로운 주택 개발이 도시 주변부로 퍼져나가고 있어요.","level":29,"category":"빈도 학습"},{"id":13656,"term":"petition","meaning":"청원; 청원서","partOfSpeech":"n.","example":"Residents signed a petition to stop the construction of the highway.","exampleTranslation":"주민들은 고속도로 건설을 막기 위해 청원서에 서명했어요.","level":29,"category":"빈도 학습"},{"id":13657,"term":"physician","meaning":"내과 의사; 의사","partOfSpeech":"n.","example":"The physician recommended rest and plenty of fluids for recovery.","exampleTranslation":"의사는 회복을 위해 휴식과 충분한 수분 섭취를 권장했어요.","level":29,"category":"빈도 학습"},{"id":13658,"term":"physics","meaning":"물리학","partOfSpeech":"n.","example":"She studied physics at university and now works as a researcher.","exampleTranslation":"그녀는 대학에서 물리학을 공부했고 지금은 연구원으로 일하고 있어요.","level":29,"category":"빈도 학습"},{"id":13659,"term":"pilgrim","meaning":"순례자; 성지 순례객","partOfSpeech":"n.","example":"Each pilgrim carried a walking stick along the long mountain trail.","exampleTranslation":"각 순례자는 긴 산길을 따라 지팡이를 들고 걸었어요.","level":29,"category":"빈도 학습"},{"id":13660,"term":"pill","meaning":"알약; 정제","partOfSpeech":"n.","example":"The doctor told him to take one pill every morning with water.","exampleTranslation":"의사가 그에게 매일 아침 물과 함께 알약 하나를 복용하라고 했어요.","level":29,"category":"빈도 학습"},{"id":13661,"term":"pillow","meaning":"베개","partOfSpeech":"n.","example":"She placed an extra pillow under her head to sleep comfortably.","exampleTranslation":"그녀는 편안하게 자기 위해 머리 아래에 베개를 하나 더 놓았어요.","level":29,"category":"빈도 학습"},{"id":13662,"term":"pinch","meaning":"꼬집다; 한 꼬집","partOfSpeech":"v.","example":"Add just a pinch of salt to improve the flavor of the soup.","exampleTranslation":"수프의 맛을 높이려면 소금을 한 꼬집만 넣으세요.","level":29,"category":"빈도 학습"},{"id":13663,"term":"pioneer","meaning":"개척자; 선구자","partOfSpeech":"n.","example":"She was a pioneer in the field of renewable energy research.","exampleTranslation":"그녀는 재생에너지 연구 분야의 선구자였어요.","level":29,"category":"빈도 학습"},{"id":13664,"term":"plague","meaning":"전염병; 역병","partOfSpeech":"n.","example":"The plague spread rapidly through the medieval towns of Europe.","exampleTranslation":"전염병이 유럽의 중세 도시들을 통해 빠르게 퍼져나갔어요.","level":29,"category":"빈도 학습"},{"id":13665,"term":"plaintiff","meaning":"원고; 고소인","partOfSpeech":"n.","example":"The plaintiff presented strong evidence to support the lawsuit.","exampleTranslation":"원고는 소송을 뒷받침하기 위해 강력한 증거를 제시했어요.","level":29,"category":"빈도 학습"},{"id":13666,"term":"plea","meaning":"탄원; 변론; 항변","partOfSpeech":"n.","example":"The lawyer submitted a plea of not guilty on behalf of her client.","exampleTranslation":"변호사는 의뢰인을 대신해 무죄 항변서를 제출했어요.","level":29,"category":"빈도 학습"},{"id":13667,"term":"plead","meaning":"탄원하다; 변호하다","partOfSpeech":"v.","example":"He decided to plead guilty and accept a reduced sentence.","exampleTranslation":"그는 유죄를 인정하고 감형된 형량을 받기로 했어요.","level":29,"category":"빈도 학습"},{"id":13668,"term":"pledge","meaning":"서약; 약속하다","partOfSpeech":"n.","example":"The new mayor made a pledge to improve public transportation in the city.","exampleTranslation":"새 시장은 도시의 대중교통을 개선하겠다는 서약을 했어요.","level":29,"category":"빈도 학습"},{"id":13669,"term":"plunge","meaning":"뛰어들다; 급락하다","partOfSpeech":"v.","example":"Stock prices plunge dramatically when investors lose confidence.","exampleTranslation":"투자자들이 신뢰를 잃으면 주가가 급격히 급락해요.","level":30,"category":"빈도 학습"},{"id":13670,"term":"plural","meaning":"복수(형)의; 복수","partOfSpeech":"adj.","example":"The plural form of 'child' is 'children' in English.","exampleTranslation":"영어에서 'child'의 복수형은 'children'이에요.","level":30,"category":"빈도 학습"},{"id":13671,"term":"poke","meaning":"찌르다; 쑤시다","partOfSpeech":"v.","example":"He used a stick to poke the fire and make it burn brighter.","exampleTranslation":"그는 막대기로 불을 쑤셔서 더 밝게 타오르게 했어요.","level":30,"category":"빈도 학습"},{"id":13672,"term":"polar","meaning":"극지의; 정반대의","partOfSpeech":"adj.","example":"Polar bears are perfectly adapted to survive in freezing temperatures.","exampleTranslation":"북극곰은 영하의 기온에서 살아남도록 완벽하게 적응되어 있어요.","level":30,"category":"빈도 학습"},{"id":13673,"term":"pond","meaning":"연못","partOfSpeech":"n.","example":"Children loved to feed the ducks swimming in the pond.","exampleTranslation":"아이들은 연못에서 헤엄치는 오리에게 먹이를 주는 것을 좋아했어요.","level":30,"category":"빈도 학습"},{"id":13674,"term":"pope","meaning":"교황","partOfSpeech":"n.","example":"The pope delivered a speech calling for peace across all nations.","exampleTranslation":"교황은 모든 나라에 평화를 촉구하는 연설을 했어요.","level":30,"category":"빈도 학습"},{"id":13675,"term":"portfolio","meaning":"포트폴리오; 작품집","partOfSpeech":"n.","example":"The designer shared her portfolio with the hiring manager during the interview.","exampleTranslation":"디자이너는 면접에서 채용 담당자에게 포트폴리오를 보여줬어요.","level":30,"category":"빈도 학습"},{"id":13676,"term":"portray","meaning":"묘사하다; 표현하다","partOfSpeech":"v.","example":"The film tries to portray the daily struggles of working-class families.","exampleTranslation":"그 영화는 노동자 계층 가정의 일상적인 어려움을 묘사하려고 해요.","level":30,"category":"빈도 학습"},{"id":13677,"term":"poster","meaning":"포스터; 벽보","partOfSpeech":"n.","example":"She hung a colorful poster of her favorite band on the bedroom wall.","exampleTranslation":"그녀는 침실 벽에 좋아하는 밴드의 화려한 포스터를 걸었어요.","level":30,"category":"빈도 학습"},{"id":13678,"term":"postpone","meaning":"연기하다; 미루다","partOfSpeech":"v.","example":"They had to postpone the outdoor concert due to heavy rain.","exampleTranslation":"폭우로 인해 야외 콘서트를 연기해야 했어요.","level":30,"category":"빈도 학습"},{"id":13679,"term":"preach","meaning":"설교하다; 전도하다","partOfSpeech":"v.","example":"The minister would preach about kindness and forgiveness every Sunday.","exampleTranslation":"목사는 매주 일요일 친절과 용서에 대해 설교했어요.","level":30,"category":"빈도 학습"},{"id":13680,"term":"precious","meaning":"소중한; 귀중한","partOfSpeech":"adj.","example":"Time with family is precious and should never be taken for granted.","exampleTranslation":"가족과 함께하는 시간은 소중하며 당연하게 여겨서는 안 돼요.","level":30,"category":"빈도 학습"},{"id":13681,"term":"predator","meaning":"포식자; 약탈자","partOfSpeech":"n.","example":"The lion is a fierce predator that hunts large animals on the savanna.","exampleTranslation":"사자는 사바나에서 큰 동물을 사냥하는 맹렬한 포식자예요.","level":30,"category":"빈도 학습"},{"id":13682,"term":"predecessor","meaning":"전임자; 이전 것","partOfSpeech":"n.","example":"The new CEO promised to continue the work started by her predecessor.","exampleTranslation":"새 최고경영자는 전임자가 시작한 일을 계속하겠다고 약속했어요.","level":30,"category":"빈도 학습"},{"id":13683,"term":"predominant","meaning":"지배적인; 주요한","partOfSpeech":"adj.","example":"English is the predominant language used in international business.","exampleTranslation":"영어는 국제 비즈니스에서 사용되는 지배적인 언어예요.","level":30,"category":"빈도 학습"},{"id":13684,"term":"prejudice","meaning":"편견; 선입견","partOfSpeech":"n.","example":"We must work together to overcome prejudice in our communities.","exampleTranslation":"우리 사회에서 편견을 극복하기 위해 함께 노력해야 해요.","level":30,"category":"빈도 학습"},{"id":13685,"term":"preliminary","meaning":"예비의; 준비의","partOfSpeech":"adj.","example":"The team conducted a preliminary survey before starting the main research.","exampleTranslation":"팀은 본 연구를 시작하기 전에 예비 설문 조사를 실시했어요.","level":30,"category":"빈도 학습"},{"id":13686,"term":"premier","meaning":"최고의; 수상","partOfSpeech":"adj.","example":"This hotel is recognized as the premier destination for luxury travelers.","exampleTranslation":"이 호텔은 고급 여행객들을 위한 최고의 목적지로 인정받고 있어요.","level":30,"category":"빈도 학습"},{"id":13687,"term":"premium","meaning":"프리미엄; 고급의","partOfSpeech":"adj.","example":"The store offers premium products made from only the finest materials.","exampleTranslation":"그 가게는 최고급 재료로만 만든 프리미엄 제품을 판매해요.","level":30,"category":"빈도 학습"},{"id":13688,"term":"preoccupy","meaning":"마음을 사로잡다; 몰두하게 하다","partOfSpeech":"v.","example":"Worries about the upcoming exam tend to preoccupy students during finals week.","exampleTranslation":"다가오는 시험에 대한 걱정이 기말고사 주간에 학생들의 마음을 사로잡는 경향이 있어요.","level":30,"category":"빈도 학습"},{"id":13689,"term":"prescribe","meaning":"처방하다; 규정하다","partOfSpeech":"v.","example":"The doctor decided to prescribe a mild antibiotic for the infection.","exampleTranslation":"의사는 감염 치료를 위해 가벼운 항생제를 처방하기로 했어요.","level":30,"category":"빈도 학습"},{"id":13690,"term":"prescription","meaning":"처방전; 처방","partOfSpeech":"n.","example":"You need a valid prescription from a doctor to buy this medication.","exampleTranslation":"이 약을 구입하려면 의사의 유효한 처방전이 필요해요.","level":30,"category":"빈도 학습"},{"id":13691,"term":"presidency","meaning":"대통령직; 의장직","partOfSpeech":"n.","example":"Her presidency was marked by significant economic reforms.","exampleTranslation":"그녀의 대통령직은 중요한 경제 개혁으로 특징지어졌어요.","level":30,"category":"빈도 학습"},{"id":13692,"term":"prestige","meaning":"위신; 명성","partOfSpeech":"n.","example":"Winning the award brought great prestige to the young scientist.","exampleTranslation":"그 상을 받는 것이 젊은 과학자에게 큰 명성을 가져다 주었어요.","level":30,"category":"빈도 학습"},{"id":13693,"term":"prevail","meaning":"우세하다; 만연하다","partOfSpeech":"v.","example":"Despite many challenges, justice will eventually prevail in a fair society.","exampleTranslation":"많은 어려움에도 불구하고, 공정한 사회에서 정의는 결국 우세하게 될 거예요.","level":30,"category":"빈도 학습"},{"id":13694,"term":"prevalent","meaning":"널리 퍼진; 흔한","partOfSpeech":"adj.","example":"Smartphone use among teenagers has become increasingly prevalent in recent years.","exampleTranslation":"최근 몇 년간 청소년들 사이에서 스마트폰 사용이 점점 더 널리 퍼지고 있어요.","level":30,"category":"빈도 학습"},{"id":13695,"term":"prey","meaning":"먹이; 희생자","partOfSpeech":"n.","example":"The eagle spotted its prey from high above and swooped down quickly.","exampleTranslation":"독수리는 높은 곳에서 먹이를 발견하고 빠르게 내려왔어요.","level":30,"category":"빈도 학습"},{"id":13696,"term":"primitive","meaning":"원시적인; 초기의","partOfSpeech":"adj.","example":"The archaeologists discovered primitive tools used by early humans.","exampleTranslation":"고고학자들이 초기 인류가 사용한 원시적인 도구를 발견했어요.","level":30,"category":"빈도 학습"},{"id":13697,"term":"privatize","meaning":"민영화하다","partOfSpeech":"v.","example":"The government decided to privatize the national airline to reduce costs.","exampleTranslation":"정부는 비용 절감을 위해 국영 항공사를 민영화하기로 결정했어요.","level":30,"category":"빈도 학습"},{"id":13698,"term":"proclaim","meaning":"선언하다; 공표하다","partOfSpeech":"v.","example":"The leader stood before the crowd to proclaim independence for the nation.","exampleTranslation":"지도자는 군중 앞에 서서 국가의 독립을 선언했어요.","level":30,"category":"빈도 학습"},{"id":13699,"term":"prolong","meaning":"연장하다; 늘리다","partOfSpeech":"v.","example":"Regular exercise can prolong your life and improve overall health.","exampleTranslation":"규칙적인 운동은 수명을 연장하고 전반적인 건강을 향상시킬 수 있어요.","level":30,"category":"빈도 학습"},{"id":13700,"term":"prop","meaning":"버팀대; 소품","partOfSpeech":"n.","example":"The workers used a wooden prop to support the old wall.","exampleTranslation":"작업자들은 낡은 벽을 지지하기 위해 나무 버팀대를 사용했다.","level":30,"category":"빈도 학습"},{"id":13701,"term":"proposition","meaning":"제안; 명제","partOfSpeech":"n.","example":"The manager made an interesting proposition to the whole team.","exampleTranslation":"팀장이 팀 전체에 흥미로운 제안을 했다.","level":30,"category":"빈도 학습"},{"id":13702,"term":"protocol","meaning":"규약; 절차","partOfSpeech":"n.","example":"Doctors must follow the correct protocol in every emergency.","exampleTranslation":"의사들은 모든 응급 상황에서 올바른 규약을 따라야 한다.","level":30,"category":"빈도 학습"},{"id":13703,"term":"publicity","meaning":"홍보; 대중의 주목","partOfSpeech":"n.","example":"The new movie received a lot of publicity before its release.","exampleTranslation":"그 새 영화는 개봉 전에 많은 홍보를 받았다.","level":30,"category":"빈도 학습"},{"id":13704,"term":"pulse","meaning":"맥박; 박동","partOfSpeech":"n.","example":"The nurse checked the patient's pulse every few hours.","exampleTranslation":"간호사는 몇 시간마다 환자의 맥박을 확인했다.","level":30,"category":"빈도 학습"},{"id":13705,"term":"pursuit","meaning":"추구; 추적","partOfSpeech":"n.","example":"Her pursuit of excellence made her one of the best scientists.","exampleTranslation":"탁월함에 대한 그녀의 추구가 그녀를 최고의 과학자 중 한 명으로 만들었다.","level":30,"category":"빈도 학습"},{"id":13706,"term":"questionnaire","meaning":"설문지; 질문지","partOfSpeech":"n.","example":"Please fill out this questionnaire before your appointment.","exampleTranslation":"예약 전에 이 설문지를 작성해 주세요.","level":30,"category":"빈도 학습"},{"id":13707,"term":"quota","meaning":"할당량; 몫","partOfSpeech":"n.","example":"Each salesperson must meet their monthly quota to earn a bonus.","exampleTranslation":"각 영업사원은 보너스를 받기 위해 월간 할당량을 달성해야 한다.","level":30,"category":"빈도 학습"},{"id":13708,"term":"rack","meaning":"선반; 걸이대","partOfSpeech":"n.","example":"She placed the wet clothes on the rack to dry.","exampleTranslation":"그녀는 젖은 옷을 선반 위에 올려 말렸다.","level":30,"category":"빈도 학습"},{"id":13709,"term":"ram","meaning":"세게 들이받다; 숫양","partOfSpeech":"v.","example":"The strong wind caused the boat to ram into the dock.","exampleTranslation":"강한 바람으로 인해 배가 부두에 세게 부딪혔다.","level":30,"category":"빈도 학습"},{"id":13710,"term":"ranger","meaning":"순찰대원; 산림 관리원","partOfSpeech":"n.","example":"The ranger patrolled the forest to protect the wildlife.","exampleTranslation":"산림 관리원이 야생동물을 보호하기 위해 숲을 순찰했다.","level":30,"category":"빈도 학습"},{"id":13711,"term":"rap","meaning":"두드리다; 랩 음악","partOfSpeech":"v.","example":"He began to rap on the door when no one answered.","exampleTranslation":"아무도 대답하지 않자 그는 문을 두드리기 시작했다.","level":30,"category":"빈도 학습"},{"id":13712,"term":"rattle","meaning":"덜거덕거리다; 당황하게 하다","partOfSpeech":"v.","example":"The old pipes tend to rattle whenever the heating turns on.","exampleTranslation":"난방이 켜질 때마다 낡은 파이프가 덜거덕거리는 경향이 있다.","level":30,"category":"빈도 학습"},{"id":13713,"term":"realm","meaning":"영역; 왕국","partOfSpeech":"n.","example":"This discovery opens a whole new realm of scientific research.","exampleTranslation":"이 발견은 과학 연구의 완전히 새로운 영역을 열어준다.","level":30,"category":"빈도 학습"},{"id":13714,"term":"recipient","meaning":"수령인; 수신자","partOfSpeech":"n.","example":"The recipient of the award gave a short speech on stage.","exampleTranslation":"수상자는 무대 위에서 짧은 연설을 했다.","level":30,"category":"빈도 학습"},{"id":13715,"term":"reconcile","meaning":"화해시키다; 조화시키다","partOfSpeech":"v.","example":"It was hard to reconcile their very different opinions on the plan.","exampleTranslation":"계획에 대한 그들의 매우 다른 의견을 조화시키기가 어려웠다.","level":30,"category":"빈도 학습"},{"id":13716,"term":"recreation","meaning":"오락; 여가 활동","partOfSpeech":"n.","example":"Hiking is a popular form of recreation for people of all ages.","exampleTranslation":"하이킹은 모든 연령대의 사람들에게 인기 있는 여가 활동이다.","level":30,"category":"빈도 학습"},{"id":13717,"term":"recur","meaning":"재발하다; 반복되다","partOfSpeech":"v.","example":"Headaches tend to recur when you do not drink enough water.","exampleTranslation":"물을 충분히 마시지 않으면 두통이 재발하는 경향이 있다.","level":30,"category":"빈도 학습"},{"id":13718,"term":"recycle","meaning":"재활용하다","partOfSpeech":"v.","example":"It is important to recycle paper and plastic to protect the environment.","exampleTranslation":"환경을 보호하기 위해 종이와 플라스틱을 재활용하는 것이 중요하다.","level":30,"category":"빈도 학습"},{"id":13719,"term":"refine","meaning":"정제하다; 개선하다","partOfSpeech":"v.","example":"The chef wanted to refine the recipe before serving it to guests.","exampleTranslation":"셰프는 손님에게 내놓기 전에 레시피를 개선하고 싶었다.","level":30,"category":"빈도 학습"},{"id":13720,"term":"refresh","meaning":"새로 고치다; 원기를 회복시키다","partOfSpeech":"v.","example":"A short walk outside can refresh your mind after long hours of work.","exampleTranslation":"잠깐 밖에서 걷는 것은 오랜 업무 후 정신을 새롭게 해줄 수 있다.","level":30,"category":"빈도 학습"},{"id":13721,"term":"regain","meaning":"되찾다; 회복하다","partOfSpeech":"v.","example":"After months of training, she was able to regain her strength.","exampleTranslation":"몇 달간의 훈련 끝에 그녀는 체력을 회복할 수 있었다.","level":30,"category":"빈도 학습"},{"id":13722,"term":"regress","meaning":"퇴보하다; 후퇴하다","partOfSpeech":"v.","example":"Without practice, language skills can regress over time.","exampleTranslation":"연습하지 않으면 언어 능력이 시간이 지남에 따라 퇴보할 수 있다.","level":30,"category":"빈도 학습"},{"id":13723,"term":"rehabilitate","meaning":"재활시키다; 복권시키다","partOfSpeech":"v.","example":"The program aims to rehabilitate young offenders through education.","exampleTranslation":"그 프로그램은 교육을 통해 청소년 범죄자를 재활시키는 것을 목표로 한다.","level":30,"category":"빈도 학습"},{"id":13724,"term":"rehearse","meaning":"연습하다; 리허설하다","partOfSpeech":"v.","example":"The actors rehearse their lines every day before the opening night.","exampleTranslation":"배우들은 개막 전날까지 매일 대사를 연습한다.","level":30,"category":"빈도 학습"},{"id":13725,"term":"reign","meaning":"통치하다; 지배하다","partOfSpeech":"v.","example":"Queen Victoria was able to reign over the British Empire for decades.","exampleTranslation":"빅토리아 여왕은 수십 년 동안 대영제국을 통치할 수 있었다.","level":30,"category":"빈도 학습"},{"id":13726,"term":"relevance","meaning":"관련성; 적절성","partOfSpeech":"n.","example":"The teacher questioned the relevance of that example to the lesson.","exampleTranslation":"선생님은 그 예시가 수업과 얼마나 관련이 있는지 의문을 제기했다.","level":30,"category":"빈도 학습"},{"id":13727,"term":"repay","meaning":"갚다; 보답하다","partOfSpeech":"v.","example":"He promised to repay the loan within one year.","exampleTranslation":"그는 1년 안에 대출금을 갚겠다고 약속했다.","level":30,"category":"빈도 학습"},{"id":13728,"term":"repress","meaning":"억압하다; 억누르다","partOfSpeech":"v.","example":"It is unhealthy to repress your emotions for a long time.","exampleTranslation":"오랫동안 감정을 억누르는 것은 건강에 좋지 않다.","level":30,"category":"빈도 학습"},{"id":13729,"term":"resent","meaning":"분개하다; 억울하게 여기다","partOfSpeech":"v.","example":"She began to resent her coworker for taking credit for her work.","exampleTranslation":"그녀는 자신의 공을 가로챈 동료에게 분개하기 시작했다.","level":30,"category":"빈도 학습"},{"id":13730,"term":"residue","meaning":"잔여물; 찌꺼기","partOfSpeech":"n.","example":"There was a sticky residue left on the pan after cooking.","exampleTranslation":"요리 후 팬에 끈적한 잔여물이 남아 있었다.","level":30,"category":"빈도 학습"},{"id":13731,"term":"retrieve","meaning":"되찾다; 검색하다","partOfSpeech":"v.","example":"The dog was trained to retrieve items thrown by its owner.","exampleTranslation":"그 개는 주인이 던진 물건을 되가져오도록 훈련받았다.","level":30,"category":"빈도 학습"},{"id":13732,"term":"rhetoric","meaning":"수사학; 미사여구","partOfSpeech":"n.","example":"The politician's speech was full of clever rhetoric but lacked real solutions.","exampleTranslation":"그 정치인의 연설은 교묘한 수사로 가득 차 있었지만 실질적인 해결책이 없었다.","level":30,"category":"빈도 학습"},{"id":13733,"term":"rib","meaning":"갈비뼈; 늑골","partOfSpeech":"n.","example":"He broke a rib during the football game last weekend.","exampleTranslation":"그는 지난 주말 풋볼 경기 중에 갈비뼈가 부러졌다.","level":30,"category":"빈도 학습"},{"id":13734,"term":"ridge","meaning":"산등성이; 능선","partOfSpeech":"n.","example":"The hikers stopped to rest on the ridge and enjoy the view.","exampleTranslation":"등산객들은 능선에서 쉬면서 경치를 감상하기 위해 멈췄다.","level":30,"category":"빈도 학습"},{"id":13735,"term":"rifle","meaning":"소총; 라이플","partOfSpeech":"n.","example":"The soldier carefully cleaned his rifle after the training exercise.","exampleTranslation":"군인은 훈련 후 소총을 조심스럽게 청소했다.","level":30,"category":"빈도 학습"},{"id":13736,"term":"rigid","meaning":"딱딱한; 엄격한","partOfSpeech":"adj.","example":"The rigid plastic casing protected the phone from serious damage.","exampleTranslation":"딱딱한 플라스틱 케이스가 휴대폰을 심각한 손상으로부터 보호했다.","level":30,"category":"빈도 학습"},{"id":13737,"term":"rigor","meaning":"엄격함; 철저함","partOfSpeech":"n.","example":"The professor is known for the rigor of her academic standards.","exampleTranslation":"그 교수는 학문적 기준의 엄격함으로 알려져 있다.","level":30,"category":"빈도 학습"},{"id":13738,"term":"riot","meaning":"폭동; 소란","partOfSpeech":"n.","example":"A riot broke out in the city after the controversial decision was announced.","exampleTranslation":"논란이 된 결정이 발표된 후 도시에서 폭동이 일어났다.","level":30,"category":"빈도 학습"},{"id":13739,"term":"roast","meaning":"굽다; 로스트하다","partOfSpeech":"v.","example":"They decided to roast the vegetables in the oven for dinner.","exampleTranslation":"그들은 저녁 식사를 위해 오븐에서 채소를 굽기로 결정했다.","level":30,"category":"빈도 학습"},{"id":13740,"term":"robot","meaning":"로봇; 자동 기계","partOfSpeech":"n.","example":"The factory uses a robot to assemble car parts with great precision.","exampleTranslation":"공장은 로봇을 사용하여 자동차 부품을 매우 정밀하게 조립한다.","level":30,"category":"빈도 학습"},{"id":13741,"term":"rocket","meaning":"로켓; 급등하다","partOfSpeech":"n.","example":"Scientists launched a rocket to carry supplies to the space station.","exampleTranslation":"과학자들은 우주 정거장에 물자를 운반하기 위해 로켓을 발사했다.","level":30,"category":"빈도 학습"},{"id":13742,"term":"rod","meaning":"막대기; 낚싯대","partOfSpeech":"n.","example":"He spent the afternoon by the river with a rod and some bait.","exampleTranslation":"그는 낚싯대와 미끼를 가지고 오후를 강가에서 보냈다.","level":30,"category":"빈도 학습"},{"id":13743,"term":"romance","meaning":"로맨스; 낭만","partOfSpeech":"n.","example":"Their romance began when they met during a vacation in Paris.","exampleTranslation":"그들의 로맨스는 파리 여행 중에 만났을 때 시작되었다.","level":30,"category":"빈도 학습"},{"id":13744,"term":"rose","meaning":"장미","partOfSpeech":"n.","example":"He gave her a single red rose on Valentine's Day.","exampleTranslation":"그는 발렌타인 데이에 그녀에게 빨간 장미 한 송이를 주었다.","level":30,"category":"빈도 학습"},{"id":13745,"term":"rotate","meaning":"회전하다; 순환하다","partOfSpeech":"v.","example":"You should rotate your tires every six months to extend their life.","exampleTranslation":"타이어 수명을 늘리려면 6개월마다 타이어를 교체해야 한다.","level":30,"category":"빈도 학습"},{"id":13746,"term":"rubber","meaning":"고무; 지우개","partOfSpeech":"n.","example":"The gloves are made of rubber to protect workers from chemicals.","exampleTranslation":"장갑은 작업자를 화학물질로부터 보호하기 위해 고무로 만들어졌다.","level":30,"category":"빈도 학습"},{"id":13747,"term":"rug","meaning":"깔개; 러그","partOfSpeech":"n.","example":"She placed a colorful rug in the center of the living room.","exampleTranslation":"그녀는 거실 중앙에 색깔 있는 깔개를 깔았다.","level":30,"category":"빈도 학습"},{"id":13748,"term":"sack","meaning":"자루; 해고하다","partOfSpeech":"n.","example":"The farmer carried a heavy sack of potatoes from the field.","exampleTranslation":"농부는 밭에서 무거운 감자 자루를 날랐다.","level":30,"category":"빈도 학습"},{"id":13749,"term":"sacred","meaning":"신성한; 거룩한","partOfSpeech":"adj.","example":"This temple is considered sacred by millions of people around the world.","exampleTranslation":"이 사원은 전 세계 수백만 명의 사람들에게 신성한 곳으로 여겨진다.","level":30,"category":"빈도 학습"},{"id":13750,"term":"salmon","meaning":"연어; 연어 살색","partOfSpeech":"n.","example":"She ordered grilled salmon with vegetables for dinner.","exampleTranslation":"그녀는 저녁 식사로 구운 연어와 채소를 주문했습니다.","level":30,"category":"빈도 학습"},{"id":13751,"term":"sane","meaning":"정신이 온전한; 분별 있는","partOfSpeech":"adj.","example":"Staying sane during a crisis requires good coping strategies.","exampleTranslation":"위기 상황에서 정신을 온전히 유지하려면 좋은 대처 전략이 필요합니다.","level":30,"category":"빈도 학습"},{"id":13752,"term":"satisfactory","meaning":"만족스러운; 충분한","partOfSpeech":"adj.","example":"The inspector gave a satisfactory rating to the restaurant.","exampleTranslation":"검사관은 그 식당에 만족스러운 등급을 부여했습니다.","level":30,"category":"빈도 학습"},{"id":13753,"term":"savage","meaning":"야만적인; 잔인한","partOfSpeech":"adj.","example":"The documentary showed the savage behavior of some predators.","exampleTranslation":"그 다큐멘터리는 일부 포식자들의 야만적인 행동을 보여주었습니다.","level":30,"category":"빈도 학습"},{"id":13754,"term":"scar","meaning":"흉터; 상처 자국","partOfSpeech":"n.","example":"He has a small scar on his chin from a childhood accident.","exampleTranslation":"그는 어린 시절 사고로 생긴 작은 흉터가 턱에 있습니다.","level":30,"category":"빈도 학습"},{"id":13755,"term":"scarce","meaning":"부족한; 드문","partOfSpeech":"adj.","example":"Clean drinking water is scarce in many parts of the world.","exampleTranslation":"깨끗한 식수는 세계 많은 지역에서 부족합니다.","level":30,"category":"빈도 학습"},{"id":13756,"term":"scenario","meaning":"시나리오; 상황 전개","partOfSpeech":"n.","example":"The team prepared for the worst-case scenario before launching the product.","exampleTranslation":"팀은 제품 출시 전에 최악의 시나리오에 대비했습니다.","level":30,"category":"빈도 학습"},{"id":13757,"term":"scent","meaning":"향기; 냄새","partOfSpeech":"n.","example":"The scent of fresh flowers filled the entire room.","exampleTranslation":"신선한 꽃향기가 방 전체를 가득 채웠습니다.","level":30,"category":"빈도 학습"},{"id":13758,"term":"skeptic","meaning":"회의론자; 의심하는 사람","partOfSpeech":"n.","example":"Even a skeptic can change their mind when faced with strong evidence.","exampleTranslation":"강력한 증거를 접하면 회의론자도 마음을 바꿀 수 있습니다.","level":31,"category":"빈도 학습"},{"id":13759,"term":"scholarship","meaning":"장학금; 학문적 업적","partOfSpeech":"n.","example":"She received a full scholarship to study at the university.","exampleTranslation":"그녀는 그 대학교에서 공부할 수 있는 전액 장학금을 받았습니다.","level":30,"category":"빈도 학습"},{"id":13760,"term":"scout","meaning":"정찰하다; 탐색하다","partOfSpeech":"v.","example":"The coach sent assistants to scout talented players at local games.","exampleTranslation":"감독은 지역 경기에서 재능 있는 선수들을 발굴하려고 보조 코치를 보냈습니다.","level":30,"category":"빈도 학습"},{"id":13761,"term":"scramble","meaning":"서둘러 움직이다; 뒤엉키다","partOfSpeech":"v.","example":"Students scramble for seats when the popular professor enters the hall.","exampleTranslation":"인기 있는 교수가 강당에 들어오면 학생들이 자리를 차지하려고 서둘러 움직입니다.","level":30,"category":"빈도 학습"},{"id":13762,"term":"scrap","meaning":"폐기하다; 조각","partOfSpeech":"v.","example":"The company decided to scrap the outdated machinery and buy new equipment.","exampleTranslation":"회사는 구식 기계를 폐기하고 새 장비를 구입하기로 결정했습니다.","level":30,"category":"빈도 학습"},{"id":13763,"term":"scrape","meaning":"긁다; 긁어내다","partOfSpeech":"v.","example":"He used a spatula to scrape the burnt bits off the pan.","exampleTranslation":"그는 주걱으로 냄비에 눌어붙은 부분을 긁어냈습니다.","level":30,"category":"빈도 학습"},{"id":13764,"term":"script","meaning":"대본; 원고","partOfSpeech":"n.","example":"The actor memorized the entire script before rehearsals began.","exampleTranslation":"그 배우는 리허설이 시작되기 전에 대본 전체를 암기했습니다.","level":30,"category":"빈도 학습"},{"id":13765,"term":"scrutiny","meaning":"철저한 검사; 면밀한 조사","partOfSpeech":"n.","example":"The new policy came under intense scrutiny from the public.","exampleTranslation":"새로운 정책은 대중의 철저한 검사를 받게 되었습니다.","level":30,"category":"빈도 학습"},{"id":13766,"term":"secular","meaning":"세속적인; 종교와 무관한","partOfSpeech":"adj.","example":"The country's education system is entirely secular and religion-neutral.","exampleTranslation":"그 나라의 교육 제도는 완전히 세속적이며 종교 중립적입니다.","level":30,"category":"빈도 학습"},{"id":13767,"term":"seldom","meaning":"거의 ~하지 않는; 드물게","partOfSpeech":"adv.","example":"She seldom eats fast food because she prefers home-cooked meals.","exampleTranslation":"그녀는 집에서 요리한 음식을 선호하기 때문에 패스트푸드를 거의 먹지 않습니다.","level":30,"category":"빈도 학습"},{"id":13768,"term":"seminar","meaning":"세미나; 소규모 토론 수업","partOfSpeech":"n.","example":"The professor held a seminar on environmental policy every Thursday.","exampleTranslation":"교수는 매주 목요일 환경 정책에 관한 세미나를 개최했습니다.","level":30,"category":"빈도 학습"},{"id":13769,"term":"senator","meaning":"상원 의원","partOfSpeech":"n.","example":"The senator proposed a bill to improve public transportation funding.","exampleTranslation":"그 상원 의원은 대중교통 자금을 개선하기 위한 법안을 제안했습니다.","level":30,"category":"빈도 학습"},{"id":13770,"term":"sensation","meaning":"감각; 느낌; 선풍적 인기","partOfSpeech":"n.","example":"He felt a warm sensation in his hands after holding the hot mug.","exampleTranslation":"그는 뜨거운 머그컵을 쥔 후 손에 따뜻한 감각을 느꼈습니다.","level":30,"category":"빈도 학습"},{"id":13771,"term":"sentencing","meaning":"선고; 판결 선언","partOfSpeech":"n.","example":"The judge postponed the sentencing hearing until next month.","exampleTranslation":"판사는 선고 공판을 다음 달로 연기했습니다.","level":30,"category":"빈도 학습"},{"id":13772,"term":"sentiment","meaning":"감정; 정서; 견해","partOfSpeech":"n.","example":"Public sentiment toward the new tax law shifted dramatically after the announcement.","exampleTranslation":"발표 후 새로운 세법에 대한 대중의 감정이 극적으로 바뀌었습니다.","level":30,"category":"빈도 학습"},{"id":13773,"term":"sergeant","meaning":"하사; 경찰 경사","partOfSpeech":"n.","example":"The sergeant briefed the squad before sending them into the field.","exampleTranslation":"하사는 분대를 현장에 투입하기 전에 브리핑을 했습니다.","level":30,"category":"빈도 학습"},{"id":13774,"term":"shaft","meaning":"축; 통로; 빛줄기","partOfSpeech":"n.","example":"A shaft of sunlight came through the narrow window of the old church.","exampleTranslation":"오래된 교회의 좁은 창문을 통해 한 줄기 햇빛이 들어왔습니다.","level":30,"category":"빈도 학습"},{"id":13775,"term":"shallow","meaning":"얕은; 피상적인","partOfSpeech":"adj.","example":"The children waded in the shallow end of the pool.","exampleTranslation":"아이들은 수영장의 얕은 쪽에서 물속을 걸어다녔습니다.","level":30,"category":"빈도 학습"},{"id":13776,"term":"shatter","meaning":"산산조각 내다; 박살내다","partOfSpeech":"v.","example":"A rock thrown by a passing car can shatter a windshield instantly.","exampleTranslation":"지나가는 차가 던진 돌멩이는 순식간에 앞 유리를 산산조각 낼 수 있습니다.","level":30,"category":"빈도 학습"},{"id":13777,"term":"sheer","meaning":"순전한; 완전한; 가파른","partOfSpeech":"adj.","example":"The team succeeded through sheer determination and hard work.","exampleTranslation":"그 팀은 순전한 결단력과 노력으로 성공했습니다.","level":31,"category":"빈도 학습"},{"id":13778,"term":"sheriff","meaning":"보안관; 지방 치안관","partOfSpeech":"n.","example":"The sheriff arrived at the scene before any other law enforcement.","exampleTranslation":"보안관은 다른 어떤 법 집행관보다 먼저 현장에 도착했습니다.","level":31,"category":"빈도 학습"},{"id":13779,"term":"shrink","meaning":"줄어들다; 수축하다","partOfSpeech":"v.","example":"Wool sweaters tend to shrink if you wash them in hot water.","exampleTranslation":"울 스웨터는 뜨거운 물에 세탁하면 줄어드는 경향이 있습니다.","level":31,"category":"빈도 학습"},{"id":13780,"term":"signature","meaning":"서명; 특징적인 것","partOfSpeech":"n.","example":"Please write your signature at the bottom of the contract.","exampleTranslation":"계약서 하단에 서명을 해 주세요.","level":31,"category":"빈도 학습"},{"id":13781,"term":"simulate","meaning":"모의 실험하다; 흉내 내다","partOfSpeech":"v.","example":"Engineers use software to simulate the effects of extreme weather on buildings.","exampleTranslation":"엔지니어들은 소프트웨어를 사용하여 건물에 대한 극한 날씨의 영향을 모의 실험합니다.","level":31,"category":"빈도 학습"},{"id":13782,"term":"sincere","meaning":"진심 어린; 성실한","partOfSpeech":"adj.","example":"Her sincere apology helped to restore trust between them.","exampleTranslation":"그녀의 진심 어린 사과는 그들 사이의 신뢰를 회복하는 데 도움이 되었습니다.","level":31,"category":"빈도 학습"},{"id":13783,"term":"sip","meaning":"홀짝이다; 조금씩 마시다","partOfSpeech":"v.","example":"She sat by the window and began to sip her morning coffee slowly.","exampleTranslation":"그녀는 창가에 앉아 아침 커피를 천천히 홀짝이기 시작했습니다.","level":31,"category":"빈도 학습"},{"id":13784,"term":"sketch","meaning":"스케치하다; 대략 그리다","partOfSpeech":"v.","example":"The artist would sketch faces of strangers at the park every weekend.","exampleTranslation":"그 예술가는 매주 주말 공원에서 낯선 사람들의 얼굴을 스케치하곤 했습니다.","level":31,"category":"빈도 학습"},{"id":13785,"term":"skip","meaning":"건너뛰다; 빠뜨리다","partOfSpeech":"v.","example":"Students who skip class often miss important information.","exampleTranslation":"수업을 빠뜨리는 학생들은 중요한 정보를 놓치는 경우가 많습니다.","level":31,"category":"빈도 학습"},{"id":13786,"term":"skull","meaning":"두개골; 해골","partOfSpeech":"n.","example":"The pirate flag traditionally shows a skull and crossbones symbol.","exampleTranslation":"해적 깃발에는 전통적으로 두개골과 교차 뼈 기호가 그려져 있습니다.","level":31,"category":"빈도 학습"},{"id":13787,"term":"slam","meaning":"쾅 닫다; 세게 치다","partOfSpeech":"v.","example":"He was so angry that he chose to slam the door on his way out.","exampleTranslation":"그는 너무 화가 나서 나가면서 문을 쾅 닫았습니다.","level":31,"category":"빈도 학습"},{"id":13788,"term":"slap","meaning":"찰싹 때리다; 손바닥으로 치다","partOfSpeech":"v.","example":"She had to slap the mosquito on her arm before it could bite.","exampleTranslation":"그녀는 모기가 물기 전에 팔에 앉은 모기를 찰싹 때려야 했습니다.","level":31,"category":"빈도 학습"},{"id":13789,"term":"sleeve","meaning":"소매","partOfSpeech":"n.","example":"He rolled up his sleeve to show the nurse where to draw blood.","exampleTranslation":"그는 간호사에게 채혈 부위를 보여주려고 소매를 걷어올렸습니다.","level":31,"category":"빈도 학습"},{"id":13790,"term":"slim","meaning":"날씬한; 가느다란; 희박한","partOfSpeech":"adj.","example":"The chances of winning the lottery are very slim.","exampleTranslation":"복권에 당첨될 확률은 매우 희박합니다.","level":31,"category":"빈도 학습"},{"id":13791,"term":"slot","meaning":"홈; 빈자리; 시간대","partOfSpeech":"n.","example":"Insert the coin into the slot to start the vending machine.","exampleTranslation":"자동 판매기를 작동시키려면 동전을 홈에 넣으세요.","level":31,"category":"빈도 학습"},{"id":13792,"term":"slump","meaning":"급락하다; 불황","partOfSpeech":"v.","example":"Sales figures tend to slump during the slow winter months.","exampleTranslation":"매출 수치는 겨울 비수기에 급락하는 경향이 있습니다.","level":31,"category":"빈도 학습"},{"id":13793,"term":"snatch","meaning":"낚아채다; 갑자기 잡다","partOfSpeech":"v.","example":"The goalkeeper managed to snatch the ball before it crossed the line.","exampleTranslation":"골키퍼는 공이 라인을 넘기 전에 낚아채는 데 성공했습니다.","level":31,"category":"빈도 학습"},{"id":13794,"term":"soak","meaning":"적시다; 흠뻑 젖게 하다","partOfSpeech":"v.","example":"You should soak the dried beans overnight before cooking them.","exampleTranslation":"말린 콩은 요리하기 전에 하룻밤 물에 불려야 합니다.","level":31,"category":"빈도 학습"},{"id":13795,"term":"soap","meaning":"비누","partOfSpeech":"n.","example":"Always use soap and warm water to wash your hands properly.","exampleTranslation":"손을 제대로 씻으려면 항상 비누와 따뜻한 물을 사용하세요.","level":31,"category":"빈도 학습"},{"id":13796,"term":"soar","meaning":"치솟다; 높이 날다","partOfSpeech":"v.","example":"Real estate prices tend to soar in popular urban neighborhoods.","exampleTranslation":"인기 있는 도심 지역에서 부동산 가격은 치솟는 경향이 있습니다.","level":31,"category":"빈도 학습"},{"id":13797,"term":"soccer","meaning":"축구","partOfSpeech":"n.","example":"Millions of children around the world play soccer every day.","exampleTranslation":"전 세계 수백만 명의 어린이들이 매일 축구를 합니다.","level":31,"category":"빈도 학습"},{"id":13798,"term":"socialist","meaning":"사회주의자; 사회주의의","partOfSpeech":"n.","example":"The politician described himself as a democratic socialist during the debate.","exampleTranslation":"그 정치인은 토론에서 자신을 민주적 사회주의자라고 소개했습니다.","level":31,"category":"빈도 학습"},{"id":13799,"term":"sociology","meaning":"사회학","partOfSpeech":"n.","example":"She chose to study sociology to better understand human behavior in groups.","exampleTranslation":"그녀는 집단 내 인간 행동을 더 잘 이해하기 위해 사회학을 공부하기로 선택했습니다.","level":31,"category":"빈도 학습"},{"id":13800,"term":"sodium","meaning":"나트륨; 소듐","partOfSpeech":"n.","example":"Too much sodium in your diet can raise blood pressure.","exampleTranslation":"식단에서 나트륨을 너무 많이 섭취하면 혈압이 올라갈 수 있어요.","level":31,"category":"빈도 학습"},{"id":13801,"term":"solar","meaning":"태양의; 태양 에너지의","partOfSpeech":"adj.","example":"Many homes now use solar panels to generate electricity.","exampleTranslation":"많은 가정에서 이제 태양 전지판을 사용해 전기를 생산해요.","level":31,"category":"빈도 학습"},{"id":13802,"term":"solo","meaning":"혼자의; 독주(독창)의","partOfSpeech":"adj.","example":"She went on a solo trip around Europe last summer.","exampleTranslation":"그녀는 지난 여름 유럽을 혼자 여행했어요.","level":31,"category":"빈도 학습"},{"id":13803,"term":"span","meaning":"기간; 범위","partOfSpeech":"n.","example":"The project will span three years from start to finish.","exampleTranslation":"이 프로젝트는 시작부터 끝까지 3년에 걸쳐 진행될 거예요.","level":31,"category":"빈도 학습"},{"id":13804,"term":"spark","meaning":"불꽃; 자극하다","partOfSpeech":"n.","example":"A small spark from the campfire landed on the dry leaves.","exampleTranslation":"캠프파이어에서 작은 불꽃이 마른 나뭇잎 위로 떨어졌어요.","level":31,"category":"빈도 학습"},{"id":13805,"term":"sparkle","meaning":"반짝이다; 빛나다","partOfSpeech":"v.","example":"The diamonds sparkle under the bright showroom lights.","exampleTranslation":"다이아몬드들이 밝은 쇼룸 조명 아래서 반짝여요.","level":31,"category":"빈도 학습"},{"id":13806,"term":"spatial","meaning":"공간의; 공간적인","partOfSpeech":"adj.","example":"Good spatial awareness helps drivers park in tight spots.","exampleTranslation":"공간 감각이 좋으면 좁은 공간에 주차하는 데 도움이 돼요.","level":31,"category":"빈도 학습"},{"id":13807,"term":"specimen","meaning":"표본; 샘플","partOfSpeech":"n.","example":"The scientist preserved a rare specimen of the butterfly in a glass case.","exampleTranslation":"과학자가 희귀한 나비 표본을 유리 상자에 보존했어요.","level":31,"category":"빈도 학습"},{"id":13808,"term":"spectacle","meaning":"장관; 볼거리","partOfSpeech":"n.","example":"The fireworks display was a breathtaking spectacle for everyone.","exampleTranslation":"불꽃놀이는 모두에게 숨이 멎을 듯한 장관이었어요.","level":31,"category":"빈도 학습"},{"id":13809,"term":"spectacular","meaning":"장관을 이루는; 눈부신","partOfSpeech":"adj.","example":"The view from the mountain top was truly spectacular.","exampleTranslation":"산 정상에서 바라본 경치는 정말 장관이었어요.","level":31,"category":"빈도 학습"},{"id":13810,"term":"spectrum","meaning":"스펙트럼; 범위","partOfSpeech":"n.","example":"The spectrum of opinions on this topic is surprisingly wide.","exampleTranslation":"이 주제에 대한 의견의 스펙트럼은 놀랄 만큼 넓어요.","level":31,"category":"빈도 학습"},{"id":13811,"term":"sphere","meaning":"구; 영역","partOfSpeech":"n.","example":"The Earth is not a perfect sphere but is slightly flattened at the poles.","exampleTranslation":"지구는 완전한 구가 아니라 극 부분이 약간 납작해요.","level":31,"category":"빈도 학습"},{"id":13812,"term":"spice","meaning":"향신료; 양념","partOfSpeech":"n.","example":"She added a pinch of spice to give the soup more flavor.","exampleTranslation":"그녀는 수프에 풍미를 더하기 위해 향신료를 조금 넣었어요.","level":31,"category":"빈도 학습"},{"id":13813,"term":"spike","meaning":"급등; 뾰족한 끝","partOfSpeech":"n.","example":"There was a sudden spike in electricity demand during the heat wave.","exampleTranslation":"폭염 기간 동안 전력 수요가 갑자기 급등했어요.","level":31,"category":"빈도 학습"},{"id":13814,"term":"spine","meaning":"척추; 등뼈","partOfSpeech":"n.","example":"Sitting at a desk all day can put strain on the spine.","exampleTranslation":"하루 종일 책상에 앉아 있으면 척추에 무리가 갈 수 있어요.","level":31,"category":"빈도 학습"},{"id":13815,"term":"spit","meaning":"침을 뱉다; 내뱉다","partOfSpeech":"v.","example":"It is rude to spit on the street in public places.","exampleTranslation":"공공장소에서 길에 침을 뱉는 것은 무례한 행동이에요.","level":31,"category":"빈도 학습"},{"id":13816,"term":"splash","meaning":"튀기다; 물보라","partOfSpeech":"v.","example":"The kids love to splash around in the pool on hot days.","exampleTranslation":"아이들은 더운 날 수영장에서 물을 튀기며 노는 걸 좋아해요.","level":31,"category":"빈도 학습"},{"id":13817,"term":"spontaneous","meaning":"자발적인; 즉흥적인","partOfSpeech":"adj.","example":"Their spontaneous decision to go camping turned into a great adventure.","exampleTranslation":"즉흥적으로 캠핑을 가기로 한 결정이 멋진 모험이 됐어요.","level":31,"category":"빈도 학습"},{"id":13818,"term":"spoon","meaning":"숟가락; 스푼","partOfSpeech":"n.","example":"Please use a clean spoon when you serve the soup.","exampleTranslation":"수프를 떠줄 때 깨끗한 숟가락을 사용하세요.","level":31,"category":"빈도 학습"},{"id":13819,"term":"spouse","meaning":"배우자","partOfSpeech":"n.","example":"Each employee may bring their spouse to the company dinner.","exampleTranslation":"각 직원은 회사 만찬에 배우자를 동반할 수 있어요.","level":31,"category":"빈도 학습"},{"id":13820,"term":"spur","meaning":"자극하다; 박차를 가하다","partOfSpeech":"v.","example":"A tight deadline can spur people to work more efficiently.","exampleTranslation":"촉박한 마감일은 사람들이 더 효율적으로 일하도록 자극할 수 있어요.","level":31,"category":"빈도 학습"},{"id":13821,"term":"spy","meaning":"스파이; 염탐하다","partOfSpeech":"n.","example":"The movie features a spy who works undercover in enemy territory.","exampleTranslation":"그 영화는 적지에서 위장 잠입하는 스파이를 주인공으로 해요.","level":31,"category":"빈도 학습"},{"id":13822,"term":"squad","meaning":"소대; 팀","partOfSpeech":"n.","example":"The soccer squad trained hard before the championship match.","exampleTranslation":"축구 팀은 챔피언십 경기 전에 열심히 훈련했어요.","level":31,"category":"빈도 학습"},{"id":13823,"term":"stab","meaning":"찌르다; 찌르는 행위","partOfSpeech":"v.","example":"He used a fork to stab the piece of meat on his plate.","exampleTranslation":"그는 포크로 접시 위의 고기 조각을 찔렀어요.","level":31,"category":"빈도 학습"},{"id":13824,"term":"stadium","meaning":"경기장; 스타디움","partOfSpeech":"n.","example":"Thousands of fans packed the stadium to watch the final game.","exampleTranslation":"수천 명의 팬이 결승전을 보기 위해 경기장을 가득 메웠어요.","level":31,"category":"빈도 학습"},{"id":13825,"term":"stagger","meaning":"비틀거리다; 충격을 주다","partOfSpeech":"v.","example":"The injured player began to stagger off the field after the collision.","exampleTranslation":"부상당한 선수가 충돌 후 비틀거리며 경기장을 빠져나가기 시작했어요.","level":31,"category":"빈도 학습"},{"id":13826,"term":"stall","meaning":"지연시키다; 노점","partOfSpeech":"v.","example":"The negotiators tried to stall for more time before signing.","exampleTranslation":"협상가들은 서명 전에 더 많은 시간을 벌기 위해 지연하려 했어요.","level":31,"category":"빈도 학습"},{"id":13827,"term":"stance","meaning":"입장; 자세","partOfSpeech":"n.","example":"The government took a firm stance against any form of corruption.","exampleTranslation":"정부는 어떠한 형태의 부패에도 단호한 입장을 취했어요.","level":31,"category":"빈도 학습"},{"id":13828,"term":"startle","meaning":"깜짝 놀라게 하다","partOfSpeech":"v.","example":"A loud clap of thunder can startle people who are indoors.","exampleTranslation":"큰 천둥소리는 실내에 있는 사람들을 깜짝 놀라게 할 수 있어요.","level":31,"category":"빈도 학습"},{"id":13829,"term":"statue","meaning":"조각상; 동상","partOfSpeech":"n.","example":"Tourists from around the world come to see the famous statue in the park.","exampleTranslation":"전 세계 관광객들이 공원의 유명한 동상을 보러 와요.","level":31,"category":"빈도 학습"},{"id":13830,"term":"steep","meaning":"가파른; 급격한","partOfSpeech":"adj.","example":"The hikers struggled to climb the steep mountain trail.","exampleTranslation":"등산객들은 가파른 산길을 오르느라 힘들었어요.","level":31,"category":"빈도 학습"},{"id":13831,"term":"steer","meaning":"조종하다; 이끌다","partOfSpeech":"v.","example":"The captain had to steer the ship carefully through the narrow channel.","exampleTranslation":"선장은 좁은 수로를 조심스럽게 배를 조종해야 했어요.","level":31,"category":"빈도 학습"},{"id":13832,"term":"stereotype","meaning":"고정관념; 틀에 박힌 생각","partOfSpeech":"n.","example":"We should challenge every stereotype rather than accept it without question.","exampleTranslation":"우리는 고정관념을 무비판적으로 받아들이기보다 도전해야 해요.","level":31,"category":"빈도 학습"},{"id":13833,"term":"stern","meaning":"엄격한; 단호한","partOfSpeech":"adj.","example":"The stern teacher rarely smiled during class but was fair to all students.","exampleTranslation":"엄격한 선생님은 수업 중에 거의 웃지 않았지만 모든 학생에게 공정했어요.","level":31,"category":"빈도 학습"},{"id":13834,"term":"stimulus","meaning":"자극; 동기 부여","partOfSpeech":"n.","example":"The government issued an economic stimulus to help businesses recover.","exampleTranslation":"정부는 기업 회복을 돕기 위해 경제 부양책을 내놓았어요.","level":31,"category":"빈도 학습"},{"id":13835,"term":"sting","meaning":"쏘다; 따끔하다","partOfSpeech":"v.","example":"A bee will sting you if it feels threatened or cornered.","exampleTranslation":"꿀벌은 위협을 받거나 궁지에 몰리면 쏠 거예요.","level":31,"category":"빈도 학습"},{"id":13836,"term":"stitch","meaning":"바느질하다; 꿰매다","partOfSpeech":"v.","example":"She learned to stitch fabric pieces together to make a quilt.","exampleTranslation":"그녀는 천 조각을 함께 꿰매 이불을 만드는 법을 배웠어요.","level":31,"category":"빈도 학습"},{"id":13837,"term":"straightforward","meaning":"간단한; 솔직한","partOfSpeech":"adj.","example":"The instructions were straightforward and easy for anyone to follow.","exampleTranslation":"설명서는 간단해서 누구나 따라 하기 쉬웠어요.","level":31,"category":"빈도 학습"},{"id":13838,"term":"strand","meaning":"가닥; 실","partOfSpeech":"n.","example":"She found a single strand of hair on the bathroom floor.","exampleTranslation":"그녀는 욕실 바닥에서 머리카락 한 가닥을 발견했어요.","level":31,"category":"빈도 학습"},{"id":13839,"term":"strap","meaning":"끈; 가죽 끈으로 묶다","partOfSpeech":"n.","example":"The bag has a long strap so you can carry it over your shoulder.","exampleTranslation":"그 가방에는 긴 끈이 있어 어깨에 메고 다닐 수 있어요.","level":31,"category":"빈도 학습"},{"id":13840,"term":"straw","meaning":"빨대; 짚","partOfSpeech":"n.","example":"He sipped his iced coffee through a paper straw.","exampleTranslation":"그는 종이 빨대로 아이스커피를 홀짝였어요.","level":31,"category":"빈도 학습"},{"id":13841,"term":"streak","meaning":"줄무늬; 연속","partOfSpeech":"n.","example":"The team is on a winning streak after five straight victories.","exampleTranslation":"팀은 5연승을 거두며 연승 행진 중이에요.","level":31,"category":"빈도 학습"},{"id":13842,"term":"stride","meaning":"성큼성큼 걷다; 진전","partOfSpeech":"v.","example":"He watched the athlete stride confidently toward the finish line.","exampleTranslation":"그는 선수가 결승선을 향해 자신감 있게 성큼성큼 걷는 것을 지켜봤어요.","level":31,"category":"빈도 학습"},{"id":13843,"term":"stripe","meaning":"줄무늬","partOfSpeech":"n.","example":"The zebra has a distinctive black and white stripe pattern.","exampleTranslation":"얼룩말은 독특한 흑백 줄무늬 무늬를 가지고 있어요.","level":31,"category":"빈도 학습"},{"id":13844,"term":"stroll","meaning":"산책하다; 거닐다","partOfSpeech":"v.","example":"They love to stroll along the riverbank after dinner.","exampleTranslation":"그들은 저녁 식사 후 강변을 따라 산책하는 것을 좋아해요.","level":31,"category":"빈도 학습"},{"id":13845,"term":"stumble","meaning":"비틀거리다; 우연히 발견하다","partOfSpeech":"v.","example":"Be careful not to stumble on the uneven pavement outside.","exampleTranslation":"밖에 울퉁불퉁한 포장도로에서 비틀거리지 않도록 조심하세요.","level":31,"category":"빈도 학습"},{"id":13846,"term":"subjective","meaning":"주관적인","partOfSpeech":"adj.","example":"Art appreciation is highly subjective and varies from person to person.","exampleTranslation":"예술 감상은 매우 주관적이며 사람마다 달라요.","level":31,"category":"빈도 학습"},{"id":13847,"term":"subordinate","meaning":"하위의; 부하","partOfSpeech":"adj.","example":"The manager always treated each subordinate employee with respect.","exampleTranslation":"그 관리자는 항상 모든 하위 직원을 존중하며 대했어요.","level":31,"category":"빈도 학습"},{"id":13848,"term":"subscribe","meaning":"구독하다; 신청하다","partOfSpeech":"v.","example":"You can subscribe to the newsletter to get weekly updates.","exampleTranslation":"주간 업데이트를 받으려면 뉴스레터를 구독할 수 있어요.","level":31,"category":"빈도 학습"},{"id":13849,"term":"subsidiary","meaning":"자회사; 보조적인","partOfSpeech":"n.","example":"The parent company opened a new subsidiary in Southeast Asia.","exampleTranslation":"모회사가 동남아시아에 새로운 자회사를 설립했어요.","level":31,"category":"빈도 학습"},{"id":13850,"term":"sue","meaning":"고소하다; 소송을 제기하다","partOfSpeech":"v.","example":"The customer decided to sue the company for damages.","exampleTranslation":"그 고객은 손해배상을 위해 회사를 고소하기로 결정했습니다.","level":31,"category":"빈도 학습"},{"id":13851,"term":"suite","meaning":"스위트룸; 한 벌; 모음곡","partOfSpeech":"n.","example":"They booked a suite at the luxury hotel for their anniversary.","exampleTranslation":"그들은 기념일을 위해 고급 호텔의 스위트룸을 예약했습니다.","level":31,"category":"빈도 학습"},{"id":13852,"term":"summon","meaning":"소환하다; 불러내다","partOfSpeech":"v.","example":"The judge decided to summon the witness to court.","exampleTranslation":"판사는 증인을 법정에 소환하기로 결정했습니다.","level":31,"category":"빈도 학습"},{"id":13853,"term":"superb","meaning":"훌륭한; 최고의","partOfSpeech":"adj.","example":"The chef prepared a superb meal for the special guests.","exampleTranslation":"주방장은 특별 손님들을 위해 훌륭한 식사를 준비했습니다.","level":31,"category":"빈도 학습"},{"id":13854,"term":"supper","meaning":"저녁 식사","partOfSpeech":"n.","example":"The whole family gathered around the table for supper.","exampleTranslation":"온 가족이 저녁 식사를 위해 식탁 주위에 모였습니다.","level":31,"category":"빈도 학습"},{"id":13855,"term":"suppress","meaning":"억누르다; 진압하다; 억제하다","partOfSpeech":"v.","example":"She tried to suppress her laughter during the serious meeting.","exampleTranslation":"그녀는 진지한 회의 중에 웃음을 억누르려고 했습니다.","level":31,"category":"빈도 학습"},{"id":13856,"term":"surge","meaning":"급증; 급격히 증가하다","partOfSpeech":"n.","example":"There was a sudden surge in electricity demand during the heat wave.","exampleTranslation":"폭염 기간 동안 전력 수요가 갑자기 급증했습니다.","level":31,"category":"빈도 학습"},{"id":13857,"term":"surgeon","meaning":"외과 의사","partOfSpeech":"n.","example":"The surgeon performed a complex operation that lasted six hours.","exampleTranslation":"그 외과 의사는 여섯 시간에 걸친 복잡한 수술을 집도했습니다.","level":31,"category":"빈도 학습"},{"id":13858,"term":"surplus","meaning":"잉여; 흑자; 남는 것","partOfSpeech":"n.","example":"The government reported a budget surplus for the first time in a decade.","exampleTranslation":"정부는 10년 만에 처음으로 예산 흑자를 보고했습니다.","level":31,"category":"빈도 학습"},{"id":13859,"term":"surrender","meaning":"항복하다; 포기하다; 항복","partOfSpeech":"v.","example":"The soldiers had no choice but to surrender to the enemy forces.","exampleTranslation":"그 병사들은 적군에게 항복하는 수밖에 없었습니다.","level":31,"category":"빈도 학습"},{"id":13860,"term":"swift","meaning":"빠른; 신속한","partOfSpeech":"adj.","example":"The paramedics gave a swift response to the emergency call.","exampleTranslation":"응급 구조대원들은 긴급 신고에 신속하게 대응했습니다.","level":31,"category":"빈도 학습"},{"id":13861,"term":"syndrome","meaning":"증후군; 증상","partOfSpeech":"n.","example":"The doctor diagnosed him with a rare syndrome that affects the nervous system.","exampleTranslation":"의사는 그에게 신경계에 영향을 미치는 희귀 증후군을 진단했습니다.","level":31,"category":"빈도 학습"},{"id":13862,"term":"synthesis","meaning":"합성; 종합","partOfSpeech":"n.","example":"The report provided a synthesis of all the research findings.","exampleTranslation":"그 보고서는 모든 연구 결과를 종합한 내용을 담고 있었습니다.","level":31,"category":"빈도 학습"},{"id":13863,"term":"tablespoon","meaning":"큰 숟가락; 테이블스푼","partOfSpeech":"n.","example":"Add one tablespoon of olive oil to the pan before cooking.","exampleTranslation":"요리하기 전에 팬에 올리브 오일 한 큰 숟가락을 넣으세요.","level":31,"category":"빈도 학습"},{"id":13864,"term":"tag","meaning":"꼬리표; 태그; 꼬리표를 달다","partOfSpeech":"n.","example":"Please check the price tag before you put the item in your cart.","exampleTranslation":"물건을 카트에 넣기 전에 가격표를 확인해 주세요.","level":31,"category":"빈도 학습"},{"id":13865,"term":"tangle","meaning":"엉키다; 뒤엉키게 하다; 엉킴","partOfSpeech":"v.","example":"The fishing lines often tangle when you cast too quickly.","exampleTranslation":"너무 빨리 던지면 낚싯줄이 자주 엉킵니다.","level":31,"category":"빈도 학습"},{"id":13866,"term":"telecom","meaning":"통신; 전기통신","partOfSpeech":"n.","example":"The telecom industry has grown rapidly over the past two decades.","exampleTranslation":"통신 산업은 지난 20년 동안 빠르게 성장했습니다.","level":31,"category":"빈도 학습"},{"id":13867,"term":"telescope","meaning":"망원경","partOfSpeech":"n.","example":"Scientists used a powerful telescope to observe distant galaxies.","exampleTranslation":"과학자들은 멀리 있는 은하를 관측하기 위해 강력한 망원경을 사용했습니다.","level":31,"category":"빈도 학습"},{"id":13868,"term":"temple","meaning":"사원; 신전; 관자놀이","partOfSpeech":"n.","example":"Tourists visit the ancient temple every year to admire its architecture.","exampleTranslation":"관광객들은 그 건축물을 감상하기 위해 매년 고대 사원을 방문합니다.","level":31,"category":"빈도 학습"},{"id":13869,"term":"tenant","meaning":"세입자; 임차인","partOfSpeech":"n.","example":"The tenant paid the rent on time every month without fail.","exampleTranslation":"그 세입자는 매달 빠짐없이 제때 임대료를 납부했습니다.","level":31,"category":"빈도 학습"},{"id":13870,"term":"terminal","meaning":"터미널; 말기의; 최종의","partOfSpeech":"n.","example":"Passengers must proceed to terminal B for international departures.","exampleTranslation":"국제선 출발 승객들은 터미널 B로 이동해야 합니다.","level":31,"category":"빈도 학습"},{"id":13871,"term":"terminate","meaning":"종료하다; 끝내다; 해고하다","partOfSpeech":"v.","example":"The company decided to terminate the contract due to repeated delays.","exampleTranslation":"회사는 반복된 지연으로 인해 계약을 종료하기로 결정했습니다.","level":31,"category":"빈도 학습"},{"id":13872,"term":"terrace","meaning":"테라스; 옥상 정원","partOfSpeech":"n.","example":"We enjoyed our morning coffee on the terrace overlooking the garden.","exampleTranslation":"우리는 정원을 내려다보는 테라스에서 아침 커피를 즐겼습니다.","level":31,"category":"빈도 학습"},{"id":13873,"term":"terrify","meaning":"몹시 겁나게 하다; 공포에 질리게 하다","partOfSpeech":"v.","example":"Loud thunderstorms terrify many young children.","exampleTranslation":"크고 요란한 뇌우는 많은 어린아이들을 몹시 겁나게 합니다.","level":31,"category":"빈도 학습"},{"id":13874,"term":"testament","meaning":"증거; 유언장; 성약","partOfSpeech":"n.","example":"Her success is a testament to years of hard work and dedication.","exampleTranslation":"그녀의 성공은 수년간의 노력과 헌신에 대한 증거입니다.","level":31,"category":"빈도 학습"},{"id":13875,"term":"testimony","meaning":"증언; 진술","partOfSpeech":"n.","example":"The witness gave clear testimony about what happened that night.","exampleTranslation":"그 목격자는 그날 밤 있었던 일에 대해 명확한 증언을 했습니다.","level":31,"category":"빈도 학습"},{"id":13876,"term":"textile","meaning":"직물; 섬유; 직물의","partOfSpeech":"n.","example":"The textile industry in this region employs thousands of workers.","exampleTranslation":"이 지역의 직물 산업은 수천 명의 근로자를 고용하고 있습니다.","level":31,"category":"빈도 학습"},{"id":13877,"term":"texture","meaning":"질감; 식감; 촉감","partOfSpeech":"n.","example":"The bread had a soft texture that melted in your mouth.","exampleTranslation":"그 빵은 입 안에서 녹는 부드러운 식감을 가지고 있었습니다.","level":31,"category":"빈도 학습"},{"id":13878,"term":"theft","meaning":"절도; 도둑질","partOfSpeech":"n.","example":"The police arrested a suspect for theft at the shopping mall.","exampleTranslation":"경찰은 쇼핑몰에서 절도 혐의로 용의자를 체포했습니다.","level":31,"category":"빈도 학습"},{"id":13879,"term":"theology","meaning":"신학; 종교학","partOfSpeech":"n.","example":"She studied theology at university before becoming a minister.","exampleTranslation":"그녀는 목사가 되기 전에 대학에서 신학을 공부했습니다.","level":31,"category":"빈도 학습"},{"id":13880,"term":"thesis","meaning":"논문; 주장; 논지","partOfSpeech":"n.","example":"She spent three years writing her thesis on climate change.","exampleTranslation":"그녀는 기후 변화에 관한 논문을 쓰는 데 3년을 보냈습니다.","level":31,"category":"빈도 학습"},{"id":13881,"term":"thigh","meaning":"허벅지","partOfSpeech":"n.","example":"The runner felt a sharp pain in his thigh during the race.","exampleTranslation":"그 달리기 선수는 경주 중에 허벅지에 날카로운 통증을 느꼈습니다.","level":31,"category":"빈도 학습"},{"id":13882,"term":"thou","meaning":"그대; 당신 (고어)","partOfSpeech":"pron.","example":"In Shakespeare's plays, thou art is used to address someone directly.","exampleTranslation":"셰익스피어 희곡에서 이 고어 표현은 상대에게 직접 말을 걸 때 쓰입니다.","level":32,"category":"빈도 학습"},{"id":13883,"term":"thread","meaning":"실; 스레드; 꿰다","partOfSpeech":"n.","example":"She used a needle and thread to sew the button back on.","exampleTranslation":"그녀는 바늘과 실을 사용하여 단추를 다시 꿰맸습니다.","level":32,"category":"빈도 학습"},{"id":13884,"term":"threshold","meaning":"문턱; 한계값; 기준점","partOfSpeech":"n.","example":"The noise level exceeded the threshold set by city regulations.","exampleTranslation":"소음 수준이 시 규정에서 정한 한계값을 초과했습니다.","level":32,"category":"빈도 학습"},{"id":13885,"term":"thrive","meaning":"번성하다; 잘 자라다","partOfSpeech":"v.","example":"Small businesses tend to thrive in areas with high foot traffic.","exampleTranslation":"소규모 사업체들은 유동 인구가 많은 지역에서 번성하는 경향이 있습니다.","level":32,"category":"빈도 학습"},{"id":13886,"term":"thrust","meaning":"밀다; 찌르다; 추력","partOfSpeech":"v.","example":"The rocket engines must thrust the spacecraft beyond the atmosphere.","exampleTranslation":"로켓 엔진은 우주선을 대기권 너머로 밀어내야 합니다.","level":32,"category":"빈도 학습"},{"id":13887,"term":"thumb","meaning":"엄지손가락","partOfSpeech":"n.","example":"He gave a thumbs-up by raising his thumb to show approval.","exampleTranslation":"그는 승인의 표시로 엄지손가락을 올려 엄지척을 했습니다.","level":32,"category":"빈도 학습"},{"id":13888,"term":"thunder","meaning":"천둥; 천둥이 치다","partOfSpeech":"n.","example":"We heard loud thunder just before the heavy rain started.","exampleTranslation":"폭우가 시작되기 직전에 큰 천둥소리를 들었습니다.","level":32,"category":"빈도 학습"},{"id":13889,"term":"tick","meaning":"째깍거리다; 체크 표시; 진드기","partOfSpeech":"v.","example":"I could hear the clock tick quietly in the empty room.","exampleTranslation":"빈 방에서 시계가 조용히 째깍거리는 소리가 들렸습니다.","level":32,"category":"빈도 학습"},{"id":13890,"term":"tiger","meaning":"호랑이","partOfSpeech":"n.","example":"The tiger is one of the most powerful predators in the animal kingdom.","exampleTranslation":"호랑이는 동물 왕국에서 가장 강력한 포식자 중 하나입니다.","level":32,"category":"빈도 학습"},{"id":13891,"term":"tile","meaning":"타일; 기와","partOfSpeech":"n.","example":"The bathroom floor was covered with white tile for easy cleaning.","exampleTranslation":"욕실 바닥은 청소하기 쉽도록 흰색 타일로 덮여 있었습니다.","level":32,"category":"빈도 학습"},{"id":13892,"term":"tilt","meaning":"기울이다; 기울다; 기울기","partOfSpeech":"v.","example":"You should tilt the bottle slightly to pour the liquid smoothly.","exampleTranslation":"액체를 부드럽게 따르려면 병을 살짝 기울여야 합니다.","level":32,"category":"빈도 학습"},{"id":13893,"term":"timber","meaning":"목재; 재목","partOfSpeech":"n.","example":"The old cabin was built entirely from local timber.","exampleTranslation":"그 오래된 오두막은 현지 목재로만 지어졌습니다.","level":32,"category":"빈도 학습"},{"id":13894,"term":"tobacco","meaning":"담배; 담뱃잎","partOfSpeech":"n.","example":"Many countries have introduced strict laws to reduce tobacco use.","exampleTranslation":"많은 나라들이 담배 사용을 줄이기 위한 엄격한 법률을 도입했습니다.","level":32,"category":"빈도 학습"},{"id":13895,"term":"tolerate","meaning":"참다; 견디다; 용납하다","partOfSpeech":"v.","example":"She could not tolerate the constant noise from the construction site.","exampleTranslation":"그녀는 공사 현장에서 나는 끊임없는 소음을 참을 수 없었습니다.","level":32,"category":"빈도 학습"},{"id":13896,"term":"torture","meaning":"고문하다; 고통스럽게 하다; 고문","partOfSpeech":"v.","example":"Human rights groups condemn any attempts to torture prisoners.","exampleTranslation":"인권 단체들은 죄수들을 고문하려는 어떤 시도도 비난합니다.","level":32,"category":"빈도 학습"},{"id":13897,"term":"toxic","meaning":"독성의; 유해한","partOfSpeech":"adj.","example":"Workers must wear protective gear when handling toxic chemicals.","exampleTranslation":"근로자들은 독성 화학물질을 다룰 때 보호 장비를 착용해야 합니다.","level":32,"category":"빈도 학습"},{"id":13898,"term":"tragic","meaning":"비극적인; 참혹한","partOfSpeech":"adj.","example":"The loss of so many lives in the earthquake was truly tragic.","exampleTranslation":"지진으로 인한 그 많은 생명의 희생은 정말로 비극적이었습니다.","level":32,"category":"빈도 학습"},{"id":13899,"term":"trait","meaning":"특성; 특징; 성격","partOfSpeech":"n.","example":"Honesty is a trait that many people look for in a leader.","exampleTranslation":"정직함은 많은 사람들이 지도자에게서 찾는 특성입니다.","level":32,"category":"빈도 학습"},{"id":13900,"term":"transcript","meaning":"기록 문서; 성적 증명서","partOfSpeech":"n.","example":"She requested an official transcript from her university.","exampleTranslation":"그녀는 대학에서 공식 성적 증명서를 요청했어요.","level":32,"category":"빈도 학습"},{"id":13901,"term":"transplant","meaning":"이식하다; 이식","partOfSpeech":"v.","example":"Doctors can transplant a healthy kidney into a patient in need.","exampleTranslation":"의사들은 건강한 신장을 필요한 환자에게 이식할 수 있어요.","level":32,"category":"빈도 학습"},{"id":13902,"term":"trauma","meaning":"정신적 충격; 외상","partOfSpeech":"n.","example":"Survivors of accidents often experience trauma for months afterward.","exampleTranslation":"사고 생존자들은 이후 몇 달 동안 정신적 충격을 경험하는 경우가 많아요.","level":32,"category":"빈도 학습"},{"id":13903,"term":"tremble","meaning":"떨다; 전율하다","partOfSpeech":"v.","example":"His hands began to tremble when he heard the frightening news.","exampleTranslation":"그는 무서운 소식을 들었을 때 손이 떨리기 시작했어요.","level":32,"category":"빈도 학습"},{"id":13904,"term":"triangle","meaning":"삼각형; 삼각관계","partOfSpeech":"n.","example":"A triangle with three equal sides is called an equilateral triangle.","exampleTranslation":"세 변의 길이가 같은 삼각형을 정삼각형이라고 해요.","level":32,"category":"빈도 학습"},{"id":13905,"term":"tribunal","meaning":"재판소; 법정","partOfSpeech":"n.","example":"The international tribunal will decide the outcome of the dispute.","exampleTranslation":"국제 재판소가 분쟁의 결과를 결정할 거예요.","level":32,"category":"빈도 학습"},{"id":13906,"term":"tribute","meaning":"경의; 헌사","partOfSpeech":"n.","example":"The concert was a tribute to the legendary musician who passed away.","exampleTranslation":"그 콘서트는 세상을 떠난 전설적인 음악가에 대한 헌사였어요.","level":32,"category":"빈도 학습"},{"id":13907,"term":"trim","meaning":"다듬다; 손질하다","partOfSpeech":"v.","example":"She asked the hairdresser to trim just the ends of her hair.","exampleTranslation":"그녀는 미용사에게 머리카락 끝부분만 다듬어 달라고 했어요.","level":32,"category":"빈도 학습"},{"id":13908,"term":"trophy","meaning":"트로피; 우승 기념품","partOfSpeech":"n.","example":"The team proudly held up the trophy after winning the championship.","exampleTranslation":"팀은 챔피언십에서 우승한 후 자랑스럽게 트로피를 들어 올렸어요.","level":32,"category":"빈도 학습"},{"id":13909,"term":"tropics","meaning":"열대 지방; 열대","partOfSpeech":"n.","example":"Many exotic fruits grow naturally in the tropics.","exampleTranslation":"많은 이국적인 과일들이 열대 지방에서 자연적으로 자라요.","level":32,"category":"빈도 학습"},{"id":13910,"term":"trousers","meaning":"바지","partOfSpeech":"n.","example":"He bought a pair of trousers that matched his new jacket perfectly.","exampleTranslation":"그는 새 재킷과 완벽하게 어울리는 바지를 한 벌 샀어요.","level":32,"category":"빈도 학습"},{"id":13911,"term":"trustee","meaning":"수탁자; 이사","partOfSpeech":"n.","example":"Each trustee on the board has a responsibility to manage the funds wisely.","exampleTranslation":"이사회의 각 수탁자는 자금을 현명하게 관리할 책임이 있어요.","level":32,"category":"빈도 학습"},{"id":13912,"term":"tuck","meaning":"집어넣다; 접어 넣다","partOfSpeech":"v.","example":"Please tuck your shirt into your pants before the interview.","exampleTranslation":"면접 전에 셔츠를 바지 안으로 집어넣으세요.","level":32,"category":"빈도 학습"},{"id":13913,"term":"tug","meaning":"잡아당기다; 세게 끌다","partOfSpeech":"v.","example":"The child began to tug at her mother's sleeve to get attention.","exampleTranslation":"아이는 관심을 끌기 위해 엄마의 소매를 잡아당기기 시작했어요.","level":32,"category":"빈도 학습"},{"id":13914,"term":"tumble","meaning":"굴러 떨어지다; 넘어지다","partOfSpeech":"v.","example":"The toddler started to tumble down the gentle slope of the hill.","exampleTranslation":"유아가 언덕의 완만한 경사면을 굴러 내려가기 시작했어요.","level":32,"category":"빈도 학습"},{"id":13915,"term":"tumor","meaning":"종양; 혹","partOfSpeech":"n.","example":"The surgeon successfully removed the tumor from the patient's brain.","exampleTranslation":"외과 의사가 환자의 뇌에서 종양을 성공적으로 제거했어요.","level":32,"category":"빈도 학습"},{"id":13916,"term":"turnover","meaning":"매출액; 이직률","partOfSpeech":"n.","example":"High staff turnover can hurt a company's productivity significantly.","exampleTranslation":"높은 직원 이직률은 회사의 생산성에 큰 타격을 줄 수 있어요.","level":32,"category":"빈도 학습"},{"id":13917,"term":"tutor","meaning":"개인 교사; 지도 교사","partOfSpeech":"n.","example":"She hired a tutor to help her son improve his math skills.","exampleTranslation":"그녀는 아들의 수학 실력 향상을 위해 개인 교사를 고용했어요.","level":32,"category":"빈도 학습"},{"id":13918,"term":"undermine","meaning":"약화시키다; 훼손하다","partOfSpeech":"v.","example":"Constant criticism can undermine a child's confidence over time.","exampleTranslation":"지속적인 비판은 시간이 지나면서 아이의 자신감을 약화시킬 수 있어요.","level":32,"category":"빈도 학습"},{"id":13919,"term":"unify","meaning":"통합하다; 하나로 합치다","partOfSpeech":"v.","example":"The new policy aims to unify different departments under one system.","exampleTranslation":"새 정책은 서로 다른 부서들을 하나의 시스템 아래 통합하는 것을 목표로 해요.","level":32,"category":"빈도 학습"},{"id":13920,"term":"upgrade","meaning":"업그레이드하다; 향상시키다","partOfSpeech":"v.","example":"It is time to upgrade your computer to handle the new software.","exampleTranslation":"새 소프트웨어를 처리하기 위해 컴퓨터를 업그레이드할 때가 됐어요.","level":32,"category":"빈도 학습"},{"id":13921,"term":"upwards","meaning":"위쪽으로; 상향으로","partOfSpeech":"adv.","example":"The hot air balloon drifted slowly upwards into the clear blue sky.","exampleTranslation":"열기구가 맑고 파란 하늘로 천천히 위쪽으로 올라갔어요.","level":32,"category":"빈도 학습"},{"id":13922,"term":"utilize","meaning":"활용하다; 이용하다","partOfSpeech":"v.","example":"We need to utilize all available resources to finish the project on time.","exampleTranslation":"프로젝트를 제때 완료하려면 모든 가용 자원을 활용해야 해요.","level":32,"category":"빈도 학습"},{"id":13923,"term":"utter","meaning":"말하다; 발언하다","partOfSpeech":"v.","example":"She was so shocked that she could not utter a single word.","exampleTranslation":"그녀는 너무 충격을 받아 한 마디도 말할 수 없었어요.","level":32,"category":"빈도 학습"},{"id":13924,"term":"validate","meaning":"유효성을 확인하다; 검증하다","partOfSpeech":"v.","example":"The system will validate your ticket before you enter the event.","exampleTranslation":"행사에 입장하기 전에 시스템이 티켓의 유효성을 확인할 거예요.","level":32,"category":"빈도 학습"},{"id":13925,"term":"vanish","meaning":"사라지다; 자취를 감추다","partOfSpeech":"v.","example":"The magician made the rabbit vanish right before the audience's eyes.","exampleTranslation":"마술사가 관객들 눈앞에서 토끼를 바로 사라지게 했어요.","level":32,"category":"빈도 학습"},{"id":13926,"term":"veil","meaning":"베일; 면사포","partOfSpeech":"n.","example":"The bride wore a delicate veil over her face during the ceremony.","exampleTranslation":"신부는 예식 중 얼굴에 섬세한 베일을 착용했어요.","level":32,"category":"빈도 학습"},{"id":13927,"term":"vein","meaning":"정맥; 혈관","partOfSpeech":"n.","example":"The nurse carefully inserted the needle into the vein on her arm.","exampleTranslation":"간호사가 그녀의 팔에 있는 정맥에 조심스럽게 바늘을 꽂았어요.","level":32,"category":"빈도 학습"},{"id":13928,"term":"venue","meaning":"행사 장소; 개최지","partOfSpeech":"n.","example":"The team is looking for a suitable venue to hold the annual conference.","exampleTranslation":"팀은 연간 회의를 개최할 적합한 장소를 찾고 있어요.","level":32,"category":"빈도 학습"},{"id":13929,"term":"verbal","meaning":"언어적인; 말로 하는","partOfSpeech":"adj.","example":"The manager gave verbal instructions instead of writing them down.","exampleTranslation":"관리자는 기록 대신 말로 지시를 내렸어요.","level":32,"category":"빈도 학습"},{"id":13930,"term":"verdict","meaning":"평결; 판결","partOfSpeech":"n.","example":"The jury delivered a verdict of not guilty after hours of deliberation.","exampleTranslation":"배심원단은 몇 시간의 심의 끝에 무죄 평결을 내렸어요.","level":32,"category":"빈도 학습"},{"id":13931,"term":"verify","meaning":"확인하다; 검증하다","partOfSpeech":"v.","example":"Please verify your email address by clicking the link we sent you.","exampleTranslation":"보내드린 링크를 클릭하여 이메일 주소를 확인해 주세요.","level":32,"category":"빈도 학습"},{"id":13932,"term":"verse","meaning":"시; 절(節)","partOfSpeech":"n.","example":"The singer wrote a moving verse about losing someone he loved.","exampleTranslation":"가수는 사랑하는 사람을 잃은 것에 대한 감동적인 시를 썼어요.","level":32,"category":"빈도 학습"},{"id":13933,"term":"vertical","meaning":"수직의; 세로의","partOfSpeech":"adj.","example":"The architect designed a vertical garden on the side of the building.","exampleTranslation":"건축가는 건물 옆면에 수직 정원을 설계했어요.","level":32,"category":"빈도 학습"},{"id":13934,"term":"veterinarian","meaning":"수의사","partOfSpeech":"n.","example":"A veterinarian examined the sick puppy and prescribed some medication.","exampleTranslation":"수의사가 아픈 강아지를 진찰하고 약을 처방했어요.","level":32,"category":"빈도 학습"},{"id":13935,"term":"viable","meaning":"실행 가능한; 생존 가능한","partOfSpeech":"adj.","example":"The team proposed a viable solution to reduce company expenses.","exampleTranslation":"팀은 회사 비용을 줄이기 위한 실행 가능한 해결책을 제안했어요.","level":32,"category":"빈도 학습"},{"id":13936,"term":"vibrate","meaning":"진동하다; 떨리다","partOfSpeech":"v.","example":"You can set your phone to vibrate during meetings instead of ringing.","exampleTranslation":"회의 중에는 전화기를 벨소리 대신 진동하도록 설정할 수 있어요.","level":32,"category":"빈도 학습"},{"id":13937,"term":"vigorous","meaning":"활기찬; 격렬한","partOfSpeech":"adj.","example":"Doctors recommend at least thirty minutes of vigorous exercise each day.","exampleTranslation":"의사들은 매일 최소 30분의 격렬한 운동을 권장해요.","level":32,"category":"빈도 학습"},{"id":13938,"term":"villa","meaning":"별장; 빌라","partOfSpeech":"n.","example":"The family rented a villa by the sea for their summer vacation.","exampleTranslation":"가족은 여름 휴가를 위해 바다 근처의 별장을 빌렸어요.","level":32,"category":"빈도 학습"},{"id":13939,"term":"virgin","meaning":"처녀; 순수한","partOfSpeech":"adj.","example":"The explorers discovered a virgin forest untouched by human activity.","exampleTranslation":"탐험가들은 인간의 활동에 손대지 않은 순수한 숲을 발견했어요.","level":32,"category":"빈도 학습"},{"id":13940,"term":"vitamin","meaning":"비타민; 영양소","partOfSpeech":"n.","example":"Eating fruits daily helps your body get enough vitamin C naturally.","exampleTranslation":"매일 과일을 먹으면 몸이 자연스럽게 충분한 비타민 C를 얻는 데 도움이 돼요.","level":32,"category":"빈도 학습"},{"id":13941,"term":"vivid","meaning":"선명한; 생생한","partOfSpeech":"adj.","example":"She still has a vivid memory of her first day at school.","exampleTranslation":"그녀는 아직도 학교 첫날의 생생한 기억을 갖고 있어요.","level":32,"category":"빈도 학습"},{"id":13942,"term":"vocal","meaning":"목소리의; 발성의","partOfSpeech":"adj.","example":"The singer warmed up with vocal exercises before performing on stage.","exampleTranslation":"가수는 무대에 오르기 전에 발성 연습으로 준비 운동을 했어요.","level":32,"category":"빈도 학습"},{"id":13943,"term":"vocation","meaning":"직업; 천직","partOfSpeech":"n.","example":"Teaching can be more than a job — it can be a true vocation.","exampleTranslation":"가르치는 일은 단순한 직업 그 이상, 진정한 천직이 될 수 있어요.","level":32,"category":"빈도 학습"},{"id":13944,"term":"volcano","meaning":"화산","partOfSpeech":"n.","example":"The active volcano on the island last erupted about fifty years ago.","exampleTranslation":"그 섬의 활화산은 약 50년 전에 마지막으로 폭발했어요.","level":32,"category":"빈도 학습"},{"id":13945,"term":"wagon","meaning":"수레; 화물차","partOfSpeech":"n.","example":"The farmer loaded fresh vegetables onto a wooden wagon for the market.","exampleTranslation":"농부는 시장을 위해 나무 수레에 신선한 채소를 실었어요.","level":32,"category":"빈도 학습"},{"id":13946,"term":"waist","meaning":"허리","partOfSpeech":"n.","example":"She measured her waist before buying a new pair of jeans online.","exampleTranslation":"그녀는 온라인으로 새 청바지를 구입하기 전에 허리를 측정했어요.","level":32,"category":"빈도 학습"},{"id":13947,"term":"wan","meaning":"창백한; 핼쑥한","partOfSpeech":"adj.","example":"He looked wan and tired after working long hours through the night.","exampleTranslation":"그는 밤새 오랜 시간 일한 후 창백하고 피곤해 보였어요.","level":32,"category":"빈도 학습"},{"id":13948,"term":"ward","meaning":"병동; 구역","partOfSpeech":"n.","example":"The patient was moved to a ward for further observation after surgery.","exampleTranslation":"환자는 수술 후 추가 관찰을 위해 병동으로 옮겨졌어요.","level":32,"category":"빈도 학습"},{"id":13949,"term":"warehouse","meaning":"창고; 물류 센터","partOfSpeech":"n.","example":"The company stores all its inventory in a large warehouse outside the city.","exampleTranslation":"회사는 모든 재고를 도시 외곽의 대형 창고에 보관해요.","level":32,"category":"빈도 학습"},{"id":13950,"term":"warrant","meaning":"영장; 정당화하다; 보장하다","partOfSpeech":"n.","example":"The police obtained a warrant to search the suspect's home.","exampleTranslation":"경찰은 용의자의 집을 수색하기 위한 영장을 발부받았습니다.","level":32,"category":"빈도 학습"},{"id":13951,"term":"warrior","meaning":"전사; 용사","partOfSpeech":"n.","example":"The brave warrior fought to protect his village from invaders.","exampleTranslation":"용감한 전사는 침략자들로부터 마을을 지키기 위해 싸웠습니다.","level":32,"category":"빈도 학습"},{"id":13952,"term":"wax","meaning":"왁스; 밀랍; 왁스를 바르다","partOfSpeech":"n.","example":"He applied wax to the wooden floor to make it shine.","exampleTranslation":"그는 나무 바닥을 빛나게 하려고 왁스를 발랐습니다.","level":32,"category":"빈도 학습"},{"id":13953,"term":"weary","meaning":"지친; 피곤한","partOfSpeech":"adj.","example":"After the long hike, the travelers felt weary and sat down to rest.","exampleTranslation":"긴 등산 후 여행자들은 지쳐서 앉아 쉬었습니다.","level":32,"category":"빈도 학습"},{"id":13954,"term":"webs","meaning":"거미줄; 망; 그물","partOfSpeech":"n.","example":"Spiders spin webs to catch insects for food.","exampleTranslation":"거미는 먹이로 삼을 곤충을 잡기 위해 거미줄을 칩니다.","level":32,"category":"빈도 학습"},{"id":13955,"term":"weep","meaning":"울다; 눈물을 흘리다","partOfSpeech":"v.","example":"She began to weep when she heard the sad news about her friend.","exampleTranslation":"그녀는 친구에 관한 슬픈 소식을 듣자 울기 시작했습니다.","level":32,"category":"빈도 학습"},{"id":13956,"term":"wells","meaning":"우물; 샘","partOfSpeech":"n.","example":"The villagers dug wells to access clean drinking water underground.","exampleTranslation":"마을 사람들은 지하의 깨끗한 식수를 얻기 위해 우물을 팠습니다.","level":32,"category":"빈도 학습"},{"id":13957,"term":"whale","meaning":"고래","partOfSpeech":"n.","example":"The tourists were thrilled to spot a whale jumping out of the ocean.","exampleTranslation":"관광객들은 바다에서 뛰어오르는 고래를 발견하고 흥분했습니다.","level":32,"category":"빈도 학습"},{"id":13958,"term":"whiskey","meaning":"위스키","partOfSpeech":"n.","example":"He poured a glass of whiskey and sat by the fireplace to relax.","exampleTranslation":"그는 위스키 한 잔을 따르고 벽난로 옆에 앉아 쉬었습니다.","level":32,"category":"빈도 학습"},{"id":13959,"term":"widow","meaning":"미망인; 과부","partOfSpeech":"n.","example":"The widow lived alone in the old house after her husband passed away.","exampleTranslation":"미망인은 남편이 세상을 떠난 후 오래된 집에서 혼자 살았습니다.","level":32,"category":"빈도 학습"},{"id":13960,"term":"wit","meaning":"재치; 기지; 지혜","partOfSpeech":"n.","example":"Her quick wit made everyone laugh during the boring meeting.","exampleTranslation":"그녀의 빠른 재치가 지루한 회의 중 모두를 웃게 만들었습니다.","level":32,"category":"빈도 학습"},{"id":13961,"term":"worship","meaning":"예배; 숭배; 예배하다","partOfSpeech":"n.","example":"The community gathered at the church for worship every Sunday morning.","exampleTranslation":"지역 사람들은 매주 일요일 아침 예배를 드리기 위해 교회에 모였습니다.","level":32,"category":"빈도 학습"},{"id":13962,"term":"wreck","meaning":"잔해; 파손; 망가뜨리다","partOfSpeech":"n.","example":"Divers explored the old wreck lying on the ocean floor.","exampleTranslation":"잠수부들은 해저에 가라앉아 있는 오래된 난파선 잔해를 탐험했습니다.","level":32,"category":"빈도 학습"},{"id":13963,"term":"wrist","meaning":"손목","partOfSpeech":"n.","example":"She wore a beautiful bracelet on her wrist at the party.","exampleTranslation":"그녀는 파티에서 손목에 아름다운 팔찌를 찼습니다.","level":32,"category":"빈도 학습"}]`);export{e as default};